INSERT INTO public.photos VALUES (21158, 'Harinera de Villarroya y Castellano 1897', 'Fâ”œأ­brica de harina de Villarroya y Castellano, Joseph Thomas Bigas, 1897. Comenzâ”œâ”‚ a funcionar en 1849, pero un incendio en 1855 obligâ”œâ”‚ a reconstruirla. En 1899 se transformâ”œâ”‚ en azucarera. Estaba situada en la confluencia de los caminos de Barcelona y Peâ”œâ–’aflor, en el barrio de Santa Isabel de Zaragoza. Fuente visual: Mâ”¬آ¬ Pilar Biel Ibâ”œأ­â”œâ–’ez, Zaragoza y la industrializaciâ”œâ”‚n: la arquitectura industrial 1875-1936, IFC, 2004.', 1897, 1897, 1897, 'Siglo XIX', 'SANTA ISABEL', 41.67222000, -0.84006900, '0101000020E610000002452C62D8E1EABFCBDB114E0BD64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19665441735.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19665441735.webp', 'https://www.flickr.com/photos/zaragozaantigua/19665441735/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21862, 'Santa Isabel 1934', 'Imagen parcial del original servicio de gasolina, agua y aire de la Casa Usâ”œأ­n ubicado junto al puente del Gâ”œأ­llego y la carretera de Cataluâ”œâ–’a, a la entrada del barrio de Santa Isabel. En este establecimiento podâ”œآ،an adquirirse, ademâ”œأ­s, ultramarinos y fiambres, lubricantes, piensos, e incluso cemento de Morata. Por su estratâ”œآ®gica situaciâ”œâ”‚n, este servicio fue ampliado y reformado en varias ocasiones. Fuente visual: www.mecd.gob.es/.', 1934, 1934, 1934, 'Anos 30', 'SANTA ISABEL', 41.67031700, -0.83966900, '0101000020E61000007AE1CE8591DEEABFF6798CF2CCD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36327616391.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36327616391.webp', 'https://www.flickr.com/photos/zaragozaantigua/36327616391/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21967, 'Santa Isabel 1941', 'Imagen de la veterana estaciâ”œâ”‚n de servicio del barrio de Santa Isabel, un poco despuâ”œآ®s de cruzar el puente del Gâ”œأ­llego, en la carretera a Barcelona. En la imagen, un autobâ”œâ•‘s de la lâ”œآ،nea del Gâ”œأ­llego, con terminal en la Plaza de Ariâ”œâ–’o. Unos aâ”œâ–’os despuâ”œآ®s, una profunda remodelaciâ”œâ”‚n expansiva le darâ”œآ،a a esta gasolinera un aire mâ”œأ­s "moderno". Fuente visual: www.avvsantaisabel.org/.', 1941, 1941, 1941, 'Anos 40', 'SANTA ISABEL', 41.67031700, -0.83966900, '0101000020E61000007AE1CE8591DEEABFF6798CF2CCD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22417193391.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22417193391.webp', 'https://www.flickr.com/photos/zaragozaantigua/22417193391/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23746, 'Ctra. de Barcelona c.1900', 'Imagen capturada en la carretera de Barcelona con el espectacular fondo de la fachada principal de los grandes pabellones de la antigua fâ”œأ­brica harinera de Villarroya y Castellano, construidos en 1857 tras el gran incendio de 1855, que en 1899 habâ”œآ،a sido reconvertida en factorâ”œآ،a azucarera con la denominaciâ”œâ”‚n de Nueva Azucarera "La Raperie". En ellos se habilitaron habitaciones para los jefes de la azucarera, una capilla, almacenes y locales para el personal facultativo, la dependencia y algunos talleres. En las traseras de estos inmuebles se abrâ”œآ،a un gran patio o jardâ”œآ،n central por el que fluâ”œآ،a al aire la acequia Urdana. En primer tâ”œآ®rmino, aspecto del trâ”œأ­fico de esta vâ”œآ،a de comunicaciâ”œâ”‚n, y en la esquina de la izquierda detalle de la sombra proyectada por el fotâ”œâ”‚grafo de esta imagen y sus acompaâ”œâ–’antes.', 1900, 1900, 1900, 'Anos 1900', 'SANTA ISABEL', 41.66965800, -0.83886600, '0101000020E6100000253E7782FDD7EABF9CC0745AB7D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15488834427.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15488834427.webp', 'https://www.flickr.com/photos/zaragozaantigua/15488834427/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23748, 'Balay 1969', 'Foto Josâ”œآ® Borobio, 1969. Nuevo edificio de la factorâ”œآ،a de electrodomâ”œآ®sticos Balay en Zaragoza, construido en la avenida de la Industria 49 del barrio de Montaâ”œâ–’ana, en 1968. La fâ”œأ­brica se habâ”œآ،a instalado allâ”œآ، en 1956. Fuente visual: "Una mirada a travâ”œآ®s de la arquitectura: Regino y Josâ”œآ® Borobio Ojeda", Daniel Estabâ”œآ®n Boldova, 2013.', 1969, 1969, 1969, 'Anos 60', 'SANTA ISABEL', 41.67191000, -0.83680800, '0101000020E610000054FF209221C7EABF7CED992501D64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15531853598.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15531853598.webp', 'https://www.flickr.com/photos/zaragozaantigua/15531853598/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23758, 'Balay 1956', 'Vista aâ”œآ®rea en 1956 de la nueva factorâ”œآ،a de electrodomâ”œآ®sticos Balay de Zaragoza, en la confluencia de las carreteras de Santa Isabel (abajo, junto a la gasolinera triangular con torrecilla) y de Montaâ”œâ–’ana (a la derecha, hoy avenida de la Industria). El negocio provenâ”œآ،a de su anterior ubicaciâ”œâ”‚n en la calle Pradilla 58. Fuente: Exposiciâ”œâ”‚n "â”œأ«rase una vez Balay", Zaragoza, 2015.', 1956, 1956, 1956, 'Anos 50', 'SANTA ISABEL', 41.67096300, -0.83922100, '0101000020E6100000AEB9A3FFE5DAEABFBCE9961DE2D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21191785903.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21191785903.webp', 'https://www.flickr.com/photos/zaragozaantigua/21191785903/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21216, 'Zaragoza desde el Gâ”œأ­llego c.1908', 'Foto Gabriel Faci/Archivo DARA. Toma de arbolillo ribereâ”œâ–’o en primer plano, con zagales en la ribera del râ”œآ،o Gâ”œأ­llego y vista de Zaragoza al fondo, con sus torres. Fuente visual: AHPZ.', 1908, 1908, 1908, 'Anos 1900', 'SANTA ISABEL', 41.66696800, -0.84112200, '0101000020E61000008D463EAF78EAEABF40BD19355FD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15423220956.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15423220956.webp', 'https://www.flickr.com/photos/zaragozaantigua/15423220956/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21140, 'La Montaâ”œâ–’anesa 1897', '1897. Fâ”œأ­brica de papel "La Montaâ”œâ–’anesa" en el barrio rural de Montaâ”œâ–’ana de Zaragoza, donde continâ”œâ•‘a. Fundada en 1867 bajo la razâ”œâ”‚n social "Sorogoyen y Compaâ”œâ–’â”œآ،a", cambiada mâ”œأ­s tarde por la de "Villarroya y Compaâ”œâ–’â”œآ،a", y transformada en 1900 en Sociedad Anâ”œâ”‚nima con la denominaciâ”œâ”‚n "La Montaâ”œâ–’anesa", con Francisco Villarroya de presidente. Fuente visual: Mâ”¬آ¬ Pilar Biel Ibâ”œأ­â”œâ–’ez, Zaragoza y la industrializaciâ”œâ”‚n: la arquitectura industrial 1875-1936, IFC, 2004.', 1897, 1897, 1897, 'Siglo XIX', 'MONTAâ”œأ¦ANA', 41.69301400, -0.82495100, '0101000020E61000000CAEB9A3FF65EABFC7D5C8AEB4D84440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14871673588.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14871673588.webp', 'https://www.flickr.com/photos/zaragozaantigua/14871673588/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22812, 'La Montaâ”œâ–’anesa 1973', 'Inâ”œآ®dita vista aâ”œآ®rea del complejo fabril de papel y cartâ”œâ”‚n ondulado "La Montaâ”œâ–’anesa S.A." fundada en 1867, recrecida en varias ocasiones e integrada desde 1969 en el grupo Sarriâ”œâ”‚ Compaâ”œâ–’â”œآ،a Papelera de Leiza, S.A., cuya denominaciâ”œâ”‚n local se derivaba del hecho de estar enclavada en este singular barrio rural zaragozano elongado en torno a la carretera del mismo nombre. En primer tâ”œآ®rmino, el camino del Cementerio de este barrio arranca desde la carretera de Montaâ”œâ–’ana, frente al que se localiza el ingreso a la factorâ”œآ،a a la altura del nâ”œâ•‘mero 109. Hacia el fondo y delimitando el perâ”œآ،metro fabril, la acequia de Urdâ”œأ­n, y en el extremo superior, el cauce del râ”œآ،o Gâ”œأ­llego. Esta importante fâ”œأ­brica conocerâ”œآ،a luego mâ”œأ­s ampliaciones y nuevos cambios de titularidad empresarial.', 1973, 1973, 1973, 'Anos 70', 'MONTAâ”œأ¦ANA', 41.69369600, -0.82463900, '0101000020E6100000553200547163EABFDAAED007CBD84440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51553373849.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51553373849.webp', 'https://www.flickr.com/photos/zaragozaantigua/51553373849/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21800, 'Avenida MZA 1931', 'Ese canicular dâ”œآ،a de julio, Marâ”œآ،n Chivite hizo una de sus estupendas fotografâ”œآ،as, la que da pie a esta entrada, pero el medio que la publicâ”œâ”‚ luego (el mâ”œأ­s antiguo de la regiâ”œâ”‚n aragonesa), la considera del montonaje, asâ”œآ، que apenas queda hoy como un borrâ”œâ”‚n en grisalla sin demasiado atractivo. Vamos a homenajearla como se merece. Se trata de una insâ”œâ”‚lita imagen de la novâ”œآ،sima, y reciâ”œآ®n abierta al trâ”œأ­fico, "Avenida de MZA", asâ”œآ، denominada por la inmediata vecindad, a la derecha, de la zanja del ferrocarril MZA de los directos. La captura se ha realizado, viniendo desde el paseo de Sagasta, casi en la intersecciâ”œâ”‚n de este nuevo vial con el camino de las Torres, que lo cruza de derecha a izquierda. A la izquierda, los muros perimetrales donde se estaba comenzando la construcciâ”œâ”‚n del nuevo convento-colegio de los PP. Agustinos, segâ”œâ•‘n proyecto de Miguel â”œأ¼ngel Navarro. A la derecha, sobre la zanja, la sombra de uno de los puentecillos para paso peatonal. Mâ”œأ­s a la derecha, â”œأ­rboles del camino de las Alcachoferas. El cauce al aire de la acequia de San Josâ”œآ® queda justo a las espaldas del fotâ”œâ”‚grafo. Este tramo de la nueva avenida, hasta su cruce con el camino de San Josâ”œآ® al fondo, era tambiâ”œآ®n denominado "calle de Fletas", por la cercana y antigua Torre agrâ”œآ،cola de ese nombre, al fondo, a la derecha. La valla de madera abierta, en primer plano, nos invita a la inauguraciâ”œâ”‚n de este vial, casi 85 aâ”œâ–’os despuâ”œآ®s. Adelante. Fuente visual: Foto Marâ”œآ،n Chivite, para Heraldo de Aragâ”œâ”‚n', 1931, 1931, 1931, 'Anos 30', 'SAN JOSâ”œأ«', 41.64104200, -0.88364700, '0101000020E610000021ACC612D646ECBF64AE0CAA0DD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26212243314.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26212243314.webp', 'https://www.flickr.com/photos/zaragozaantigua/26212243314/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21898, 'Hospital de italianos c.1938', 'Sonriente y luminoso posado de oficiales y enfermeras en el patio del nuevo convento-colegio de los P.P. agustinos en el camino de las Torres, habilitado como hospital de legionarios italianos durante la â”œâ•‘ltima guerra civil. Al fondo, el paâ”œâ–’o noroccidental del patio.', 1938, 1938, 1938, 'Anos 30', 'SAN JOSâ”œأ«', 41.64113600, -0.88244600, '0101000020E6100000718DCF64FF3CECBFE62494BE10D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51217718273.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51217718273.webp', 'https://www.flickr.com/photos/zaragozaantigua/51217718273/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21916, 'Hospitales de Miraflores 1938', 'Inâ”œآ®dita imagen capturada en el interior del extenso terreno ocupado por el colegio-seminario de los PP. agustinos de Miraflores. En una zona de firme irregular junto al frontâ”œâ”‚n aparece una canasta de baloncesto sin uso entre tiendas de campaâ”œâ–’a seâ”œâ–’aladas con la Cruz Roja. En el edificio principal de este colegio aâ”œâ•‘n no terminado (a espaldas de esta foto) Falange instalâ”œâ”‚ una أ”أ‡آ£oficina de investigaciâ”œâ”‚nأ”أ‡أک para detener, torturar y ejecutar extrajudicialmente infieles a la sublevaciâ”œâ”‚n militar de 1936, y aquâ”œآ، se estableciâ”œâ”‚ tambiâ”œآ®n un cuartel y un hospital de sangre. Al fondo, en el antiguo barrio de Cartier destaca el edificio de las escuelas de la calle de Abadâ”œآ،a (actual CEIP San Jose de Calasanz) inaugurado en 1935 en la esquina entre la calle de Abadâ”œآ،a y el callejâ”œâ”‚n de la Bailera, junto a la proyectada y no realizada avenida Perimetral y que en 1937 fue reutilizado como hospital de sangre para tropas italianas.', 1938, 1938, 1938, 'Anos 30', 'SAN JOSâ”œأ«', 41.64085800, -0.88079300, '0101000020E61000009B7631CD742FECBFA3B08BA207D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53214894398.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53214894398.webp', 'https://www.flickr.com/photos/zaragozaantigua/53214894398/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21998, 'C.â”¬â•‘ de las Torres c.1941', 'Imagen de la fachada principal del nuevo convento-colegio de los PP. Agustinos del camino de las Torres, esquina (a la derecha) con la calle de Fletas, y la zanja del ferrocarril de Zaragoza a Barcelona. Este edificio fue diseâ”œâ–’ado por Miguel â”œأ¼ngel Navarro Pâ”œآ®rez, y la descomunal iglesia vinculada a este proyecto estaba prevista en la zona trasera del ala izquierda. A la espalda del fotâ”œâ”‚grafo fluâ”œآ،a al aire la antigua acequia de las Adulas, ahora denominada de San Josâ”œآ®. Fuente visual: foto Juan Mora Insa, en AHPZ.', 1941, 1941, 1941, 'Anos 40', 'SAN JOSâ”œأ«', 41.64112000, -0.88321900, '0101000020E61000001C96067E5443ECBFE0675C3810D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33287643572.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33287643572.webp', 'https://www.flickr.com/photos/zaragozaantigua/33287643572/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22224, 'P.â”¬â•‘ de Fernando el Catâ”œâ”‚lico 1958', 'Imagen capturada desde la altura del moderno inmueble del nâ”¬â•‘ 58 del paseo de Fernando el Catâ”œâ”‚lico, y centrada en las instalaciones de la Editorial Luis Vives S.A., con el aspecto conferido tras la notable ampliaciâ”œâ”‚n realizada en 1950 con diseâ”œâ–’o de los hermanos Borobio, sobre la original planta ideada por ellos mismos en 1940. A la izquierda, la calle de Luis Vives, y al fondo, traseras de la Harinera Imperial junto al Canal Imperial de Aragâ”œâ”‚n, de la que se destaca su chimenea. En la zona central, parque de Primo de Rivera del que emerge el Monumento al rey Alfonso I en el Cabezo de Buenavista. Esta imagen, coloreada, fue profusamente utilizada como icono publicitario de los libros o textos escolares de la Editorial Edelvives.', 1958, 1958, 1958, 'Anos 50', 'UNIVERSIDAD', 41.63825300, -0.89686100, '0101000020E6100000F5D901D715B3ECBF75C93846B2D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48986825551.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48986825551.webp', 'https://www.flickr.com/photos/zaragozaantigua/48986825551/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22017, 'Camino de las Torres c.1941', 'Imagen capturada en altura desde la altura del nâ”¬â•‘ 24 de la calle de Jesâ”œâ•‘s Comâ”œآ،n, antigua del Alba, con una interesante vista parcial del extenso perâ”œآ،metro del colegio de San Agustâ”œآ،n sito en el camino de las Torres, angular a la derecha a la avenida MZA. Diseâ”œâ–’ado por Miguel â”œأ¼ngel Navarro Pâ”œآ®rez en 1930, fue construido entre 1931 y 1935, si bien no se finalizaron todas las instalaciones previstas, entre ella la gran iglesia de Santa Rita de Casia. Durante la Guerra Civil fue reconvertido en hospital para soldados italianos heridos en combate, y hubo de esperar hasta 1941 para ser inaugurado, por fin, como colegio y convento. En primer tâ”œآ®rmino y a la izquierda, acequia al aire de San Josâ”œآ® descendente por el camino de las Torres. A la derecha, la zanja del ferrocarril de los directos a Barcelona y alguno de los puentecillos de paso peatonal. Sobre el camino de las Alcachoferas destaca la chimenea de la fâ”œأ­brica de cervezas La Zaragozana. Al fondo, la torre de Fletas, que tambiâ”œآ®n daba nombre a este extraâ”œâ–’o vial entre la avenida de San Josâ”œآ® y el camino de las Torres.', 1941, 1941, 1941, 'Anos 40', 'SAN JOSâ”œأ«', 41.64117600, -0.88268200, '0101000020E610000068925852EE3EECBF747D1F0E12D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49420633858.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49420633858.webp', 'https://www.flickr.com/photos/zaragozaantigua/49420633858/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22105, 'La Zaragozana c.1950', 'Interior del recinto de la fâ”œأ­brica de cervezas La Zaragozana, domiciliada en la calle Ramâ”œâ”‚n Berenguer IV 1 y construida en 1900. Fuente visual: Colecciâ”œâ”‚n Josâ”œآ® Marâ”œآ،a Ballestâ”œآ،n Miguel', 1950, 1950, 1950, 'Anos 50', 'SAN JOSâ”œأ«', 41.63787300, -0.88104100, '0101000020E6100000A2EC2DE57C31ECBF2E008DD2A5D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20985831439.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20985831439.webp', 'https://www.flickr.com/photos/zaragozaantigua/20985831439/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22201, 'F.C. a Barcelona 1959', 'Imagen capturada durante las obras de establecimiento de la doble vâ”œآ،a ferroviaria entre las estaciones de Campo Sepulcro y Miraflores (lâ”œآ،nea de Barcelona). La imagen se ha tomado desde uno de los pasos elevados que, en el tramo entre el camino de las Torres, y la avenida de San Josâ”œآ®, salvaban la zanja del ferrocarril. A la izquierda, la antigua calle de Fletas, y el punto mâ”œأ­s al sureste del muro perimetral que delimitaba el enorme colegio de los PP. Agustinos, hasta las inmediaciones del antiguo callejâ”œâ”‚n de Bailera y el colegio de San Josâ”œآ® de Calasanz. A la derecha, y al fondo, fachada de los bloques recayentes a la calle Lausana, conducente a general Millâ”œأ­n Astray, y Suiza. Una vaporosa (tal vez una "Mikado") se encamina con su regular traqueteo hacia la estaciâ”œâ”‚n Campo Sepulcro. El despejado panorama de esa zona de huerta pronto mutarâ”œآ،a, en su parte derecha, con nuevos bloques, 2,5 veces mâ”œأ­s de altos, de media, y nuevos viales. Al desdoblamiento de la vâ”œآ،a le seguirâ”œآ،a luego el cubrimiento hasta el camino del Puente del Virrey, y el advenimiento de la denominaciâ”œâ”‚n de Tenor Fleta a la avenida resultante. Fuente visual: Archivo Municipal de Zaragoza.', 1959, 1959, 1959, 'Anos 50', 'SAN JOSâ”œأ«', 41.63963900, -0.88104000, '0101000020E61000008CF84ECC7A31ECBF821FD5B0DFD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33603130385.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33603130385.webp', 'https://www.flickr.com/photos/zaragozaantigua/33603130385/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22343, 'PP. Agustinos c.1966', 'Captura, en el cruce de Camino de las Torres con Tenor Fleta, de la gigantesca manzana (por el tamaâ”œâ–’o, casi calabaza, y de las gordas) en la que los PP Agustinos tenâ”œآ،an colegio, varios campos de fâ”œâ•‘tbol, zonas verdes, y un proyecto de magna iglesia que no pasâ”œâ”‚ de proyecto. Inmediatamente, en el pedazo de Tenor Fleta visible, la reciâ”œآ®n recubierta trinchera del ferrocarril a Barcelona, con restos aâ”œâ•‘n de obra. La vista parcialmente aâ”œآ®rea, realizada desde el bloque de viviendas nâ”¬â•‘ 104 de Camino de las Torres, permite una contemplaciâ”œâ”‚n de los entonces apacibles y verdosos jardines internos del Colegio, con câ”œآ®sped, setos, â”œأ­rboles...y suelo de tierra. A la derecha, tras las lejos muros perimetrales del colegio, los campos de cultivo de Miraflores, aâ”œâ•‘n cultivados de herbâ”œأ­ceas. Al fondo, a la izquierda, los bloques de vivienda de la calle Lorenzo Pardo, Licorera (con una vista del edificio de la antigua fâ”œأ­brica), y los bloques de viviendas de la Avenida de S. Josâ”œآ®... todo ello es visible porque la imagen es anterior a la prolongaciâ”œâ”‚n de Marina Moreno, y la posterior erecciâ”œâ”‚n de todos los altos bloques de la actual Cesâ”œأ­reo Alierta, en la acera de los impares, y la acera de los pares, por supuesto. Tambiâ”œآ®n es visible el entorno de la Parroquia de S. Agustâ”œآ،n, con su pabellâ”œâ”‚n, el arranque de la calle Cartagena. Ya a la derecha, las traseras de los bloques de S. Josâ”œآ®, Domingo Lobera. La foto parece de hace cuatro dâ”œآ،as, pero los cambios que han de producirse en estaq zona son de consideraciâ”œâ”‚n. Fuente visual: Imâ”œأ­genes Antiguas de Zaragoza.', 1966, 1966, 1966, 'Anos 60', 'SAN JOSâ”œأ«', 41.64112000, -0.88321900, '0101000020E61000001C96067E5443ECBFE0675C3810D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20224425316.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20224425316.webp', 'https://www.flickr.com/photos/zaragozaantigua/20224425316/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22469, 'Calle de Pradilla 1962', 'Imagen capturada desde la terraza del nâ”¬â•‘ 14 de la calle del Marquâ”œآ®s de Ahumada, vivienda unifamiliar de 1942 diseâ”œâ–’ada por Enrique Vincenti Bravo. La vista, orientada hacia el suroeste, nos retrotrae a los espacios y escalas edilicias del urbanismo del antiguo barrrio de los "Chiflaos", en este caso las traseras ajardinadas de algunas de las parcelas de la calle de Pradilla que, en dencenso, arrancaban en la antigua avenida del Siglo XX, luego paseo de Cuâ”œآ®llar. En primer plano, el jardâ”œآ،n y construcciâ”œâ”‚n secundaria del propio edificio desde donde se toma la fotografâ”œآ،a. A la derecha, el exuberante seto sobre la medianera con el nâ”¬â•‘ 12 de Marquâ”œآ®s de Ahumada, cuya casa era gemela del nâ”¬â•‘ 14, y que luego fue derribada. En el centro de la imagen, las traseras ajardinadas de las antiguas parcelas de la calle de Pradilla nâ”¬â•‘ 34, nâ”¬â•‘ 35, nâ”¬â•‘ 37, y nâ”¬â•‘ 38, esta con un destacado torreoncillo seâ”œâ–’a de identidad de varias de las construcciones de la zona. A la izquierda, un poco mâ”œأ­s al fondo, vista parcial del torreoncillo, este cubierto a cuatro aguas, de la antigua parcela nâ”¬â•‘ 13 y 14 de la misma calle. Al fondo, a la derecha, el edificio de la antigua parcela del nâ”¬â•‘ 37 del paseo de Cuâ”œآ®llar. Todas estas construcciones luego fueron derribadas y sustituidas por edificios de viviendas mâ”œأ­s modernos, y todas las zonas ajardinadas de la imagen fueron incorporadas a los nuevos espacios residenciales resultantes. De esta zona sâ”œâ”‚lo perdura la parcela del actual nâ”¬â•‘ 19 de Pradilla, y la parcela desde donde se ha capturado esta imagen. Fuente visual: exclusiva aportaciâ”œâ”‚n de la colecciâ”œâ”‚n de Vicente Garcâ”œآ®s al "Gran Archivo Zaragoza Antigua" (GAZA).', 1962, 1962, 1962, 'Anos 60', 'SAN JOSâ”œأ«', 41.63792300, -0.88297100, '0101000020E610000014200A664C41ECBFE02EFB75A7D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33215518083.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33215518083.webp', 'https://www.flickr.com/photos/zaragozaantigua/33215518083/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22235, 'Romareda c.1955', 'Singular imagen capturada desde el nuevo Seminario Mayor o Metropolitano de Zaragoza y centrada en el panorama que desde allâ”œآ، se tenâ”œآ،a de la tradicional zona agrâ”œآ،cola del tâ”œآ®rmino de la Romareda. Se destaca al fondo la mole de la Residencia Sanitaria Jose Antonio, inmediata al convento de Jerusalâ”œآ®n. A la izquierda, torre de la Feria Nacional de Muestras y torre de la Editorial Luis Vives. A la derecha, el Colegio-Residencia de Nuestra Seâ”œâ–’ora del Pilar para Huâ”œآ®rfanos e Hijos del Magisterio.', 1955, 1955, 1955, 'Anos 50', 'UNIVERSIDAD', 41.63643800, -0.90444000, '0101000020E61000003737A6272CF1ECBF40F7E5CC76D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50234103647.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50234103647.webp', 'https://www.flickr.com/photos/zaragozaantigua/50234103647/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22475, 'Marquâ”œآ®s de Ahumada 1962', 'Irrepetible captura visual desde la terraza del nâ”¬â•‘ 14 de la calle del Marquâ”œآ®s de Ahumada, en el antiguo barrrio de los "Chiflaos", con una panorâ”œأ­mica perdida en la dimensiâ”œâ”‚n del pasado, que culmina al fondo con las estilizadas torres del Pilar. Inmediatos al objetivo, los tejados de las antiguas parcelas nâ”¬â•‘ 11 y nâ”¬â•‘ 13 de la referida calle; detrâ”œأ­s, el nâ”¬â•‘ 18 de la calle Francisco Cidâ”œâ”‚n, y el nâ”¬â•‘ 44 de la calle General Millâ”œأ­n Astray, ambas recayentes a la plaza homâ”œâ”‚nima. A la derecha, y al fondo, el referencial depâ”œâ”‚sito del "Gas" en el camino de las Torres, y a la izquierda, la mole del colegio de los PP. Agustinos. Con el tiempo, la foresta que emerge de las parcelas serâ”œأ­ progresivamente sustituida, junto a estas, por construcciones mâ”œأ­s modernas, y compactadas. Fuente visual: exclusiva aportaciâ”œâ”‚n de la colecciâ”œâ”‚n de Vicente Garcâ”œآ®s al "Gran Archivo Zaragoza Antigua" (GAZA).', 1962, 1962, 1962, 'Anos 60', 'SAN JOSâ”œأ«', 41.63809100, -0.88271300, '0101000020E6100000292158552F3FECBF9C6F44F7ACD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33861200272.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33861200272.webp', 'https://www.flickr.com/photos/zaragozaantigua/33861200272/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22752, 'Av. del Tenor Fleta 1971', 'Imagen de la avenida del Tenor Fleta en su primer tramo entre el paseo del General Mola (al fondo), y el cruce con el camino de las Torres (donde el reciente y chaflanero nâ”¬â•‘ 98 de este camino, inmediato y a la derecha). Al fondo, perdura el inmueble esquinero del paseo del General Mola con la avenida de Goya, en esos momentos funcionando todavâ”œآ،a como academia La Figuera, si bien poco le quedaba de porvenir. El provinciano edificio del antiguo nâ”¬â•‘ 17, casi en el centro de la imagen, destaca por una pertinaz escualidez que lo hace casi invisible entre los modernos gigantes que lo flanquean, un mal edilicio de remedio afortunadamente subsanable, al tiempo. Fuente visual: foto Gerardo Sancho Ramo, AMZ.', 1971, 1971, 1971, 'Anos 70', 'SAN JOSâ”œأ«', 41.64136300, -0.88429000, '0101000020E610000040C1C58A1A4CECBFA6EECA2E18D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32636126460.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32636126460.webp', 'https://www.flickr.com/photos/zaragozaantigua/32636126460/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22910, 'Frontâ”œâ”‚n agustino 1985', 'Imagen del antiguo frontâ”œâ”‚n doble del gran colegio de los PP. Agustinos, levantado en los aâ”œâ–’os 30 del pasado siglo. En el momento de realizar esta captura, una zona del original perâ”œآ،metro (al sureste) ya habâ”œآ،a sido retranqueada unas decenas de metros durante la urbanizaciâ”œâ”‚n del polâ”œآ،gono de Miraflores, y apertura de nuevos viales (calle de Uncastillo, y paseo de los Rosales). A la derecha del frontâ”œâ”‚n perduraba una arboleda, y una gran zona de huerta y campos de cultivo, y al fondo, un campo de fâ”œâ•‘tbol, de los dos que llegâ”œâ”‚ a haber (entre ellos, el de "La Amistad"). Tras los muros del colegio, las grandes torres de viviendas del polâ”œآ،gono de Miraflores, el colegio pâ”œâ•‘blico Miraflores, el parque del mismo nombre, y algunos grandes bloques de la avenida de Cesâ”œأ­reo Alierta, en el emboque a la calle del escultor Fâ”œآ®lix Burriel. Unos pocos aâ”œâ–’os despuâ”œآ®s, la mayor parte de este sector del colegio desaparecerâ”œأ­ tras la venta del suelo, la construcciâ”œâ”‚n de dos grandes bloques en el andador de Luis Puntes, y la apertura de la nueva calle de Francisco Albiâ”œâ–’ana, que pasarâ”œأ­ justo por donde estâ”œأ­ el frontâ”œâ”‚n (a menos cota de altura). Fuente visual: www.agustinoszaragoza.com/', 1985, 1985, 1985, 'Anos 80', 'SAN JOSâ”œأ«', 41.64085800, -0.88079300, '0101000020E61000009B7631CD742FECBFA3B08BA207D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22823346958.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22823346958.webp', 'https://www.flickr.com/photos/zaragozaantigua/22823346958/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23257, 'C.â”¬â•‘ de las Torres 1968', 'Imagen capturada durante las obras de urbanizaciâ”œâ”‚n de la avenida de Tenor Fleta desde el paseo del General Mola, a la derecha, y hasta el camino del Puente del Virrey, hacia la izquierda. Esta actuaciâ”œâ”‚n estaba relacionada con el cubrimiento de la zanja del ferrocarril desde Campo Sepulcro, que impulsâ”œâ”‚ el vertiginoso y vertical crecimiento de bloques habitacionales a ambos lados del antiguo "camino del ferrocarril de los directos Madrid-Barcelona", ahora redenominado en estos casi cuatro kilâ”œâ”‚metros como "Goya", y "Tenor Fleta". Esta imagen se ha tomado en el cruce de Tenor Fleta con el camino de las Torres, que al fondo confluye con General Mola. La macizada manzana de bloques en construcciâ”œâ”‚n de la izquierda fue durante muchas dâ”œآ®cadas la ubicaciâ”œâ”‚n de las instalaciones de la TUDOR. Podemos contemplarla tan diâ”œأ­fanamente porque los nuevos bloques de Tenor Fleta aâ”œâ•‘n no han llegado a ese punto. A la derecha, la esquinera ubicaciâ”œâ”‚n de la clâ”œآ،nica del doctor Ricardo Horno inaugurada en 1950. En primer tâ”œآ®rmino, la acequia de las Adulas, o del Presidio, o de San Josâ”œآ®, fluyendo al aire en direcciâ”œâ”‚n al salto de la "Lanera Aragonesa", primero, y al "Gas", despuâ”œآ®s.', 1968, 1968, 1968, 'Anos 60', 'SAN JOSâ”œأ«', 41.64112200, -0.88381800, '0101000020E610000052B7B3AF3C48ECBF815F234910D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22489447334.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22489447334.webp', 'https://www.flickr.com/photos/zaragozaantigua/22489447334/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24188, 'Tenor Fleta 1951', 'Imagen de la calle Tenor Fleta desde el cruce con el Camino de las Torres, en direcciâ”œâ”‚n a Puente Virrey, al fondo. A la izquierda, el muro de los PP. Agustinos. A la derecha, campos de cultivo entre el Camino de las Alcachoferas y la Torre de Fletas. Fuente visual: Archivo Mora, AMZ.', 1951, 1951, 1951, 'Anos 50', 'SAN JOSâ”œأ«', 41.64047900, -0.88270400, '0101000020E61000005D8C81751C3FECBF2C634337FBD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20325813261.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20325813261.webp', 'https://www.flickr.com/photos/zaragozaantigua/20325813261/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25018, 'Disco Bar &quot;Liverpool&quot; 1977', 'Colectivo Plâ”œأ­stico de Zaragoza. Octubre 1977. En el chaflâ”œأ­n de la calle Comâ”œآ،n con el Camino de las Torres, "Liverpool discotheque", "La Liverpul", de cuando en las discotecas se ponâ”œآ،a mâ”œâ•‘sica rock. La fachada, un mural ideado y realizado por el "Colectivo Plâ”œأ­stico de Zaragoza".', 1977, 1977, 1977, 'Anos 70', 'SAN JOSâ”œأ«', 41.64148900, -0.88359400, '0101000020E61000006C239EEC6646ECBF33DFC14F1CD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15007121087.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15007121087.webp', 'https://www.flickr.com/photos/zaragozaantigua/15007121087/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25773, 'C.â”¬â•‘ de las Torres 1968', 'Imagen capturada durante el proceso de urbanizaciâ”œâ”‚n de la avenida del Tenor Fleta, en el cruce con el camino de las Torres, con la caudalosa y antigua acequia de las Adulas, o de San Josâ”œآ®, como protagonista en primer plano, tras recibir el aporte de la acequia del Entonar, desde el antiguo camino de las Alcachoferas, por la derecha. A la izquierda, vista muy parcial del nuevo bloque del nâ”¬â•‘ 19 de la avenida del Tenor Fleta, levantado sobre el huerto trasero del nâ”¬â•‘ 18-20 de la calle Comâ”œآ،n, antigua del Alba. A su derecha, huertos de las parcelas de los antiguos nâ”¬â•‘ 22, y 24 de esa misma calle, que poco despuâ”œآ®s serâ”œآ،an sustituidas por un bloque con el nuevo nâ”¬â•‘ 98-100 del camino de las Torres. Tras ellas, emergen las obras de construcciâ”œâ”‚n del nuevo bloque del nâ”¬â•‘ 96, recayente a la calle de Comâ”œآ،n. A la izquierda, el convento-colegio de los PP. Agustinos, y la grâ”œâ•‘a de obra de la nueva iglesia parroquial de Santa Rita de Casia. Fuente visual: Archivo Municipal de Zaragoza.', 1968, 1968, 1968, 'Anos 60', 'SAN JOSâ”œأ«', 41.64096200, -0.88411900, '0101000020E61000000FB6D8EDB34AECBF48FDF50A0BD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33631770375.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33631770375.webp', 'https://www.flickr.com/photos/zaragozaantigua/33631770375/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25786, 'C.â”¬â•‘ de las Torres 1968', 'Imagen capturada durante las obras de cubrimiento de la acequia de San Josâ”œآ® previas a la urbanizaciâ”œâ”‚n del tramo del camino de las Torres comprendido entre la calle de Colâ”œâ”‚n (a la izquierda) y del Tenor Fleta. De fondo, los modernos inmuebles de los nâ”œâ•‘meros 106 y 104 del camino de las Torres, por donde circula entre el trâ”œأ­fico un autobâ”œâ•‘s de la lâ”œآ،nea "Puente Virrey-Plaza de Huesca". En primer tâ”œآ®rmino, zanja de la acequia de las Adulas, del Presidio (porque pasaba junto al antiguo presidio o penal), o de San Josâ”œآ® durante las obras de cubrimiento a la altura de las calles de N.â”¬آ¬ S.â”¬آ¬ de Abarca y Josâ”œآ® Pellicer.', 1968, 1968, 1968, 'Anos 60', 'SAN JOSâ”œأ«', 41.64075900, -0.88435600, '0101000020E61000001DAF40F4A44CECBF10CF126404D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51658962504.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51658962504.webp', 'https://www.flickr.com/photos/zaragozaantigua/51658962504/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25994, 'PP. Agustinos Aâ”œâ–’os 40', 'Imagen que aâ”œâ•‘n sigue catalogada oficialmente como "La Zaragozana. Fâ”œأ­brica de cerveza. Vista exterior de la fâ”œأ­brica." Se trata del convento-colegio de los PP. Agustinos en el Camino de las Torres, tomada desde la trasera del pabellâ”œâ”‚n principal, con una buena visual del terreno de Miraflores que, delimitado por su muralla neomudâ”œآ®jar, formaba parte del colegio. Construido en estilo historicista-eclâ”œآ®ctico segâ”œâ•‘n proyecto de Miguel â”œأ¼ngel Navarro al comienzo de los aâ”œâ–’os 30, contaba en proyecto con una enorme iglesia cuya torre alcanzaba los 70 metros de altura. Tras el 18-07-1936, los nacionalistas lo reutilizaron como cuartel y hospital de aliados italianos, y las obras quedaron suspensas. Tras 1939, la original iglesia ya no se realizarâ”œآ،a. En la imagen se aprecia la traza de su proyectada planta en cruz latina con naves laterales abiertas en capillas. En 1968 comenzaron las obras de una nueva iglesia segâ”œâ•‘n planos de Josâ”œآ® Luis Navarro (hijo de Miguel â”œأ¼ngel Navarro). El proyecto, menos costoso, sin la torre, y en otro estilo, fue consagrado a la santa catâ”œâ”‚lica "abogada de los imposibles" (santa Rita de Casia), que tambiâ”œآ®n lo es de las vâ”œآ،ctimas de abusos, personas en soledad, de la prevenciâ”œâ”‚n de esterilidad y enfermedades del cuerpo en general, de matrimonios con dificultades, viudas, padres... Fuente visual: AHPZ, Archivo Mora', 1940, 1940, 1949, 'Anos 40', 'SAN JOSâ”œأ«', 41.64140900, -0.88128800, '0101000020E6100000936E4BE48233ECBF172EABB019D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20357950342.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20357950342.webp', 'https://www.flickr.com/photos/zaragozaantigua/20357950342/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25765, 'Av. San Josâ”œآ® 1977', 'Imagen capturada en el tramo alto de la avenida de San Josâ”œآ®, entre las calles de Garcâ”œآ،a Lorca y Luis Royo Villanova (ambas, a la derecha), con visual (a la izquierda) de la fachada del "Colegio de Marâ”œآ،a Auxiliadora" de las salesianas, inaugurado en 1953, y del solar dejado por las antiguas parcelitas de los nâ”œâ•‘meros 206 y 208, donde poco despuâ”œآ®s se levantarâ”œأ­ el actual bloque 206-208. Junto al colegio, a su izquierda, una pequeâ”œâ–’a puertecilla (que perdura) indica el cauce al aire de la acequia del Entonar, que baja desde la antigua fâ”œأ­brica textil de PINASAR. La conversiâ”œâ”‚n del antiguo camino de San Josâ”œآ® en una gran vâ”œآ،a de circulaciâ”œâ”‚n rodada, que pasa circunstancialmente por el barrio de San Josâ”œآ®, es un hito de la movilidad urbana que deberâ”œآ،a ser revertido. El retorno del tranvâ”œآ،a en su versiâ”œâ”‚n moderna es, en este sentido, una posibilidad para un futuro mejor. Fuente visual: foto Gerardo Sancho Ramo, AMZ.', 1977, 1977, 1977, 'Anos 70', 'SAN JOSâ”œأ«', 41.63527700, -0.87992400, '0101000020E610000069E55E605628ECBF5473B9C150D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32675506530.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32675506530.webp', 'https://www.flickr.com/photos/zaragozaantigua/32675506530/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25779, 'Calle de Agustâ”œآ،n Querol c.1945', 'Imagen capturada desde un baldâ”œآ،o inmediato a la acequia del Ontonar (a la derecha, fuera de plano) y centrada en la cara sur de la fâ”œأ­brica de cerveza, malta y hielo La Zaragozana SA con sus originales instalaciones y gran chimenea de principios de siglo diseâ”œâ–’adas por los ingenieros Mayandâ”œآ،a y Egozcue (Egorgâ”œâ•‌e o Ezorgâ”œâ•‌e, segâ”œâ•‘n otras versiones). A la izquierda, traseras de la parcela con extenso huerto del nâ”¬â•‘ 1 de la desaparecida calle de Agustâ”œآ،n Querol. Apilados junto al muro, centenares de cascos de vidrio posiblemente usados y algunas cajas de madera para botellas. Detrâ”œأ­s de la fâ”œأ­brica, el camino de las Alcachoferas, por donde fluye en paralelo la acequia de Ontonar hasta desembocar en la acequia de San Josâ”œآ® en el camino de las Torres. Aâ”œâ–’os despuâ”œآ®s comenzâ”œâ”‚ la radical remodelaciâ”œâ”‚n urbanâ”œآ،stica de este entorno, impulsada fundamentalmente por la ampliaciâ”œâ”‚n edilicia de la fâ”œأ­brica cervecera. Fuente visual: foto Juan Mora Insa, en Archivo Josâ”œآ® Marâ”œآ،a Ballestâ”œآ،n Miguel.', 1945, 1945, 1945, 'Anos 40', 'SAN JOSâ”œأ«', 41.63663200, -0.88136100, '0101000020E61000000F09DFFB1B34ECBF25CB49287DD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40568194804.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40568194804.webp', 'https://www.flickr.com/photos/zaragozaantigua/40568194804/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21540, '&quot;Jardâ”œآ،n de Pina&quot; 1923', 'La impresionante casa de Dâ”œأ­maso Pina llamaba la atenciâ”œâ”‚n en las terrazas de Pina, junto al Canal Imperial, en las alturas del barrio de San Josâ”œآ®, en una curva que tantas veces aparece en postales, fotografâ”œآ،as e imâ”œأ­genes de la â”œآ®poca. Mas esa no era la â”œâ•‘nica cosa reseâ”œâ–’able de esta notable construcciâ”œâ”‚n. Detrâ”œأ­s de la fachada y su visual remate en torreâ”œâ”‚n, aguardaba un precioso conjunto de jardines, estatuas, pâ”œآ®rgolas, parterres, un cenador, y una destacable variedad de plantas y â”œأ­rboles con buenas vistas a los terrenos inferiores, y al propio Canal, desde donde fluâ”œآ،a la acequia del Ontonar. Los importantes desniveles aterrazados, mâ”œأ­s allâ”œأ­ de los muros de la casa, permitâ”œآ،an ocho fructâ”œآ،feros huertos de notable tamaâ”œâ–’o. La imagen recoge la parte del jardâ”œآ،n orientada hacia la calle de Cantarranas y, mâ”œأ­s abajo, la fâ”œأ­brica textil de la misma familia Pina, de la que un pedazo de chimenea destaca por encima de la balaustrada. A la izquierda de estos jardines un aâ”œâ–’o despuâ”œآ®s se instalarâ”œأ­ el colegio de La Salle Torrero, para hacer competencia a las cercanas y laicas escuelas de Julio Cejador Frauca. Asâ”œآ، se mantuvo esto hasta la dâ”œآ®cada de los aâ”œâ–’os 70, cuando toda la superficie de la casa, el jardâ”œآ،n y los huertos, fueron aplanados y reconvertidos en los bloques de viviendas que hoy se elevan entre las calles del Pintor Marâ”œآ،n Bagâ”œâ•‌â”œآ®s, la Plaza del Canal Imperial, y las Terrazas de Cuâ”œآ®llar. Fuente visual: AHPZ. Archivo Julio Requejo. 10/06/1923.', 1923, 1923, 1923, 'Anos 20', 'SAN JOSâ”œأ«', 41.63285300, -0.87960300, '0101000020E6100000E5D4CE30B525ECBF7616BD5301D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20043777129.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20043777129.webp', 'https://www.flickr.com/photos/zaragozaantigua/20043777129/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21541, 'Fâ”œأ­brica de Pina 1927', 'Zaragoza tuvo que esperar hasta bien mediados del XIX para que se iniciara a escala apreciable la fabricaciâ”œâ”‚n mecâ”œأ­nica de tejidos, principalmente de lencerâ”œآ،a, lonas, y algunas telas de vestir. Mientras que las telas de vestir seguirâ”œأ­n siendo importadas al 98%, el "boom" textil fue protagonizado por la fabricaciâ”œâ”‚n de lonas para alpargatas, para toldos, velamen de embarcaciones, y otros usos, de tal forma que Zaragoza se convirtiâ”œâ”‚ en suministrador principal del mercado interior espaâ”œâ–’ol. Uno de los promotores industriosos mâ”œأ­s destacados fue Dâ”œأ­maso Pina (padre), que tuvo continuidad familiar con sus hijos, Dâ”œأ­maso Pina (hijo), y aun nietos, Alfredo Sarto Pina, con quienes la fâ”œأ­brica llegâ”œâ”‚ a ser una de las mâ”œأ­s importantes de Espaâ”œâ–’a. La factorâ”œآ،a principal estaba ubicada en lo que hoy es el Parque-Jardâ”œآ،n de la Memoria del Barrio, que la imagen captura desde los feraces campos de labor de la actual calle Melilla. La imagen de conjunto es ciertamente impresionante, y en el interior de las naves se contaba con la maquinaria textil mâ”œأ­s moderna del momento, como la mâ”œأ­quina "rompe-balsa"; la Caja de polvo Grigthon con su abridora y transportador; un Batâ”œأ­n atelador; un Batâ”œأ­n repasador; Cardas de chaprones; mâ”œأ­quinas de estirar y torcer las mechas; mâ”œأ­quinas mecheras; mâ”œأ­quinas continuas de hilar; mâ”œأ­quinas de retorcer; mâ”œأ­quina de doblar, de aspeas, de hacer cordones especiales, etc. Habâ”œآ،a tambiâ”œآ®n instalaciones para blanqueo, apresto y teâ”œâ–’ido de hilados. La lona salâ”œآ،a para hacer alpargatas, para toldos de vagones de tren y todo tipo de carruajes, para mangueras, para filtros de azucareras, loneta kaki para uniformes, para calzados, para cinchas de caballerâ”œآ،as... En total, unos 50.000 metros cuadrados, y mâ”œأ­s de 500 personas trabajando en las instalaciones. Fuese, y no hubo nada, ni siquiera la chimenea de la imagen, que se intentâ”œâ”‚ mantener como recuerdo y memoria del Barrio y la ciudad, pero eran aâ”œâ–’os en que la moda de la conservaciâ”œâ”‚n de chimeneas no estaba muy asentada. Fuente visual: ', 1927, 1927, 1927, 'Anos 20', 'SAN JOSâ”œأ«', 41.63409600, -0.87890600, '0101000020E6100000FA42C879FF1FECBF2043C70E2AD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20062892550.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20062892550.webp', 'https://www.flickr.com/photos/zaragozaantigua/20062892550/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21618, 'Calle de Cantarranas 1926', 'Imagen de la maqueta con las instalaciones de la fâ”œأ­brica de tejidos Hijos de Dâ”œأ­maso Pina, S.A., en la empinada parte final del camino de San Josâ”œآ® donde la abundancia de agua surtida del Canal Imperial por medio de las acequias del Plano, y de Ontonar, convirtiâ”œâ”‚ a esta zona en el principio del siglo XX en un denso paraje industrial con las harineras de La Constancia, y de Morâ”œâ”‚n, una fâ”œأ­brica de yeso, y este monumental taller textil. A la izquierda de la maqueta, la fila de viviendas para trabajadores de la fâ”œأ­brica construidas en la calle de Cantarranas (el â”œâ•‘nico vial con nombre, en esa â”œآ®poca), y cuyas traseras daban a la referencial Torre de Dâ”œأ­maso Pina. Luego, y en descenso, sucesiâ”œâ”‚n de naves y talleres junto a la derivaciâ”œâ”‚n de la acequia del Ontonar que era conducida por el interior de la fâ”œأ­brica. En primer plano, el edificio con el taller de reparaciones de maquinaria, la carpinterâ”œآ،a, y un almacâ”œآ®n. Tras el cierre y derribo de la factorâ”œآ،a, este terreno fue encaminado por los senderos de la especulaciâ”œâ”‚n urbanâ”œآ،stica (que no es un defecto, sino la definiciâ”œâ”‚n del proceso) hacia la conversiâ”œâ”‚n en un conglomerado de torres edilicias babilâ”œâ”‚nicas, de las que afortunadamente sâ”œâ”‚lo se hizo una. La chimenea fue el â”œâ•‘ltimo vestigio de esta fâ”œأ­brica que quedâ”œâ”‚ en pie durante unos aâ”œâ–’os, y que la asociaciâ”œâ”‚n vecinal de San Josâ”œآ® trabajâ”œâ”‚ para su permanencia, mas no fue posible (el Ayuntamiento no quiso). Fuente visual: La Historia de la Industrializaciâ”œâ”‚n de Zaragoza.', 1926, 1926, 1926, 'Anos 20', 'SAN JOSâ”œأ«', 41.63409600, -0.87890600, '0101000020E6100000FA42C879FF1FECBF2043C70E2AD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32270418835.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32270418835.webp', 'https://www.flickr.com/photos/zaragozaantigua/32270418835/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21654, 'Calle del Doce de Octubre 1927', 'Imagen centrada en el primer tramo de la calle del Doce de Octubre capturada desde su arranque en el camino de San Josâ”œآ®. A la izquierda e inmediatos, talleres de la fâ”œأ­brica de muebles de Urbano Bernardos de Frutos. A la derecha, parcelas con viviendas de dos alturas del lado de los pares de esta calle, en cuyas traseras se abrâ”œآ،an los correspondientes huertos regados por una derivada de la acequia del Antonar o Entonar. El firme de terroso, destacando alguna esporâ”œأ­dica pareja de â”œأ­rboles donde "la acera". Hacia el fondo la calle se va empinando en su ascenso a las calles de Lizarbe. Tejar, y al barrio de Cuber.', 1927, 1927, 1927, 'Anos 20', 'SAN JOSâ”œأ«', 41.63585400, -0.87875400, '0101000020E61000007A5567B5C01EECBFF183F3A963D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52195393221.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52195393221.webp', 'https://www.flickr.com/photos/zaragozaantigua/52195393221/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21656, 'Calle de la Huerta 1927', 'Imagen capturada en el barrio de Colâ”œâ”‚n, tramo final y en ascenso de la calle de la Huerta donde al fondo arranca hacia la derecha la calle de Levante. Era este uno de los barrios particulares surgidos de la parcelaciâ”œâ”‚n de varios terrenos de cuatro grandes propietarios en esta empinada zona inmediata al Canal Imperial de Aragâ”œâ”‚n. En el momento de realizar esta fotografâ”œآ،a se encontraba vertebrado por las calles de Amâ”œآ®rica, Treinta y Uno de Julio, Zaragoza, Nador, La Huerta y Levante, y contaba con unas ciento treinta parcelas (construidas y en construcciâ”œâ”‚n) de una/dos alturas con huerto y corral. Su condiciâ”œâ”‚n de barrio particular lo asemejaba a los otros barrios particulares de la zona y de la ciudad en general: sin pavimentaciâ”œâ”‚n, iluminaciâ”œâ”‚n, agua corriente y vertido de aguas residuales, entre otros servicios bâ”œأ­sicos de los que carecâ”œآ،a. Esas "cualidades" se traducâ”œآ،an en que sus moradores fueran familias trabajadoras pobres o muy pobres.', 1927, 1927, 1927, 'Anos 20', 'SAN JOSâ”œأ«', 41.63181900, -0.87670600, '0101000020E61000008C9FC6BDF90DECBFE7FEEA71DFD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52326513929.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52326513929.webp', 'https://www.flickr.com/photos/zaragozaantigua/52326513929/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21680, 'San Josâ”œآ®-Cuber-Colâ”œâ”‚n 1932', 'Imagen capturada desde la quinta del industrial Leandro Sanz Pâ”œآ®rez, inmediata a la fâ”œأ­brica de lonas para alpargatas de su propiedad en el nâ”¬â•‘ 376 de Torrero, desde que se separara de su socio el seâ”œâ–’or Castillo en 1902 y que desde 1930 era denominada "Fâ”œأ­brica de Tejidos de los Hijos de don Leandro Sanz", situada a la izquierda y fuera de plano en esta elevada zona entre la travesâ”œآ،a del Puente del Virrey y la calle de Cuber. Entre la torre, quinta o casa y la fâ”œأ­brica y al aire fluye la nueva acequia del Plano, que aquâ”œآ، tenâ”œآ،a un salto de agua para proveer de energâ”œآ،a a la fâ”œأ­brica y que en la imagen se muestra encajonada y en serpenteante descenso desde la altura de la fâ”œأ­brica textil de Dâ”œأ­maso Pina. Hacia el fondo, el final en alto de la calle del Doce de Octubre y el arranque de la subida de Bescâ”œâ”‚s, donde el barrio de San Josâ”œآ® lindaba con el barrio de Cuber y la torre de don Felipe Cuber. Detrâ”œأ­s, el urbanismo disperso y discontinuo llega, en ascenso, hasta las parcelas del barrio de Colâ”œâ”‚n que coronan su altura determinada a la derecha por la calle de los Mâ”œأ­rtires de Jaca y su confluencia con la calle de Amâ”œآ®rica. El escenario aparece decorado de blanco por la destacada nevada que la maâ”œâ–’ana del dâ”œآ،a 12 de febrero de ese aâ”œâ–’o depositâ”œâ”‚ espesores entre los 20 y 40 centâ”œآ،metros. que en las "afueras" despertâ”œâ”‚ gran expectaciâ”œâ”‚n entre el vecindario, originando ademâ”œأ­s una "peregrinaciâ”œâ”‚n" de zaragozanos que desde la ciudad subâ”œآ،an hasta las alturas del Cabezo y parque de Buenavista, ademâ”œأ­s del Cabezo Cortado, que en la imagen queda fuera de plano y bastante a la izquierda.', 1932, 1932, 1932, 'Anos 30', 'SAN JOSâ”œأ«', 41.63470600, -0.87635200, '0101000020E61000001A187959130BECBF9949D40B3ED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14877621231.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14877621231.webp', 'https://www.flickr.com/photos/zaragozaantigua/14877621231/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22099, 'Avenida de San Josâ”œآ® 1951', 'La unidad 92, de la lâ”œآ،nea 13 ("San Josâ”œآ®"), delante del reciente cine Rialto (habâ”œآ،a abierto un par de aâ”œâ–’os antes), donde la Cuesta de Morâ”œâ”‚n se hace carne mortal y nos recuerda que "subir" a Torrero no es una metâ”œأ­fora. El tranvâ”œآ،a, segâ”œâ•‘n los expertos, estaba pintado en azul y crema, y este publicita un producto "repara medias". A la izquierda, la entrada a la calle Doce de Octubre, flanqueada por una parcela con peluquerâ”œآ،a en los bajos, y por las naves de la "Catedral del Mueble". Fuente visual: Los tranvâ”œآ،as de Zaragoza, J. Peâ”œâ–’a - J. M. Valero, DPZ, 1985.', 1951, 1951, 1951, 'Anos 50', 'SAN JOSâ”œأ«', 41.63574000, -0.87912000, '0101000020E6100000FD4D2844C021ECBF2861A6ED5FD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20392959372.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20392959372.webp', 'https://www.flickr.com/photos/zaragozaantigua/20392959372/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22171, 'Av. San Josâ”œآ® c.1956', 'Luminosa y festiva captura realizada junto a la marquesina del original cine Rialto, inaugurado unos aâ”œâ–’os antes en la avenida de San Josâ”œآ®, en el arranque de la "Cuesta de Morâ”œâ”‚n", cuya reconocida dureza fue reconocida en eventos como este: una competiciâ”œâ”‚n ciclista amateur con todas las de la ley, organizada en esta humilde barriada de la periferia. La imagen recoge el momento de entrega de distinciones a los ganadores (o supervivientes), junto a la tribuna repleta de pâ”œâ•‘blico que posa con entusiasmo, mientras un locutor, a la derecha, anima el evento. En primer tâ”œآ®rmino, Antonio Mariâ”œâ–’osa Gea, Adolfo Bello y posiblemente Josâ”œآ® Gascâ”œâ”‚n. Fuente visual: Banco de Imâ”œأ­genes del Barrio de San Josâ”œآ®.', 1956, 1956, 1956, 'Anos 50', 'SAN JOSâ”œأ«', 41.63574000, -0.87912000, '0101000020E6100000FD4D2844C021ECBF2861A6ED5FD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31365402064.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31365402064.webp', 'https://www.flickr.com/photos/zaragozaantigua/31365402064/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22518, 'C.â”¬â•‘ del Puente del Virrey c.1964', 'Inâ”œآ®dita imagen capturada en la torre de Alfredo Sarto Pina sita en el camino del Puente del Virrey donde figura Carmen Lâ”œأ­zaro Sierra, hija de los "guardeses" de la torre. Al fondo y sobre el muro de la torre, una oriental y despejada vista que alcanza hasta la manzana de modernas viviendas (incluyendo un desarrolista bloque de nueve alturas) construidas en el â”œâ•‘ltimo tramo de la calle de Cartagena, entre una calle de nueva traza que poco despuâ”œآ®s serâ”œآ،a denominada de Armando Palacio Valdâ”œآ®s y el camino de Cabaldâ”œâ”‚s. Poco despuâ”œآ®s de ser tomada esta fotografâ”œآ،a la torre de Alfredo Sarto Pina completarâ”œآ،a su urbanizaciâ”œâ”‚n de la que resultarâ”œآ،a la apertura de la actual calle de â”œأ¼ngel Ganivet y la construcciâ”œâ”‚n de los bloques del lado de sus impares.', 1964, 1964, 1964, 'Anos 60', 'SAN JOSâ”œأ«', 41.63844200, -0.87447500, '0101000020E61000005D6DC5FEB2FBEBBF4832AB77B8D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52488699499.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52488699499.webp', 'https://www.flickr.com/photos/zaragozaantigua/52488699499/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22521, 'Travesâ”œآ،a del Puente del Virrey 1961', 'Imagen capturada durante las fiestas del barrio de San Josâ”œآ® del aâ”œâ–’o 1961 organizadas en honor de San Josâ”œآ® de Calasanz, durante la procesiâ”œâ”‚n general que tras el rezo del rosario en la iglesia de San Lino recorriâ”œâ”‚ algunas calles de la parte alta del barrio. Aquâ”œآ، la procesiâ”œâ”‚n viene de bajada desde la calle de Lizarbe desembocando en la arbolada Travesâ”œآ،a del Puente del Virrey para continuar luego por la calle de Zaragoza la Vieja y el camino del Puente del Virrey hasta la avenida del Tenor Fleta. La escena se centra en las "bellâ”œآ،simas" seâ”œâ–’oritas ataviadas con festivos atuendos, tradicionalistas mantillas y las bandas que las identifican como "presidentas" de las fiestas, acompaâ”œâ–’adas por un plantel de niâ”œâ–’as abaturradas y aspirantes a ser las "presidentas del maâ”œâ–’ana", por algunos escolapios y seguidas por los comunes.', 1961, 1961, 1961, 'Anos 60', 'SAN JOSâ”œأ«', 41.63618900, -0.87685700, '0101000020E6100000F6984869360FECBF988922A46ED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54158959373.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54158959373.webp', 'https://www.flickr.com/photos/zaragozaantigua/54158959373/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22627, 'Av. de San Josâ”œآ® 1974', 'Imagen de la unidad 208 de la tranviaria Lâ”œآ،nea 11 (Parque-San Josâ”œآ®) en la Avenida de San Josâ”œآ®, tras haberse incorporado desde la izquierda, por la calle Suiza, y se dispone a iniciar el recorrido hasta el Parque. A la derecha, el acceso a la calle Bellavista, y vista de la antigua manzana de parcelas de los aâ”œâ–’os 30 que llegaba hasta la Travesâ”œآ،a del Puente del Virrey, con panaderâ”œآ،a, tiendas de chuches y revistas, una vaquerâ”œآ،a, un taller... Aâ”œâ–’os despuâ”œآ®s, serâ”œأ­n derribadas. Hoy, en ese lugar, se encuentra la nueva plaza del Primero de Mayo.', 1974, 1974, 1974, 'Anos 70', 'SAN JOSâ”œأ«', 41.63630900, -0.87836900, '0101000020E6100000463F1A4E991BECBF4293C49272D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20151991458.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20151991458.webp', 'https://www.flickr.com/photos/zaragozaantigua/20151991458/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22631, 'Cadena de la Granja 1975', 'Son los â”œâ•‘ltimos dâ”œآ،as del aâ”œâ–’o, un aâ”œâ–’o que luego serâ”œآ،a valorado como el principio de muchas cosas, incuestionables. Las permanencias y continuidades ocuparâ”œأ­n muchâ”œآ،sima menos tinta: el pensamiento mâ”œأ­gico las tratarâ”œأ­ como si no estuvieran. Mas sâ”œآ،. Asâ”œآ، terminaba entonces la flamante avenida del Tenor Fleta (al fondo) tras cruzarse con el Camino del Puente del Virrey. La imagen estâ”œأ­ capturada desde la terrenal calle "Cadena de la Granja", una de esas esplâ”œآ®ndidas, y perdidas, muestras del nomenclâ”œأ­tor zaragozano en llamar las cosas por su nombre, sin tener que apelar a extravagancias, como los juegos de computadora: aquâ”œآ، habâ”œآ،a una cadena para cerrar el paso a nivel que conducâ”œآ،a a la Granja Agrâ”œآ،cola Experimental, antes del cubrimiento de la trinchera del tren. Un pretil pretendâ”œآ،a prevenir accidentes, aunque muy levemente. A la izquierda, el Colegio "Calixto Ariâ”œâ–’o-Mariano de Cavia", una de las Escuelas construidas por la Segunda Repâ”œâ•‘blica que seguâ”œآ،an en las mismas condiciones, literalmente, que el dâ”œآ،a de su inauguraciâ”œâ”‚n. A la derecha, se atisba el comienzo de la desigual manzana que llegaba hasta la que fuera calle del "11 de febrero" (fecha de la proclamaciâ”œâ”‚n de la Primera Repâ”œâ•‘blica Espaâ”œâ–’ola, en 1873), tras el 18 de julio de 1936 "Escultor Moreto". El paisaje lo domina la masa de gigantescos bloques de viviendas levantados durante el desarrollismo franquista, que se detuvo justo donde decidiâ”œâ”‚ terminar el cubrimiento de las vâ”œآ،as. Mâ”œأ­s allâ”œأ­, es decir, mâ”œأ­s acâ”œأ­, sin transiciâ”œâ”‚n, el agro puro y duro. Los grandes propietarios de suelo habâ”œآ،an decidido que la ciudad tenâ”œآ،a que crecer por otros lados. Fuente visual: AMZ, Gerardo Sancho Ramo.', 1975, 1975, 1975, 'Anos 70', 'SAN JOSâ”œأ«', 41.63642200, -0.87450700, '0101000020E610000035F0A31AF6FBEBBF3B3AAE4676D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20220875452.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20220875452.webp', 'https://www.flickr.com/photos/zaragozaantigua/20220875452/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22238, 'Pâ”¬â•‘ Isabel la Catâ”œâ”‚lica 1955', 'Nocturna imagen capturada desde la altura de la torre-mirador de la Feria de Muestras, orientada hacia el nuevo paseo de Isabel la Catâ”œâ”‚lica, que iluminado vertebra esta perifâ”œآ®rica zona de la ciudad, coincidente con el tranviario tendido de la lâ”œآ،nea 15. Casablanca. A su izquierda destaca la estructura de la Residencia Sanitaria Josâ”œآ® Antonio y, mâ”œأ­s en penumbra, el Colegio-Residencia de Nuestra Seâ”œâ–’ora del Pilar para Huâ”œآ®rfanos e Hijos del Magisterio. A la derecha, luces que alumbran los trabajos preliminares de la construcciâ”œâ”‚n del estadio municipal de fâ”œâ•‘tbol, y a continuaciâ”œâ”‚n el convento de Jerusalâ”œآ®n.', 1955, 1955, 1955, 'Anos 50', 'UNIVERSIDAD', 41.63565200, -0.90073900, '0101000020E6100000726A6798DAD2ECBF89D1730B5DD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50878171236.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50878171236.webp', 'https://www.flickr.com/photos/zaragozaantigua/50878171236/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22637, 'Calle Suiza 1974', 'El 30 de agosto de 1945 se inaugura la Lâ”œآ،nea 13 del tranvâ”œآ،a, denominada "San Josâ”œآ®", de 2200 metros de longitud. Como la Plaza de Espaâ”œâ–’a estaba saturada de terminales, se construyâ”œâ”‚ un ramal en la reciâ”œآ®n ensanchada calle de Eusebio Blasco (lateral al Teatro Principal), para situar el comienzo de lâ”œآ،nea, cuya Terminal estaba al comienzo de la Cuesta de Morâ”œâ”‚n, en la Avenida de S. Josâ”œآ®, para dar servicio a la Harinera allâ”œآ، instalada. Poco despuâ”œآ®s, justo allâ”œآ،, se inaugurarâ”œأ­ el Cine Rialto. En 1951 se construyâ”œâ”‚ un tortuoso bucle en la terminal de la Avenida de S. Josâ”œآ®, zigzageando por las calles de "Millâ”œأ­n Astray" (luego, Marâ”œآ،a Moliner), Monforte y Suiza, para desembocar en la Avenida de S. Josâ”œآ®. En 1967 se unieron las lâ”œآ،neas 11 y 13 en la nueva Lâ”œآ،nea 11 "Parque-S. Josâ”œآ®", en activo hasta el 23 de enero de 1976. En la imagen, captura de un vehâ”œآ،culo de la serie 200 saliendo de la calle Suiza para dar la pirivuelta que lo colocaba en disposiciâ”œâ”‚n de acceder a la Avenida de S. Josâ”œآ® para regresar hasta el "Parque". La parcela de la izquierda, con el nâ”¬â•‘ 176 de la Avenida, era de 1936, superviviente hasta hace no demasiado tiempo, en que fue derruida para ganar verticalidad. El edificio del otro lado de la calle, el nâ”¬â•‘ 172, de 1930 sobrevive, aunque ya sin la carnicerâ”œآ،a de la imagen. Fuente visual: Imâ”œأ­genes Antiguas Zaragoza.', 1974, 1974, 1974, 'Anos 70', 'SAN JOSâ”œأ«', 41.63626100, -0.87886300, '0101000020E61000002843554CA51FECBF315C1D0071D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20258015861.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20258015861.webp', 'https://www.flickr.com/photos/zaragozaantigua/20258015861/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22775, 'Av. de San Josâ”œآ® 1972', 'Imagen capturada en el cruce de la Av. del Tenor Fleta con la Av. de San Josâ”œآ®, y motivada por el reciente retoque urbanâ”œآ،stico que, al objeto de favorecer la movilidad del trâ”œأ­nsito rodado, y siendo que la acera era demasiado espaciosa, habâ”œآ،a alabeado lo que era una ortogonal esquina de toda la vida. El â”œâ•‘nico problema, ahora, era que un poste esquinero habâ”œآ،a sido dejado en su histâ”œâ”‚rica ubicaciâ”œâ”‚n, de forma que el giro automovilâ”œآ،stico debâ”œآ،a atenerse al del antiguo â”œأ­ngulo, para evitar el impacto. Como este giro era considerado vital para la circulaciâ”œâ”‚n rodada de la capital del Ebro, poco despuâ”œآ®s el poste fue retranqueado, afortunadamente. A la izquierda de la imagen, la angulosa esquina del moderno bloque del nâ”¬â•‘ 95 de la Av. del Tenor Fleta, en cuyos bajos resplandecâ”œآ،a la sucursal de una caja de ahorro local inaugurada hacâ”œآ،a poco. Al fondo, tras el trâ”œأ­nsito de la Av, de San Josâ”œآ®, las provincianas construcciones recayentes al arranque de la calle de San Josâ”œآ® de Calasanz, la de la izquierda inmediata al restaurante Fujiyama; la de la derecha, territorio de los ultramarinos Barriendo y sus antropolâ”œâ”‚gicas pizarras de la fachada, donde se anunciaba el gâ”œآ®nero a unos precios imbatibles. Tiempo despuâ”œآ®s, esta esquina se convirtiâ”œâ”‚ en mojâ”œâ”‚n administrativo referencial de la nueva ordenaciâ”œâ”‚n de la ciudad en distritos, ya que la zona de la izquierda de la imagen, delimitada por las avenidas de Tenor Fleta, San Josâ”œآ®, y Cesâ”œأ­reo Alierta, fue adscrita al distrito Centro. Con esta rectificaciâ”œâ”‚n de fronteras, una zona histâ”œâ”‚rica del perifâ”œآ®rico barrio de San Josâ”œآ® (antiguo callejâ”œâ”‚n de la Bailera, de Lobera, calle de Abadâ”œآ،a...) quedâ”œâ”‚ incluida en el exclusivo distrito Centro. Fuente visual: fotografâ”œآ،a de Luis Mompel, en Heraldo de Aragâ”œâ”‚n.', 1972, 1972, 1972, 'Anos 70', 'SAN JOSâ”œأ«', 41.63773900, -0.87687700, '0101000020E6100000BDAAB35A600FECBF1F317A6EA1D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34334108764.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34334108764.webp', 'https://www.flickr.com/photos/zaragozaantigua/34334108764/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22777, 'Calle de Royo Villanova 1972', 'Imagen capturada entre las contrastadas zonas de sol y sombra del breve primer tramo de la calle de don Luis Royo Villanova, desde su arranque en la av. de San Josâ”œآ®, al fondo. Este lugar era filâ”œâ”‚n de sucesos por la persistencia al aire de la confluencia de la acequias del Plano, que tras pasar por la harinera SAPASA descendâ”œآ،a hacia la travesâ”œآ،a del Puente del Virrey; y de la acequia de Entonar/Ontonar, que tras pasar por la antigua fâ”œأ­brica textil de PINASAR cruzaba la av. de San Josâ”œآ® y continuaba en direcciâ”œâ”‚n a la fâ”œأ­brica de cerveza de la Zaragozana. Estas acequias, en servicio de toda la vida para el abastecimiento de las numerosas industrias y factorâ”œآ،as de la zona, ahora eran asociadas con un provinciano pasado agrâ”œآ،cola del que Zaragoza huâ”œآ،a como si de la peste de Marsella se tratara, y que habâ”œآ،a que cerrar de forma radical con gruesa capa de cemento armado. A la derecha, modernos utilitarios aparcados donde fuera que hubiera espacio, en este caso junto a la reciente manzana edilicia de la calle de Garcâ”œآ،a Lorca. Al fondo, edificios de vivienda de la av. de San Josâ”œآ® recayentes a la calle de Juan Josâ”œآ® Gâ”œأ­rate, y el colegio privado sostenido con fondos pâ”œâ•‘blicos "Marâ”œآ،a Auxiliadora" de las salesianas. Fuente visual: fotografâ”œآ،a de Luis Mompel, en Heraldo de Aragâ”œâ”‚n.', 1972, 1972, 1972, 'Anos 70', 'SAN JOSâ”œأ«', 41.63498800, -0.87967700, '0101000020E6100000786341615026ECBF1DAD6A4947D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35067637151.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35067637151.webp', 'https://www.flickr.com/photos/zaragozaantigua/35067637151/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22792, 'Calle de Monforte 1971', 'Imagen capturada en la calle de Vicente Monforte y centrada en la tranviaria unidad 214 en servicio en la lâ”œآ،nea 11 &quot;Parque-San Josâ”œآ®&quot;. Por esta josefina y antigua calle estaba trazado un tramo del bucle que por las calles de Millâ”œأ­n Astray, Monforte y Suiza, permitâ”œآ،a a los tranvâ”œآ،as dar la vuelta hasta la terminal-principio de lâ”œآ،nea en la paralela avenida de San Josâ”œآ®. Esta unidad estuvo en servicio hasta 1976, cuando la lâ”œآ،nea 11 fue desmantelada y el tranvâ”œآ،a desguazado. Como marco edilicio, y de izquierda a derecha, vista parcial del antiguo inmueble del nâ”¬â•‘ 12 (desaparecido), los nâ”¬â•‘ 10, 8 Dpdo., 8, 6, y las antiguas parcelas de los nâ”¬â•‘ 4 Dpdo. y 4 (desaparecidas). Fuente visual: Josâ”œآ® Marâ”œآ،a Valero Suâ”œأ­rez, Centenario del tranvâ”œآ،a elâ”œآ®ctrico. Zaragoza, 1902-2002.', 1971, 1971, 1971, 'Anos 70', 'SAN JOSâ”œأ«', 41.63658400, -0.87891500, '0101000020E6100000C7D79E591220ECBF1494A2957BD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/41473748034.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/41473748034.webp', 'https://www.flickr.com/photos/zaragozaantigua/41473748034/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22820, 'Avenida de San Josâ”œآ® 1974', 'Inâ”œآ®dita imagen capturada desde la altura del nâ”¬â•‘ 137 de la avenida de San Josâ”œآ®, inmueble donde estaba radicado el restaurante Fuji-Yama, todo un referente social desde su inauguraciâ”œâ”‚n en 1960, y donde tambiâ”œآ®n estaba radicada la Comisiâ”œâ”‚n de Festejos del barrio de San Josâ”œآ®. La fotografâ”œآ،a se centra en Marâ”œآ،a Teresa Alcaine Moreu, designada Reina de las Fiestas del barrio a celebrar entre el 24 y el 1 de septiembre de ese aâ”œâ–’o. Hacia el fondo, escena urbana donde destaca el cruce de la avenida con la calle del Tenor Fleta y la moderna guarderâ”œآ،a de Santa Marâ”œآ،a del Pilar, construida sobre una parte de la antigua Torre de los Fleta que originalmente dio nombre a esa calle. Sobre el firme de la avenida, vâ”œآ،as de la lâ”œآ،nea 11 del tranvâ”œآ،a "Parque-San Josâ”œآ®".', 1974, 1974, 1974, 'Anos 70', 'SAN JOSâ”œأ«', 41.63787300, -0.87654500, '0101000020E61000003F1D8F19A80CECBF2E008DD2A5D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51633355729.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51633355729.webp', 'https://www.flickr.com/photos/zaragozaantigua/51633355729/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23164, 'Puerto fluvial 2007', 'Foto: Maite Fernâ”œأ­ndez. Obras de construcciâ”œâ”‚n del puerto fluvial de Vadorrey, en el râ”œآ،o Ebro. Este fue el lugar elegido para dar abrigo a las 20 embarcaciones que surcarâ”œآ،an el râ”œآ،o gracias al nuevo azud (al fondo). La infraestructura de navegaciâ”œâ”‚n se completâ”œâ”‚ con el muelle de la Expo (que apenas se pudo utilizar, debido a supuestos imponderables) y el del Club Nâ”œأ­utico. Todo resultâ”œâ”‚ ser un verdadero fiasco, que requiriâ”œâ”‚ rebajar la solera del puente de Piedra, realizar continuos dragados en el recorrido y finalmente cancelar el servicio en 2016, tras los â”œâ•‘ltimos viajes de 2015. Fuente: Heraldo de Aragâ”œâ”‚n.', 2007, 2007, 2007, 'Siglo XXI', 'LAS FUENTES', 41.65290200, -0.86015400, '0101000020E610000033C170AE6186EBBF1ABFF04A92D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32615253085.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32615253085.webp', 'https://www.flickr.com/photos/zaragozaantigua/32615253085/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22885, 'Calle de Joaquâ”œآ،n Sorolla 1985', 'Quâ”œآ® difâ”œآ،cil es bogar por el mar en un Simca 1000 (+200)... Ya era febrero, y las partidas presupuestadas el aâ”œâ–’o anterior para asfaltar calles del barrio de San Josâ”œآ® aâ”œâ•‘n estaban en el limbo municipal. Entre las actuaciones previstas estaba desecar el mundialmente famoso en todo el Barrio "mar de Sorolla", cerca de la antigua calle de Cantarranas. Hay bastantes fotos de este humedal no natural que perduraba hasta pasada una semana de haber llovido. Los vehâ”œآ،culos de la izquierda ya sabâ”œآ،an donde aparcaban: en lo alto, para evitar el riesgo de avenida. Peatones de la zona, a mirar y dar un rodeo. Aâ”œâ•‘n pasarâ”œأ­ un tiempecito hasta que esto fuera solucionado. A la izquierda, imagen de las viviendas luego derribadas en la manzana entre las calles Josâ”œآ® Salarrullana y Hermanos Hurus, sobre las que se levantarâ”œأ­ un par de aâ”œâ–’os despuâ”œآ®s el nâ”¬â•‘ 1 de Josâ”œآ® Salarrullana (1987), y mâ”œأ­s tarde aâ”œâ•‘n (1999), el nâ”¬â•‘ 19 de Joaquâ”œآ،n Sorolla. El poste de cemento para cables elâ”œآ®ctricos seâ”œâ–’ala el arranque del puerto de categorâ”œآ،a especial que supone subir andando por la calle Josâ”œآ® Salarrullana. Los tres bloques de viviendas del fondo fueron construidos el aâ”œâ–’o 1962 sobre terrenos de huertas aterrazadas. Son un total de 9 bloques, y su direcciâ”œâ”‚n en calle Santa Gema 45, aunque tienen entradas por Joaquâ”œآ،n Sorolla. Fuente visual: AVV San Josâ”œآ®', 1985, 1985, 1985, 'Anos 80', 'SAN JOSâ”œأ«', 41.63339100, -0.87869100, '0101000020E6100000E14389963C1EECBF564ACFF412D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20064994959.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20064994959.webp', 'https://www.flickr.com/photos/zaragozaantigua/20064994959/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22940, 'Callejâ”œâ”‚n de Nador c.1981', 'Imagen del callejâ”œâ”‚n de Nador, ascendente entre la calle de Melilla, desde donde se ha capturado la imagen, y la calle del Santuario de Nuestra Seâ”œâ–’ora de la Cabeza, en el barrio de San Josâ”œآ®. Las antiguas torrenteras y rampas naturales estâ”œأ­n en proceso de ser convertidas en escaleras mâ”œأ­s accesibles. Un ciudadano inspecciona las obras. Tras el posterior derribo de las parcelas en ruinas a sus espaldas (arriba, recayentes a la plaza del Diez de Agosto), todo este espacio quedarâ”œأ­ unificado bajo la denominaciâ”œâ”‚n de calle del 10 de Agosto, homenaje en el nomenclâ”œأ­tor al fracasado intento de golpe de Estado de Sanjurjo en 1932, que tras la recuperaciâ”œâ”‚n de la democracia ha sobrevivido a once legislaturas estatales, y nueve municipales Parece ser que a la dâ”œآ®cima va a ir la vencida. Fuente visual: AVV. de San Josâ”œآ®.', 1981, 1981, 1981, 'Anos 80', 'SAN JOSâ”œأ«', 41.63275700, -0.87712500, '0101000020E6100000C520B0726811ECBF54A86E2EFED04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33149770584.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33149770584.webp', 'https://www.flickr.com/photos/zaragozaantigua/33149770584/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23150, 'Travesâ”œآ،a Puente Virrey 2000', 'Imagen que captura, desde cierta altura, la finalizaciâ”œâ”‚n del derribo de las antiguas parcelas comprendidas entre el nâ”œâ•‘mero 30 (cuya impronta perdura en el vecino bloque, como si de un corte estratigrâ”œأ­fico se tratara), y el 52 de la travesâ”œآ،a del Puente del Virrey, derribo impulsado por una destacada empresa constructora con un peso mâ”œأ­s que apreciable en el urbanismo del barrio de San Josâ”œآ®. Tras el derribo, el proyecto incluâ”œآ،a la apertura de un nuevo vial que diera a la calle del Tejar una continuidad mâ”œأ­s espaciosa para el trâ”œأ­fico rodado. Esta calle serâ”œآ،a luego denominada Miguel â”œأ¼ngel Tricas de Pablo, como homenaje a su trabajo desde la asociaciâ”œâ”‚n de vecinos del barrio. A ambos lados de la calle se habrâ”œآ،an de levantar dos grandes bloques de viviendas, denominado el uno "Edificio Virrey I", terminado hace aâ”œâ–’os y ya habitado, y el "Edificio Virrey II", que sigue en barbecho, o limbo constructivo. Las medianeras de la imagen se corresponden con el Grupo de Viviendas Puente Virrey y calle Tejar, promovido a principios de los aâ”œâ–’os 50 para trabajadores de la fâ”œأ­brica textil de Pina. En esa zona, precisamente, se localiza el terminado "Edificio Virrey I", que ha cegado la visual de las irregulares ventanas abiertas en la medianera.', 2000, 2000, 2000, 'Siglo XXI', 'SAN JOSâ”œأ«', 41.63553400, -0.87606100, '0101000020E610000040A20914B108ECBF7FBF982D59D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32195531145.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32195531145.webp', 'https://www.flickr.com/photos/zaragozaantigua/32195531145/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23170, 'Av. de San Josâ”œآ® 2004', 'Imagen capturada desde cierta altura (posiblemente, el nâ”¬â•‘ 95 de la avenida de Tenor Fleta), del tramo mâ”œأ­s alto de la avenida de San Josâ”œآ®, entre Tenor Fleta y la Vâ”œآ،a de San Fernando (al fondo), tras la remodelaciâ”œâ”‚n acometida en la segunda mitad de ese aâ”œâ–’o. Casi en el centro de la imagen, donde la parada de autobuses urbanos, vista parcial de las ruinas de la antigua manzana de parcelas entre las calles de Bellavista, avenida de San Josâ”œآ®, y travesâ”œآ،a del Puente del Virrey. Una parte de ese solar, urbanizado y convertido en plaza pâ”œâ•‘blica, recibiâ”œâ”‚ recientemente la denominaciâ”œâ”‚n de plaza del 1â”¬â•‘ de mayo, nomenclâ”œأ­tor que fue erradicado del barrio de San Josâ”œآ® tras el 18 de julio de 1936. Casi al fondo de la avenida, a la izquierda, se recorta todavâ”œآ،a la alta silueta del silo de la harinera de Pellicer Industria Panificadora S.A. (PEIPASA), cerrada pocos aâ”œâ–’os antes. Fuente visual: "Zaragoza 1908-2008. Arquitectura y Urbanismo".', 2004, 2004, 2004, 'Siglo XXI', 'SAN JOSâ”œأ«', 41.63705700, -0.87768100, '0101000020E61000002942EA76F615ECBF0C5872158BD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33085321183.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33085321183.webp', 'https://www.flickr.com/photos/zaragozaantigua/33085321183/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24060, 'Recinto ferial 1973', 'Desde la avenida del Tenor Fleta, vista en altura del espacio donde se montaban las ferias de las Fiestas del Pilar durante los primeros aâ”œâ–’os 70. A la izquierda, muros perimetrales del colegio de los Agustinos. A la derecha, el colegio pâ”œâ•‘blico de San Josâ”œآ® de Calasanz. Al fondo, restos de la huerta de Miraflores, prolongaciâ”œâ”‚n del paseo de Marina Moreno, y traseras edilicias de las calles de la Licorera, Fueros del Trabajo y de Manuel Lorenzo Pardo.', 1973, 1973, 1973, 'Anos 70', 'SAN JOSâ”œأ«', 41.64105900, -0.87908600, '0101000020E6100000F8E28BF67821ECBF3AE7A7380ED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32215214696.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32215214696.webp', 'https://www.flickr.com/photos/zaragozaantigua/32215214696/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22256, 'Universidad 1962', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo/1962. Objetivamente, en la jerarquâ”œآ،a moral de muchos seres humanos el burro, o asno, es considerado terco, necio e insensible, y ocupa un muy bajo estrato de consideraciâ”œâ”‚n. Por ello, en escenarios festivos varios, organizan "carreras de burros" que les dan muchas risas y divertimentos, pues los burros acostumbran a negarse a avanzar hacia lo que presumen desagradable, o simplemente estâ”œâ•‘pido. Porque, los burros, como otras muchas especies animales, no suelen ser competitivos, y el concepto de "correr" para "ganar" les resulta inconcebible, es algo que sâ”œâ”‚lo estâ”œأ­ en el ideario de quienes les montan. Aâ”œâ•‘n perdura esta prâ”œأ­ctica, que la imagen recoge practicada, precisamente, en el entonces reciente campus universitario de la Plaza de San Francisco. Al fondo, la Facultad de Ciencias. A la izquierda, la de Derecho.', 1962, 1962, 1962, 'Anos 60', 'UNIVERSIDAD', 41.64120000, -0.89893600, '0101000020E6100000484E266E15C4ECBFFC1873D712D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14665208717.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14665208717.webp', 'https://www.flickr.com/photos/zaragozaantigua/14665208717/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24112, 'C.â”¬â•‘ de San Josâ”œآ® 1942', 'Imagen capturada durante el fresco mediodâ”œآ،a del lunes 16 de febrero de 1942 con motivo de la inauguraciâ”œâ”‚n oficial de la Comisarâ”œآ،a de San Josâ”œآ® sita en el homâ”œâ”‚nimo camino, en el tramo de los pares entre el camino que por los campos de Miraflores conduce al camino de Las Torres, y la calle del Padre Polanco. Centra la escena el reverendo padre Luis Doâ”œâ–’ate, regente de la parroquia de San Miguel de los Navarros que preceptivamente bendijo los nuevos locales. Junto a â”œآ®l y a la izquierda, el secretario general del jefe superior de Policâ”œآ،a, Enrique Fontana Bernabâ”œآ®u, que inaugurâ”œâ”‚ la comisarâ”œآ،a terminando con los no menos preceptivos gritos de "viva Franco" y "Arriba Espaâ”œâ–’a", y el comandante en jefe de la policâ”œآ،a armada y de trâ”œأ­fico, Josâ”œآ® Arija Valenzuela. Junto a â”œآ®l y a la derecha, el inspector jefe de la brigada de investigaciâ”œâ”‚n criminal, Ismael Bas Ballester. Posan junto a ellos, ademâ”œأ­s, funcionarios del Cuerpo de policâ”œآ،a adscritos a esta nueva comisarâ”œآ،a (con un total de cinco inspectores y nueve agentes, ademâ”œأ­s del comisario jefe Josâ”œآ® Abello Drets), cuya jurisdicciâ”œâ”‚n quedâ”œâ”‚ delimitada al este de la lâ”œآ،nea imaginaria que desde el puente del Pilar, pasando por la calle del Heroâ”œآ،smo, camino de las Torres, paseos de Cuâ”œآ®llar y de Colâ”œâ”‚n, llegaba hasta el parque de Buenavista. Sobre el posado grupal se proyecta la leve sombra de algunas desnudas ramas de los â”œأ­rboles que jalonaban el camino de San Josâ”œآ® hasta que poco despuâ”œآ®s fueron cortados para dar paso al tendido tranviario de la nueva lâ”œآ،nea 13 "San Josâ”œآ®" inaugurada en 1945.', 1942, 1942, 1942, 'Anos 40', 'SAN JOSâ”œأ«', 41.63963700, -0.87456100, '0101000020E6100000016DAB5967FCEBBFE1270EA0DFD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52039019692.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52039019692.webp', 'https://www.flickr.com/photos/zaragozaantigua/52039019692/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24205, 'Tenor Fleta 1968', 'Imagen capturada durante el proceso de urbanizaciâ”œâ”‚n de la avenida del Tenor Fleta, como una toma de contacto con el estado previo, a la altura del arranque de la calle de Lausana, a la derecha. El objetivo se centra en una chimenea construida por RENFE tras el soterramiento de las vâ”œآ،as, como vâ”œآ،a de salida de los humos generados por las locomotoras vaporosas de la lâ”œآ،nea de Barcelona. En primer plano, y adoquinada, la antigua calle de Fletas. Fuente visual: Archivo Municipal de Zaragoza.', 1968, 1968, 1968, 'Anos 60', 'SAN JOSâ”œأ«', 41.63866900, -0.87916200, '0101000020E6100000B859BC581822ECBF09FCE1E7BFD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32812602593.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32812602593.webp', 'https://www.flickr.com/photos/zaragozaantigua/32812602593/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24471, 'Chimenea de Pina 1984', 'Imagen de la identificativa, reivindicada y derribada chimenea de la antigua fâ”œأ­brica textil de Pina y Marâ”œآ،n, cuando era reclamada por el movimiento vecinal organizado como parte de un nuevo parque. Esta chimenea, recuerdo de tiempos fabriles, era reivindicada como parte de la memoria visual de ese pasado, y se le asignaba un carâ”œأ­cter central en el proyecto de parque propuesto. Hasta que una maâ”œâ–’ana, la chimenea ya no estaba: el Ayuntamiento la derribâ”œâ”‚ con alevosâ”œآ،a y nocturnidad. El proyecto del Jardâ”œآ،n de la Memoria fue tambiâ”œآ®n un adelantado a su tiempo en este sentido: unos aâ”œâ–’os despuâ”œآ®s las chimeneas ya no eran consideradas enemigas del Progreso, y la tendencia fue mâ”œأ­s conservacionista. O tempora, o mores. Al fondo de la imagen, a la izquierda, la gigantesca y singular urbanizaciâ”œâ”‚n de la calle Pintor Marâ”œآ،n Bagâ”œâ•‌â”œآ®s. Fuente visual: AVV. San Josâ”œآ®', 1984, 1984, 1984, 'Anos 80', 'SAN JOSâ”œأ«', 41.63409600, -0.87890600, '0101000020E6100000FA42C879FF1FECBF2043C70E2AD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20345608126.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20345608126.webp', 'https://www.flickr.com/photos/zaragozaantigua/20345608126/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25722, 'Escultor Lobato 1968', 'Imagen del camino del Escultor Lobato tal y como era entonces, con las antiguas parcelas, las empinadas cuestas, el camino de tierra, la acequia, y algunas farolas. Al fondo, la calle Garcâ”œآ،a Lorca, y mâ”œأ­s al fondo, la avenida de San Josâ”œآ®. Cruza descendente (o ascendente, segâ”œâ•‘n donde se vaya) la reciente y tambiâ”œآ®n terrosa calle Joaquâ”œآ،n Sorolla, junto a la antigua fâ”œأ­brica de Pina, desde la calle de Cantarranas (arriba), hasta la del Doce de Octubre (abajo). Fuente: "Zaragoza viva" (1969)', 1968, 1968, 1968, 'Anos 60', 'SAN JOSâ”œأ«', 41.63430500, -0.87797200, '0101000020E610000002B859BC5818ECBF3A58FFE730D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19923307013.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19923307013.webp', 'https://www.flickr.com/photos/zaragozaantigua/19923307013/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25725, 'Calixto Ariâ”œâ–’o 1976', 'Hacâ”œآ،a meses que la "Asociaciâ”œâ”‚n de Padres de Alumnos" (sic) del Colegio "Calixto Ariâ”œâ–’o y Mariano de Cavia", y la Asociaciâ”œâ”‚n de Cabezas de Familia de S. Josâ”œآ® llevaban denunciando la penosa situaciâ”œâ”‚n del colegio "Nacional" (sic), y planteando su sustituciâ”œâ”‚n por uno nuevo. El 16 de noviembre, el Alcalde, Sr. Merino, recibiâ”œâ”‚ a una representaciâ”œâ”‚n de ambas entidades, y allâ”œآ، saliâ”œâ”‚ la posibilidad de permutar terrenos con los de la DPZ en "La Granja" para construir allâ”œآ، unas nuevas escuelas. El Colegio "Calixto Ariâ”œâ–’o y Mariano de Cavia" habâ”œآ،a sido edificado en 1931, cuando la Segunda Repâ”œâ•‘blica impulsâ”œâ”‚ la construcciâ”œâ”‚n urgente de escuelas (habâ”œآ،a un dâ”œآ®ficit de mâ”œأ­s de 27000 escuelas, y mâ”œأ­s de un millâ”œâ”‚n de niâ”œâ–’os y niâ”œâ–’as estaban sin escolarizar). Tenâ”œآ،a capacidad para 400 niâ”œâ–’as y niâ”œâ–’os, en condiciones que hay que recordar: la luz elâ”œآ®ctrica tenâ”œآ،a que estar siempre encendida porque las aulas eran oscuras, sombrâ”œآ،as; los muros rezumaban humedad; el patio apenas contaba con 40 m2; el paso de los aâ”œâ–’os habâ”œآ،a degradado la construcciâ”œâ”‚n, realizada en materiales sencillos; los baâ”œâ–’os goteaban fuerte... Eran tiempos en que 6000 niâ”œâ–’as y niâ”œâ–’as del barrio tenâ”œآ،an que irse a otros barrios, o morir al palo de los colegios privados y confesionales, para poder escolarizarse. En la imagen, el Colegio visto desde el cruce de Tenor Fleta con el Camino del Puente del Virrey. El patio, con los dos â”œأ­rboles, quedaba en medio de los dos pabellones, uno para niâ”œâ–’as, y otro para niâ”œâ–’os. La entrada al Colegio estaba por detrâ”œأ­s de la imagen, en la Calle Dos de Mayo. Fuente visual: Archivo Heraldo de Aragâ”œâ”‚n.', 1976, 1976, 1976, 'Anos 70', 'SAN JOSâ”œأ«', 41.63638900, -0.87500000, '0101000020E6100000000000000000ECBF5F44DB3175D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20064377628.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20064377628.webp', 'https://www.flickr.com/photos/zaragozaantigua/20064377628/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25731, 'Callejâ”œâ”‚n de Nador 1977', 'Muy cerca ya del Canal Imperial las cuestas y empinamientos casi comienzan a parecer cordilleras a los llaneros de la ciudad romana. Tal vez por eso, desde antiguo, se consideraba natural que el monte de Torrero comenzara ya donde la actual Doce de Octubre. El Cabezo Cortado, un poco mâ”œأ­s arriba, era el Olimpo de la periferia, al que venâ”œآ،an artistas y fotâ”œâ”‚grafos cuando querâ”œآ،an "retratar" bien la ciudad. No obstante los desniveles, la progresiva afluencia de gente del campo a la ciudad empujâ”œâ”‚ a construir donde no parece posible hacerlo. Pero aquâ”œآ، el precio del suelo estaba por los idems, los materiales de construcciâ”œâ”‚n se abastecâ”œآ،an allâ”œآ، mismo (adobe, ladrillo, maderos, teja), y la mano de obra salâ”œآ،a de la familia y amistades. Asâ”œآ،, los antiguos caminos y calles de Alcalâ”œأ­ Zamora, Mâ”œأ­rtires de Jaca, 14 de abril, de la Huerta, y del 14 de diciembre, fueron poblâ”œأ­ndose de prodigiosas construcciones, humildes (proletarias, en lenguaje antiguo). Los riegos fluâ”œآ،an de la cercana acequia de Ontanar, y en los terraplenes entre la calle Melilla y Escultor Lobato crecâ”œآ،a maâ”œآ،z y cereal. Cuando llovâ”œآ،a, torrentes y barranqueras surgâ”œآ،an donde antes sâ”œâ”‚lo habâ”œآ،a polvo, niebla, viento, y sol. En la imagen, aspecto del confuso espacio ascendente del callejâ”œâ”‚n de Nador, a la izquierda, o lado de los nâ”œâ•‘meros pares. Tras las parcelas del centro de la imagen, arriba, estaba la plaza del Diez de Agosto, y a la derecha, una calle homâ”œâ”‚nima, de una fecha que recuerda la derogaciâ”œâ”‚n en 1792 de la monarquâ”œآ،a durante la Revoluciâ”œâ”‚n Francesa, aunque oficialmente es un homenaje al fracasado intento de Golpe de Estado de Sanjurjo en 1932. Mâ”œأ­s tarde, y tras el derribo de las parcelas referidas, todo este espacio fue adjudicado a la denominaciâ”œâ”‚n de calle del Diez de Agosto. El edificio de la derecha es el nâ”¬â•‘ 6-8 de la calle de Nuestra Seâ”œâ–’ora de la Cabeza. Los edificios de arriba a la izquierda perduran como nâ”¬â•‘ 4 y nâ”¬â•‘ 6 de la calle Diez de Agosto. El resto de parcelas, supervivientes de la construidas durante los', 1977, 1977, 1977, 'Anos 70', 'SAN JOSâ”œأ«', 41.63275700, -0.87712500, '0101000020E6100000C520B0726811ECBF54A86E2EFED04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20204876386.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20204876386.webp', 'https://www.flickr.com/photos/zaragozaantigua/20204876386/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25746, 'Ex-Calixto Ariâ”œâ–’o 1988', 'Las antiguas "Escuelas de Calixto Ariâ”œâ–’o-Mariano de Cavia", luego Colegio Nacional "Calixto Ariâ”œâ–’o" estaba domiciliado en la calle Dos de Mayo nâ”¬â•‘ 35. Por Orden de 28 de agosto de 1979, de la Direcciâ”œâ”‚n General de Educaciâ”œâ”‚n Bâ”œأ­sica, fue trasladado a "locales de nueva construcciâ”œâ”‚n en calle Josâ”œآ® Galisay, sin nâ”œâ•‘mero, (barrio San Josâ”œآ®-La Granja)" (sic). Tras el traslado quedâ”œâ”‚ abandonado, pasando por un tiempos muy complicados cuando su cesiâ”œâ”‚n temporal, y en precario, a la comunidad gitana. Finalmente, fue derribado, y en la segunda mitad de los 90 fue objeto de una promociâ”œâ”‚n de viviendas denominada "Calixto Ariâ”œâ–’o" que comenzâ”œâ”‚ las obras en 1996, con 38 viviendas, locales, aparcamientos y trasteros. Fuente visual: AVV. San Josâ”œآ®.', 1988, 1988, 1988, 'Anos 80', 'SAN JOSâ”œأ«', 41.63638900, -0.87500000, '0101000020E6100000000000000000ECBF5F44DB3175D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20388991672.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20388991672.webp', 'https://www.flickr.com/photos/zaragozaantigua/20388991672/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25758, 'Avenida de San Josâ”œآ® 1950', 'El "Diamante Negro", en la avenida de San Josâ”œآ®, es el antecedente directo del mâ”œآ،tico Bar-Restaurante Fujiyama (nâ”¬â•‘ 137 de la avenida). El singular nombre vendrâ”œآ،a dado por la traducciâ”œâ”‚n poâ”œآ®tica del habitual uso del local como depâ”œâ”‚sito de carbâ”œâ”‚n (carbonera), ademâ”œأ­s de otros productos antiguos, como la paja. Una vez despejado y limpio de carbâ”œâ”‚n y paja, fue habilitado como "Salâ”œâ”‚n (de baile) de la Comisiâ”œâ”‚n" durante las fiestas del barrio de San Josâ”œآ®. Tenâ”œآ،a como vecina una notoria vaquerâ”œآ،a, pero el ingenio y una ocurrente decoraciâ”œâ”‚n con coloristas motivos florales y guirnaldas varias, convirtiâ”œâ”‚ el espacio en otra cosa. Por aâ”œâ–’adidura, el soleado posado de unas endomingadas mozas a la puerta del local, parece un reclamo de fiesta y baile, con un ambiente muy similar al de decenas y decenas de pueblos (eso eran entonces los barrios de la periferia de la ciudad) en sus fiestas mayores. En la imagen, acceso desde la avenida de San Josâ”œآ® al festivo y resplandeciente local. Fuente visual: Banco de Imâ”œأ­genes del Barrio de S. Josâ”œآ® (A.VV. San Josâ”œآ®)', 1950, 1950, 1950, 'Anos 50', 'SAN JOSâ”œأ«', 41.63792300, -0.87629700, '0101000020E610000037A79201A00AECBFE02EFB75A7D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24153781489.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24153781489.webp', 'https://www.flickr.com/photos/zaragozaantigua/24153781489/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25767, 'Cadena de la Granja 1977', 'Imagen capturada seguramente por la singularidad del galguero que, ascendiendo por la calle Cadena de la Granja (que conducâ”œآ،a a la antigua Granja Agrâ”œآ،cola de Zaragoza), ha llegado al cruce con el camino del Puente del Virrey, donde finaliza la avenida de Tenor Fleta, y la circulaciâ”œâ”‚n rodada gira 45â”¬â•‘ hacia nuestra derecha para continuar ruta. A la izquierda, de fondo, destacable imagen de las antiguas Escuelas de Calixto Ariâ”œâ–’o y Mariano de Cavia, con entrada por la recayente calle del Dos de Mayo (antigua del 1â”¬â•‘ de mayo). Justo a la izquierda, tambiâ”œآ®n, aunque fuera de plano, finalizaba el soterramiento de la lâ”œآ،nea ferroviaria. Fuente visual: foto Gerardo Sancho Ramo, AMZ.', 1977, 1977, 1977, 'Anos 70', 'SAN JOSâ”œأ«', 41.63642200, -0.87450700, '0101000020E610000035F0A31AF6FBEBBF3B3AAE4676D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33039710135.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33039710135.webp', 'https://www.flickr.com/photos/zaragozaantigua/33039710135/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25769, 'Tenor Fleta 1968', 'Imagen del tramo final de la moderna avenida del Tenor Fleta, entre la avenida de San Josâ”œآ® (a la espalda), y el camino del Puente del Virrey (al fondo), al que afortunadamente nadie proponâ”œآ،a cambiar la denominaciâ”œâ”‚n de "camino" (â”¬â”گreminiscencia rural?) por la de "avenida" (â”¬â”گmâ”œأ­s propio de una ciudad moderna?). Parece ser que la urbanizaciâ”œâ”‚n de este vial se estaba encontrando con problemas como el de la imagen: los modernos bloques, en su avance, como el nâ”¬â•‘ 120, topan con una parcela recayente a la calle del Dos de Mayo (antigua del 1â”¬آ¬ de Mayo) que conserva el alineamiento original de los jardines y huertos traseros. Tras ella, las escuelas de Calixto Ariâ”œâ–’o y Mariano de Cavia, aunque algo mâ”œأ­s retranqueadas, tampoco habâ”œآ،an previsto la nueva alineaciâ”œâ”‚n. Al poco tiempo, la parcela irredenta fue sustituida por un moderno bloque (nâ”¬â•‘ 122) alineado ortodoxamente, y la acera resultante fue adaptada de forma plâ”œأ­stica a unos pocos centâ”œآ،metros junto a las escuelas donde hacer equilibrios impensables. Tendrâ”œآ،an que pasar unos cuantos aâ”œâ–’os para que el derribo del Calixto Ariâ”œâ–’o normalizara la situaciâ”œâ”‚n. Al fondo, naves industriales en la calle Cadena de la Granja, junto a las vâ”œآ،as del tren. La imagen presenta un aire de irrealidad: no hay circulaciâ”œâ”‚n rodada. Fuente visual: foto AMZ.', 1968, 1968, 1968, 'Anos 60', 'SAN JOSâ”œأ«', 41.63676000, -0.87560000, '0101000020E61000004D158C4AEA04ECBF53B3075A81D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33184504891.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33184504891.webp', 'https://www.flickr.com/photos/zaragozaantigua/33184504891/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25771, 'C.â”¬â•‘ del Puente del Virrey 1976', 'Antropolâ”œâ”‚gica imagen capturada en la confluencia del antiquâ”œآ،simo camino del Puente del Virrey (derecha), con la mâ”œأ­s moderna travesâ”œآ،a del Puente del Virrey (izquierda), por donde todavâ”œآ،a bajaba al aire la acequia del Plano en su trâ”œأ­nsito hacia el camino de Miraflores, y un desmadejado, pero estratâ”œآ®gico, â”œأ­rbol (posiblemente, una acacia) generaba un microespacio de convivencia intergeneracional, y de sombra en verano, ciertamente impagable. Cosas de barrio de la periferia (San Josâ”œآ®). Fuente visual: foto Calvo Pedrâ”œâ”‚s, en diario "El Noticiero". Archivo Josâ”œآ® Marâ”œآ،a Ballestâ”œآ،n Miguel.', 1976, 1976, 1976, 'Anos 70', 'SAN JOSâ”œأ«', 41.63508200, -0.87529000, '0101000020E6100000C381902C6002ECBF9E23F25D4AD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33304604076.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33304604076.webp', 'https://www.flickr.com/photos/zaragozaantigua/33304604076/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25772, 'Tenor Fleta 1968', 'Imagen capturada durante el proceso de urbanizaciâ”œâ”‚n de la avenida del Tenor Fleta, en este caso en un corto tramo entre el cruce con la avenida de San Josâ”œآ® (derecha), y el bloque del nâ”¬â•‘ 94, en el centro. A su derecha, restos de las parcelas nâ”¬â•‘ 90, y 92, donde poco despuâ”œآ®s, tras ser retranqueadas, serâ”œآ،a construido un nuevo bloque con ese numeral. A su derecha, cartelones comerciales apoyados en el antiguo nâ”¬â•‘ 145 de la avenida de San Josâ”œآ®. Al otro lado de la avenida, la guarderâ”œآ،a أ”أ‡آ£Santa Marâ”œآ،a del Pilarأ”أ‡أک, y los novâ”œآ،simos y grandes bloques construidos por una entidad de ahorro local. El trâ”œأ­fico rodado, el usual de la â”œآ®poca, en nâ”œâ•‘mero, y calidades. Fuente visual: Archivo Municipal de Zaragoza.', 1968, 1968, 1968, 'Anos 60', 'SAN JOSâ”œأ«', 41.63733800, -0.87683400, '0101000020E6100000EBAA402D060FECBFC03FA54A94D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33473240482.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33473240482.webp', 'https://www.flickr.com/photos/zaragozaantigua/33473240482/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25774, 'Calle del Dos de Mayo 1967', 'Imagen de la calle del Dos de Mayo, centrada en el primer tramo del lado de los pares, con una interesante panorâ”œأ­mica de la transiciâ”œâ”‚n del original estado parcelario, a nuevos bloques levantados sobre sus solares. Asâ”œآ،, en el centro de la imagen, se muestra en construcciâ”œâ”‚n el nuevo edificio del nâ”¬â•‘ 14-16, resultado de la fusiâ”œâ”‚n solariega de las antiguas parcelas 14 y 16. A su derecha, las parcelas 12, 10 y 8, que mâ”œأ­s tarde serâ”œأ­n refundidas en un nuevo bloque unitario. A su izquierda, las antiguas parcelas 18, 20 y 22, luego sustituidas por otro bloque moderno, y vista parcial de la parcela 24, incorporada luego a otro mâ”œأ­s moderno y vertical bloque. Al fondo, el arranque de la calle desde la avenida de San Josâ”œآ®, con las parcelas 6, 4 y 2, ya modernizadas. Si bien en la imagen el bloque en construcciâ”œâ”‚n parece destacar bastante del entorno, no deja de ser una modesto edificio de apenas cuatro alturas, mâ”œأ­s bajos, aunque aprovechando de forma mâ”œأ­s â”œâ”‚ptima la edificabilidad de los antiguos y abiertos patios y corrales de las traseras. La denominaciâ”œâ”‚n de esta calle (Dos de Mayo) fue impuesta tras el 18 de julio de 1936 sobre la anterior del 1â”¬â•‘ de Mayo, como una mâ”œأ­s de las numerosas referencias urbanas relacionadas con la memoria histâ”œâ”‚rica de las guerras peninsulares de 1808-14. Fuente visual: colecciâ”œâ”‚n de Enrique Baile, en Gran Archivo Zaragoza Antigua (GAZA).', 1967, 1967, 1967, 'Anos 60', 'SAN JOSâ”œأ«', 41.63692100, -0.87651200, '0101000020E610000050A6D1E4620CECBF5C9198A086D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33867495386.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33867495386.webp', 'https://www.flickr.com/photos/zaragozaantigua/33867495386/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25778, 'Av. de San Josâ”œآ® 1945', 'Imagen capturada el 30 de agosto de 1945 con motivo de la inauguraciâ”œâ”‚n de la tranviaria lâ”œآ،nea 13 "San Josâ”œآ®", trazada con vâ”œآ،a doble por la avenida de San Josâ”œآ® (una de subida, otra de bajada). Para habilitar el espacio necesario para instalar el tendido se hubieron de talar los â”œأ­rboles que jalonaban el antiguo camino, y la penuria de materiales que caracterizâ”œâ”‚ la Autarquâ”œآ،a franquista hizo que los materiales en buena parte tuvieran que ser reutilizados de la desmantelada lâ”œآ،nea de Circunvalaciâ”œâ”‚n, y de algunos tramos de otras lâ”œآ،neas. La terminal de salida estaba ubicada en la calle de la Verâ”œâ”‚nica (en las traseras del Teatro Principal), pasando luego por el Coso, la calle de Espartero, la plaza de San Miguel, la calle de Miguel Servet, el cuartel de Intendencia, y la avenida de San Josâ”œآ®, por la que ascendâ”œآ،a hasta justo donde comenzaba lo mâ”œأ­s duro de la cuesta de Morâ”œâ”‚n, en las inmediaciones de la harinera homâ”œâ”‚nima, desde donde regresaba al centro de la ciudad. En la imagen, el coche nâ”¬â•‘ 92 asciende por la avenida posiblemente en el despejado tramo entre la calle de Fletas, donde la trinchera del ferrocarril de los directos a Barcelona, y el arranque del camino de las Alcachoferas. A la derecha, fuera de plano, parcelas junto a los ingresos a la calle del Dos de Mayo y a la de Ventura Rodrâ”œآ،guez. Fuente visual: Foto Lozano en El Noticiero, del archivo de Josâ”œآ® Marâ”œآ،a Ballestâ”œآ،n Miguel.', 1945, 1945, 1945, 'Anos 40', 'SAN JOSâ”œأ«', 41.63705700, -0.87768100, '0101000020E61000002942EA76F615ECBF0C5872158BD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40007125933.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40007125933.webp', 'https://www.flickr.com/photos/zaragozaantigua/40007125933/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25780, 'Calle del Dos de Mayo 1966', 'Matinal y soleada imagen de la calle del Dos de Mayo (antigua avenida del 1.â”¬â•‘ de Mayo) con una vista parcial centrada en las antiguas parcelas de los nâ”œâ•‘meros 14 y 16 poco antes de su derribo para ser sustituidas por un moderno bloque de viviendas. A la izquierda la parcela del 18, y a la derecha la parcela del 12. Ambas tambiâ”œآ®n serâ”œأ­n luego derribadas e integradas en sendos nuevos bloques edilicios. Al fondo, luminosas traseras del nuevo bloque de los nâ”œâ•‘meros 5-7-9 de la calle de Ventura Rodrâ”œآ،guez, antigua de la Igualdad. De la treintena de parcelas que fueron levantadas en este largo vial, con viviendas unifamiliares de una y dos alturas, apenas sobrevive a fecha de hoy una, la nâ”¬â•‘ 30. Fuente visual: colecciâ”œâ”‚n de Enrique Baile, en Gran Archivo Zaragoza Antigua (GAZA).', 1966, 1966, 1966, 'Anos 60', 'SAN JOSâ”œأ«', 41.63692100, -0.87651200, '0101000020E610000050A6D1E4620CECBF5C9198A086D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40723561224.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40723561224.webp', 'https://www.flickr.com/photos/zaragozaantigua/40723561224/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25782, 'Av. de San Josâ”œآ® c.1967', 'Tranviaria imagen centrada en el coche nâ”¬â•‘ 305 (serie de los "300") en servicio en la nueva lâ”œآ،nea "Parque-San Josâ”œآ®", resultado de la unificaciâ”œâ”‚n de las lâ”œآ،neas 11 y 13, estacionado en la terminal sita en la avenida de San Josâ”œآ®, tramo entre las calles de Bellavista (parcela a la izquierda) y la del Doce de Octubre (a la derecha, fuera de plano). Se encuentra orientado para comenzar el viaje de vuelta hacia la terminal del Teatro Principal. De fondo, edificio junto a la fâ”œأ­brica de La Catedral del Mueble que un incendio se llevâ”œâ”‚ luego por delante. Desde entonces aquâ”œآ، se encuentran los verticales y modernos inmuebles del 167-169 de la avenida. Fuente visual: Archivo de Josâ”œآ® Marâ”œآ،a Ballestâ”œآ،n Miguel.', 1967, 1967, 1967, 'Anos 60', 'SAN JOSâ”œأ«', 41.63607700, -0.87874500, '0101000020E6100000ADC090D5AD1EECBF705E9CF86AD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/41164628952.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/41164628952.webp', 'https://www.flickr.com/photos/zaragozaantigua/41164628952/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25788, 'Calle de la Igualdad 1927', 'Imagen del tramo final de la terrosa calle de la Igualdad del barrio de San Josâ”œآ® capturada desde su desemboque en el camino del Puente del Virrey. Parcelas de una y dos alturas (las menos) jalonan esta calle, donde a la derecha destaca el pequeâ”œâ–’o riego que bajaba al aire por todo el vial desde su arranque al fondo, en el camino de San Josâ”œآ®, donde destacan algunos de sus veteranos olmos que se superponen a los â”œأ­rboles de la torre de Fletas. Tras las parcelas de la izquierda bajaba tambiâ”œآ®n muy caudalosa la acequia del Plano por la travesâ”œآ،a del Puente del Virrey. A pesar de que esta calle presentaba su nombre de "Igualdad" desde el comienzo de la dictadura del general Primo de Rivera, tras el 18 de julio de 1936 fue renombrada con el "menos problemâ”œأ­tico" de Ventura Rodrâ”œآ،guez, lo que para ser una barriada de la periferia, fue todo un honor... Lo mismo le sucediâ”œâ”‚ a su paralela e inmediata calle del 1â”¬آ¬ de Mayo (a la derecha y fuera de plano), que desde entonces es la calle del Dos de Mayo.', 1927, 1927, 1927, 'Anos 20', 'SAN JOSâ”œأ«', 41.63572400, -0.87516100, '0101000020E61000004D8237A45101ECBF23A46E675FD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52197487621.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52197487621.webp', 'https://www.flickr.com/photos/zaragozaantigua/52197487621/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25793, 'Plaza de las Terrazas 1925', 'Fotograma de un reportaje dedicado a la "garden party" organizada en honor de los asistentes al I Congreso de "Oto-Rino-Laringologâ”œآ،a" celebrado en Zaragoza en abril de ese aâ”œâ–’o y en cuyo marco fue constituida la "Asociaciâ”œâ”‚n Hispano-Lusa-Americana" de esta especialidad mâ”œآ®dico-quirâ”œâ•‘rgica. El espacio elegido para esta celebraciâ”œâ”‚n fueron los "pintorescos" y singulares jardines de la torre de Dâ”œأ­maso Pina Pâ”œآ®rez sita al final de la playa de Torrero, y ademâ”œأ­s de los congresistas asistieron "las mâ”œأ­s distinguidas familias de la buena sociedad zaragozana". Hubo orquesta, jotas y un "exquisito lunch" cuyos caldos elevaron el tono del evento.', 1925, 1925, 1925, 'Anos 20', 'SAN JOSâ”œأ«', 41.63285300, -0.87960300, '0101000020E6100000E5D4CE30B525ECBF7616BD5301D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54686824754.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54686824754.webp', 'https://www.flickr.com/photos/zaragozaantigua/54686824754/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20948, 'Convento de San Josâ”œآ® 1808', '"Vista del convento de San Josâ”œآ® incendiado por los franceses". Serie Ruinas de Zaragoza, de Juan Gâ”œأ­lvez (dibujo) y Fernando Brambila (grabado), Câ”œأ­diz, 1812. Una de las mejores vistas del convento de San Josâ”œآ®, con el puente de acceso sobre el râ”œآ،o Huerva en primer plano, desde la actual calle Aznar Molina, en su tramo entre Asalto y Hâ”œأ­bitat Don 2000. Fuente: artillerosdearagon.blogspot.com', 1808, 1808, 1808, 'Siglo XIX', 'SAN JOSâ”œأ«', 41.64814200, -0.87251300, '0101000020E610000013B70A62A0EBEBBFFF942A51F6D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15085319677.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15085319677.webp', 'https://www.flickr.com/photos/zaragozaantigua/15085319677/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20964, 'Puente de San Josâ”œآ® c.1818', '"El alguacil Lampiâ”œâ–’os cosido dentro de un caballo muerto", dibujo de Francisco de Goya. "En Zaragoza, a mediados del siglo pasado (XVIII), metieron a un alguacil llamado Lampiâ”œâ–’os en el cuerpo de un rocâ”œآ،n muerto y lo cosieron; toda la noche se mantuvo vivo", escribe Goya a pie de dibujo. Ya en 1725 el medianero Antonio Gavâ”œآ،n incluyâ”œâ”‚ esta tremenda historia en "El anti-papismo de un aragonâ”œآ®s anglicano en la Inglaterra del siglo XVIII". En esa obra, el alguacil se llamaba Guadalajara, y era guardia de la Universidad, en la plaza de la Magdalena, contratado para arrestar a los malos estudiantes. Era tan celoso en su desempeâ”œâ–’o, que se convirtiâ”œâ”‚ en azote de estudiantes, putas, y sospechosos en general, hasta que unos resentidos estudiantes decidieron darle un escarmiento a la zaragozana: lo secuestraron y sacaron de la ciudad por la Puerta Quemada y, junto al Puente de San Josâ”œآ® sobre el Huerva, lo metieron atado de pies y manos dentro de un caballo muerto, previamente destripado. Cosieron el cuerpo del caballo con la cabeza del pobre guardia fuera, por el orificio anal, y asâ”œآ، lo dejaron toda la noche, expuesto a las alimaâ”œâ–’as atraidas por el olor visceral. Sobreviviâ”œâ”‚ vociferando a los perros que se acercaban a merendarse los restos. El pasmo que produjo el espectâ”œأ­culo con las primeras luces del dâ”œآ،a siguiente (una humana testa en el culo de un caballo), derivâ”œâ”‚ el asunto en cosa del demonio, y el caso fue llevado al Tribunal de la Santa Inquisiciâ”œâ”‚n, que procediâ”œâ”‚ a torturar al hombre-caballo para hallar la verdad, o que pereciera en el intento. Y la verdad se descubriâ”œâ”‚ cuando el potro de tortura desgarrâ”œâ”‚ los cosidos del caballo, y el alguacil se escurriâ”œâ”‚ lastimosamente al suelo. Tres semanas despuâ”œآ®s, el alguacil morâ”œآ،a de calenturas, perdonando a los traviesos estudiantes madaleneros, que le correspondieron componiâ”œآ®ndole una apropiada y sentida elegâ”œآ،a funeraria. En el dibujo, Goya se centra en la turbadora imagen del hombre-caballo defendiâ”œآ®ndose a gritos de unos asombrados perr', 1818, 1818, 1818, 'Siglo XIX', 'SAN JOSâ”œأ«', 41.64814200, -0.87251300, '0101000020E610000013B70A62A0EBEBBFFF942A51F6D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16948854662.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16948854662.webp', 'https://www.flickr.com/photos/zaragozaantigua/16948854662/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20976, 'Convento de San Josâ”œآ® 1808', 'Apunte de Juan Gâ”œأ­lvez para un grabado de la colecciâ”œâ”‚n de "Ruinas de Zaragoza" (1812) que no se llegâ”œâ”‚ a realizar, y que sirviâ”œâ”‚ de base para la sâ”œآ، realizada "Vista del convento de San Josâ”œآ® incendiado por los franceses", de la misma serie, grabada por la mano de Fernando Brambila. El apunte incluye una precisa imagen del antiguo y barroco convento de San Josâ”œآ® de los Carmelitas Descalzos (destaca su imponente iglesia), el puente de San Josâ”œآ® sobre el râ”œآ،o Huerva, demolido parcialmente por los defensores de la ciudad, que tambiâ”œآ®n talaron los â”œأ­rboles de las riberas del râ”œآ،o y el entorno para una mejor visual. Fuente visual: Imagen aportada por Josâ”œآ® Luis Cintora a la obra de Rafael Contento Mâ”œأ­rquez, "Las Ruinas de Zaragoza de Gâ”œأ­lvez y Brambila. Una epopeya calcogrâ”œأ­fica", Zaragoza, IFC, 2010.', 1808, 1808, 1808, 'Siglo XIX', 'SAN JOSâ”œأ«', 41.64755000, -0.87221100, '0101000020E61000003FC4060B27E9EBBF2D431CEBE2D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20291995778.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20291995778.webp', 'https://www.flickr.com/photos/zaragozaantigua/20291995778/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20977, 'Convento de San Josâ”œآ® 1806', 'Convento de carmelitas descalzos de San Josâ”œآ®. Dibujo de Louis-Franâ”œآ؛ois Lejeune y grabado de Perdoux, 1806. Ademâ”œأ­s del convento, en el grabado aparecen el puente de San Josâ”œآ® sobre el râ”œآ،o Huerva, y un fragmento de la puerta Quemada a la izquierda. Fuente: Ensemble de 255 dessins originaux â”œأ­ la mine de plomb, â”œأ، la plume avec lavis ayant servi â”œأ، illustrer le Voyage pittoresque et historique de lأ”أ‡أ–Espagne, par Alexandre de Laborde (1773-1842).', 1806, 1806, 1806, 'Siglo XIX', 'SAN JOSâ”œأ«', 41.64814200, -0.87251300, '0101000020E610000013B70A62A0EBEBBFFF942A51F6D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20357644581.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20357644581.webp', 'https://www.flickr.com/photos/zaragozaantigua/20357644581/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21101, 'Matadero c.1885', 'El nuevo macelo de la ciudad, diseâ”œâ–’ado por Ricardo Magdalena y realizado entre 1878-1875, es una obra funcional, apropiada y estâ”œآ®ticamente agradable, que cayâ”œâ”‚ como un paracaidista en la ubicaciâ”œâ”‚n prevista, en la calle de Miguel Servet en su confluencia con el arranque del camino de las Fuentes, entre huertos, solares, riegos, vides, torres, y campos de hortalizas. No podâ”œآ،a ser de otra forma, por razones higiâ”œآ®nico-sanitarias, dadas las caracterâ”œآ،sticas de los materiales que deberâ”œآ،a procesar. La imagen ha sido capturada casi desde el Camino de San Josâ”œآ®, donde aâ”œâ–’os despuâ”œآ®s, cuando la urbanizaciâ”œâ”‚n de la zona avance, se habilitarâ”œأ­ un "Callejâ”œâ”‚n del Pilar" para conectarlo con Miguel Servet. Mâ”œأ­s tarde serâ”œأ­ redenominado "Calle del Matadero". El frontal del matadero, con sus tres grandes naves confluyendo en el patio central donde la fuente del "Buen Pastor", y su monumental puerta de acceso, siguen siendo hoy en dâ”œآ،a, casi un siglo despuâ”œآ®s, un espectâ”œأ­culo pâ”œâ•‘blico y câ”œآ،vico de primer orden.', 1885, 1885, 1885, 'Siglo XIX', 'SAN JOSâ”œأ«', 41.64456800, -0.87038700, '0101000020E610000038A27BD635DAEBBF2906483481D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16099500504.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16099500504.webp', 'https://www.flickr.com/photos/zaragozaantigua/16099500504/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21251, 'Penal de San Josâ”œآ® 1907', 'Postal. "Colecciâ”œâ”‚n Patria y Fe nâ”œâ•‘m. 24, Zaragoza 1908 - Centenario de los Sitios", 1907. "Antiguo convento de Carmelitas Descalzos, y luego presidio de Zaragoza, situado mâ”œأ­s allâ”œأ­ de la puerta Quemada, al otro lado del Huerva, en un terreno elevado inmediato al râ”œآ،o. Fue constantemente atacado por ocho baterâ”œآ،as francesas. Los aragoneses lo incendiaron antes de abandonarlo y sobre sus ruinas instalâ”œأ­ronse baterâ”œآ،as que hicieron mucho daâ”œâ–’o a las tropas de Napoleâ”œâ”‚n." Con motivo del Centenario 1 de "Los Sitios", la Imprenta Casaâ”œâ–’al realiza en 1907 la colecciâ”œâ”‚n de postales "Patria y Fe", y en ella incluye imâ”œأ­genes de algunos de los escenarios considerados referenciales de ese evento. Asâ”œآ،, con el nâ”¬â•‘ 24 de la serie, una imagen recoge el estado del "Antiguo Penal de San Josâ”œآ®", antiguo Convento de S. Josâ”œآ® de los Carmelitas Descalzos, arruinado durante el conflicto de 1808-09, y reconstruido luego. Fue Penal Correccional hasta 1900, y estuvo abandonado unos aâ”œâ–’os, hasta que fue adjudicado al Ejâ”œآ®rcito de Tierra para uso como Cuartel de Intendencia. La imagen se ha capturado desde el puente de San Josâ”œآ®, y en ella se ve uno de los torreoncillos construidos como garitas de vigilancia de presos, en sus tiempos de Penal. A la vista de otras imâ”œأ­genes del entorno, la foto estâ”œأ­ reproducida horizontalmente al revâ”œآ®s. Fuente visual y del texto de la postal: www.pasapues.es/', 1907, 1907, 1907, 'Anos 1900', 'SAN JOSâ”œأ«', 41.64755000, -0.87221100, '0101000020E61000003FC4060B27E9EBBF2D431CEBE2D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20322375321.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20322375321.webp', 'https://www.flickr.com/photos/zaragozaantigua/20322375321/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21788, 'Camino de San Josâ”œآ® c.1938', 'Imagen de uno de los autobuses en servicio en la lâ”œآ،nea "Barrio de San Josâ”œآ®" a finales de los aâ”œâ–’os 30, integrante de la compaâ”œâ–’â”œآ،a "Autobuses Ensanches Zaragoza" del empresario del sector Jesâ”œâ•‘s Sâ”œأ­nchez Falces.', 1938, 1938, 1938, 'Anos 30', 'SAN JOSâ”œأ«', 41.64399100, -0.87294100, '0101000020E610000018CDCAF621EFEBBF8CF50D4C6ED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23866038221.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23866038221.webp', 'https://www.flickr.com/photos/zaragozaantigua/23866038221/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21801, 'Miguel Servet 1933', 'Imagen capturada en un arbolado tramo de la calle de Miguel Servet en el antiguo barrio de Montemolâ”œآ،n, posiblemente entre el Matadero, la calle de las Escuelas y la de Utrillas, muy cerca del arranque del camino de Cabaldâ”œâ”‚s y el Frontâ”œâ”‚n Zaragozano (a la derecha, fuera de plano). Al fondo, traquetea una unidad tranviaria de la lâ”œآ،nea 1 Bajo Aragâ”œâ”‚n. Fuente visual: www.mecd.gob.es/.', 1933, 1933, 1933, 'Anos 30', 'SAN JOSâ”œأ«', 41.64387200, -0.86961300, '0101000020E610000076A565A4DED3EBBFB267CF656AD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26311030859.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26311030859.webp', 'https://www.flickr.com/photos/zaragozaantigua/26311030859/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21866, 'C.â”¬â•‘ de San Josâ”œآ® 1933', 'Imagen de la fachada de los enormes talleres de muebles del establecimiento La Catedral del Mueble de Urbano Bernardos, sitos en el camino de San Josâ”œآ® nâ”¬â•‘ 32, esquineros con la calle de Miraflores (a la derecha, fuera de plano). Con una experiencia de treinta aâ”œâ–’os en el oficio, aquâ”œآ، se construâ”œآ،an selectos muebles en estilo y materiales nobles, ademâ”œأ­s de muebles econâ”œâ”‚micos y accesibles para casi todos los bolsillos (eso al menos sugerâ”œآ،a la publicidad). En el arranque de la câ”œآ®ntrica calle de Santiago contaba con un extenso y concurrido local expositor y de venta. En la imagen, la fachada de los talleres recayente al camino de San Josâ”œآ®, con los â”œأ­rboles que lo jalonaban hasta que fueron cortados al principio de la dâ”œآ®cada de los aâ”œâ–’os cuarenta, cuando el tendido de la nueva lâ”œآ،nea tranviaria "San Josâ”œآ®". Este notable edificio perdurâ”œâ”‚ hasta su derribo y sustituciâ”œâ”‚n por modernos bloques de viviendas, no ha mucho. Fuente visual: www.mecd.gob.es/.', 1933, 1933, 1933, 'Anos 30', 'SAN JOSâ”œأ«', 41.64402300, -0.87283300, '0101000020E610000080D3BB783FEEEBBF976F7D586FD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36420672135.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36420672135.webp', 'https://www.flickr.com/photos/zaragozaantigua/36420672135/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21918, 'Calle de Miguel Servet 1934', 'Posado de un teniente de la Comandancia de Intendencia de Zaragoza montado en moto con sidecar ante la fachada que da ingreso al Matadero municipal desde la calle de Miguel Servet. Competan la escena, tras â”œآ®l, tropas armadas, grupo de civiles y niâ”œâ–’os.', 1934, 1934, 1934, 'Anos 30', 'SAN JOSâ”œأ«', 41.64458400, -0.87037600, '0101000020E61000003E25E7C41EDAEBBF2FC37FBA81D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54169474966.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54169474966.webp', 'https://www.flickr.com/photos/zaragozaantigua/54169474966/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22344, 'Galletas Polen 1968', 'Imagen de la Fabrica de Galletas Polen, sita en la esquina de las calles del Fuero del Trabajo (nâ”¬â•‘ 4, a la izquierda), y la Avenida de San Josâ”œآ® (nâ”¬â•‘ 38, a la derecha), donde estaba el despacho o tienda, los aromas de este establecimiento perfumaron esta parte del Barrio de San Josâ”œآ® durante unas cuantas dâ”œآ®cadas, hasta que se trasladaron al polâ”œآ،gono de Cogullada. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1968, 1968, 1968, 'Anos 60', 'SAN JOSâ”œأ«', 41.64336500, -0.87300500, '0101000020E6100000C8D2872EA8EFEBBF0E32C9C859D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20230845931.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20230845931.webp', 'https://www.flickr.com/photos/zaragozaantigua/20230845931/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22345, 'Avenida de San Josâ”œآ® 1969', 'Imagen de la avenida de San Josâ”œآ®. A la izquierda, tras la pausa publicitaria, el pabellâ”œâ”‚n de Hermanas Enfermas del antiguo Asilo de Pobres. A continuaciâ”œâ”‚n, tras la calle Miraflores, la que fuera fâ”œأ­brica de muebles Abenia. Fuente visual: AMZ, Gerardo Sancho Ramo.', 1969, 1969, 1969, 'Anos 60', 'SAN JOSâ”œأ«', 41.64439100, -0.87290800, '0101000020E61000002A560DC2DCEEEBBF1A6B7F677BD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20233029718.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20233029718.webp', 'https://www.flickr.com/photos/zaragozaantigua/20233029718/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22544, 'Matadero Municipal 1971', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo. 05/02/1971. El arquitecto municipal Ricardo Magdalena proyectâ”œâ”‚ un nuevo matadero municipal, que fue terminado en 1884 en la antigua huerta de Montemolâ”œآ،n. Inaugurado como recinto de la Exposiciâ”œâ”‚n Aragonesa de productos industriales de 1885-1886, entrâ”œâ”‚ en funcionamiento como matadero efectivo al aâ”œâ–’o siguiente. Los sacrificios de animales cesaron en 1980, y el matadero cerrâ”œâ”‚ definitivamente en 1981. En la imagen, el patio del Matadero, lleno de viejos, pero activos, camiones de reparto, junto a uno nuevo.', 1971, 1971, 1971, 'Anos 70', 'SAN JOSâ”œأ«', 41.64477600, -0.87006000, '0101000020E61000002BD9B11188D7EBBF739F1C0588D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14945573365.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14945573365.webp', 'https://www.flickr.com/photos/zaragozaantigua/14945573365/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22618, 'Cuartel de San Josâ”œآ® 1973', 'Foto Monge, 1973. Esta especie de globo instalado en el mismo lugar donde hasta poco antes hubo "otra singular edificaciâ”œâ”‚n destinada a la exhibiciâ”œâ”‚n del Cinerama", albergâ”œâ”‚ la sala de actos de los Cristianos Adventistas del Sâ”œآ®ptimo Dâ”œآ،a. Obra del arquitecto vallisoletado Josâ”œآ® Miguel de Prada Poole, se hinchaba en 20 minutos y tenâ”œآ،a un aforo de 400 personas. Mientras, al fondo, se termina de construir el edificio denominado "Hâ”œأ­bitat Don 2000", que sigue presidiendo las vistas de la ciudad desde varios kilâ”œâ”‚metros a la redonda. A la izquierda, pequeâ”œâ–’o fragmento del edificio de Elâ”œآ®ctricas Reunidas de Zaragoza. Posteriormente, por estos terrenos del antiguo Cuartel de San Josâ”œآ® se prolongâ”œâ”‚ el camino de las Torres hasta el puente de Las Fuentes. Fuente: Diario Amanecer, 24 de enero de 1973.', 1973, 1973, 1973, 'Anos 70', 'SAN JOSâ”œأ«', 41.64770600, -0.87135900, '0101000020E6100000906802452CE2EBBF24B6BB07E8D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19367279556.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19367279556.webp', 'https://www.flickr.com/photos/zaragozaantigua/19367279556/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22628, 'Miguel Servet 1974', 'Tranvâ”œآ،a nâ”¬â•‘ 226 de la lâ”œآ،nea 11 (Parque-San Josâ”œآ®) terminando de dar la curva que desde la Avenida de San Josâ”œآ® lo situaba en Miguel Servet, en direcciâ”œâ”‚n Parque. A su derecha, otra unidad de esta lâ”œآ،nea se dirige hacia San Josâ”œآ®. Entre adoquines, en el suelo, el cruce de vâ”œآ،as de las lâ”œآ،neas 11 y la 1 "Bajo Aragâ”œâ”‚n". La gran publicidad de "Residencial Paraâ”œآ،so", anuncia la importante mudanza que se estaba produciendo en la apetitosa y gran pastilla situada entre los paseos de Las Damas y de Mola. El edificio que soporta la publicidad tambiâ”œآ®n serâ”œأ­ luego mudado por otro mâ”œأ­s nuevo.', 1974, 1974, 1974, 'Anos 70', 'SAN JOSâ”œأ«', 41.64613900, -0.87195200, '0101000020E61000003DD175E107E7EBBFC7D5C8AEB4D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20152158770.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20152158770.webp', 'https://www.flickr.com/photos/zaragozaantigua/20152158770/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22632, 'Frontâ”œâ”‚n Zaragozano 1975', 'Restos del "Frontâ”œâ”‚n Zaragozano", construido a finales del s. XIX cerca del Camino del Bajo Aragâ”œâ”‚n y el nuevo Macelo. En 1967 fue derribado (casi a la vez que el "Frontâ”œâ”‚n Aragonâ”œآ®s"), para urbanizar la zona y comenzar a construir nuevos bloques de viviendas del barrio de San Josâ”œآ®. En la imagen, reliquia de la puerta de acceso al "Frontâ”œâ”‚n Zaragozano de Pelota", en ladrillo y formas neomudâ”œآ®jares. Acorralada entre nuevas y enormes colmenas habitacionales (los bloques de la imagen, recayentes a Monasterio de Poblet), esta pequeâ”œâ–’a puerta de acceso no tuvo espacio para ser preservada, y su memoria, que era parte de la reciente memoria de la ciudad, fue borrada.', 1975, 1975, 1975, 'Anos 70', 'SAN JOSâ”œأ«', 41.64391800, -0.87039800, '0101000020E6100000321F10E84CDAEBBF22A7AFE76BD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20228987961.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20228987961.webp', 'https://www.flickr.com/photos/zaragozaantigua/20228987961/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22651, 'La Salle Montemolâ”œآ،n 1970', 'Posado en el patio del colegio La Salle Montemolâ”œآ،n, levantado en el antiguo camino de las Torres con proyecto de 1915 de Francisco Albiâ”œâ–’ana, junto a la Fundiciâ”œâ”‚n de Iranzo de la calle Miguel Servet (derecha). Este enorme espacio, dos aâ”œâ–’os mâ”œأ­s tarde, serâ”œأ­ vendido, el colegio derribado, y el solar reutilizado para la construcciâ”œâ”‚n de un enorme megabloque de viviendas. Los Hermanos de las Escuelas Cristianas abrirâ”œأ­n entonces un nuevo centro en la calle Josâ”œآ® Galiay.', 1970, 1970, 1970, 'Anos 70', 'SAN JOSâ”œأ«', 41.64714000, -0.87386400, '0101000020E610000016DBA4A2B1F6EBBF7BF7C77BD5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21187990435.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21187990435.webp', 'https://www.flickr.com/photos/zaragozaantigua/21187990435/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22768, 'Miguel Servet 1971', 'Puerta de ingreso del matadero municipal en la calle de Miguel Servet 55, en el momento en que sale uno de los veteranos camiones de reparto. Este macelo, obra del arquitecto Ricardo Magdalena, entrâ”œâ”‚ en funcionamiento en 1887 y fue cerrado como tal en 1981, para albergar despuâ”œآ®s otros servicios pâ”œâ•‘blicos del Ayuntamiento. Sobre el firme, el tendido, y aâ”œآ®reo, el cableado que por la derecha conducâ”œآ،a a las cocheras de los tranvâ”œآ،as.', 1971, 1971, 1971, 'Anos 70', 'SAN JOSâ”œأ«', 41.64453300, -0.87025000, '0101000020E61000000C022B8716D9EBBFAD18AE0E80D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33438717146.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33438717146.webp', 'https://www.flickr.com/photos/zaragozaantigua/33438717146/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22782, 'Av. de San Josâ”œآ® 1979', 'Imagen capturada en la avenida de San Josâ”œآ® y centrada en el decimonâ”œâ”‚nico y desaparecido (por derribo) pabellâ”œâ”‚n sanatorio de las Hermanitas Enfermas integrante del gran complejo asistencial de la Congregaciâ”œâ”‚n de las Hermanitas de los Ancianos Desamparados. A la izquierda, fuera de plano, el principio de la calle de Miraflores. Fuente visual: AMZ.', 1979, 1979, 1979, 'Anos 70', 'SAN JOSâ”œأ«', 41.64439100, -0.87290800, '0101000020E61000002A560DC2DCEEEBBF1A6B7F677BD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/37884084724.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/37884084724.webp', 'https://www.flickr.com/photos/zaragozaantigua/37884084724/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22838, 'Calle Monasterio de Samos aâ”œâ–’os 80', 'Aâ”œâ–’os 80 del siglo XX. La calle Monasterio de Samos, en su tramo entre Compromiso de Caspe y Miguel Servet, fue abierta en los aâ”œâ–’os 70, restâ”œأ­ndole terreno al perâ”œآ،metro del antiguo Matadero Municipal, hoy Centro Câ”œآ،vico Salvador Allende. En la foto, con los edificios de Miguel Servet al fondo, vemos unas construcciones naranjas abajo a la derecha, que luego serâ”œآ،an derruidas para edificar una comisarâ”œآ،a agresora del conjunto, que hoy es un centro administrativo municipal. Foto: Santos Santos.', 1980, 1980, 1989, 'Anos 80', 'SAN JOSâ”œأ«', 41.64529100, -0.87055600, '0101000020E61000003BC5AA4198DBEBBF9AB33EE598D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14868808299.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14868808299.webp', 'https://www.flickr.com/photos/zaragozaantigua/14868808299/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22928, 'Miguel Servet 1981', 'Foto: Javier Peâ”œâ–’a. Calle de Miguel Servet, vista desde la esquina con la avenida del Compromiso de Caspe (derecha, fuera de encuadre). Al fondo, confluencia con el camino de las Torres. Fuente: www.facebook.com/photo.php?fbid=1519294098086430&set=...', 1981, 1981, 1981, 'Anos 80', 'SAN JOSâ”œأ«', 41.64653700, -0.87262100, '0101000020E6100000ABB019E082ECEBBFB55373B9C1D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30683583891.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30683583891.webp', 'https://www.flickr.com/photos/zaragozaantigua/30683583891/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22962, 'C.â”¬â•‘ de las Torres 1985', 'Canicular imagen capturada en el camino de las Torres a la altura del inmueble del nâ”¬â•‘ 9, y centrada en el aparentemente anodino gran solar tapiado y esquinero con la calle de Amado Nervo, que en el centro de la escena muestra su desemboque en el camino. Esta calle de Amado Nervo fue asâ”œآ، denominada en 1965 como homenaje al poeta modernista mejicano Amado Ruiz Nervo Ordaz, y entonces comenzaba en la paralela calle de la Reina Fabiola y terminaba en fondo de saco ante el perâ”œآ،metro de la fâ”œأ­brica de harinas de San Josâ”œآ® aquâ”œآ، establecida desde dâ”œآ®cadas antes, lo que determinâ”œâ”‚ el urbanismo de la zona hasta su derribo a principios de los aâ”œâ–’os 80 del pasado siglo XX. El solar de la imagen perduraba como recuerdo de su ubicaciâ”œâ”‚n, una vez retranqueada buena parte de su superficie que se extendâ”œآ،a por casi toda la anchura del actual camino de las Torres, casi hasta la desembocadura de la calle de la Concepciâ”œâ”‚n. Aâ”œâ–’os mâ”œأ­s tarde en el solar de la imagen se construirâ”œآ،a el actual bloque de viviendas del nâ”¬â•‘ 11 del camino, denominado "Edificio Alejandrâ”œآ،a", que casualmente parece hacer referencia al verso alejandrino utilizado de forma caracterâ”œآ،stica por poetas modernistas hispanoamericanos como Rubâ”œآ®n Darâ”œآ،o y Amado Nervo.', 1985, 1985, 1985, 'Anos 80', 'SAN JOSâ”œأ«', 41.64631600, -0.87393800, '0101000020E6100000A96917D34CF7EBBFD670917BBAD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53257348800.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53257348800.webp', 'https://www.flickr.com/photos/zaragozaantigua/53257348800/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23137, 'Miguel Servet 2000', 'Imagen centrada en la chaflanera esquina, o despartidero, que indica, hacia la derecha, el arranque de la avenida de San Josâ”œآ®, mientras que hacia la izquierda prosigue la calle de Miguel Servet. Un inmenso telâ”œâ”‚n de fondo, patrocinado por una marca de alcohol escocâ”œآ®s (propiedad de una conocida compaâ”œâ–’â”œآ،a ronera), hace de pantalla publicitaria para los humanos que por allâ”œآ، transiten, mientras del otro lado se remodela el edificio del nâ”¬â•‘ 56 de Miguel Servet. Justo a su izquierda, una de las â”œâ•‘ltimas imagenes de la antigua casa del nâ”¬â•‘ 58 de esa calle, que poco tiempo despuâ”œآ®s serâ”œآ،a derribada y homologada con un entorno mâ”œأ­s moderno, y vertical. A la derecha, entre colosos, el antiguo nâ”¬â•‘ 9 de la avenida de San Josâ”œآ® ya ha sido derribado, y estâ”œأ­ encaminado hacia la hipernormalizaciâ”œâ”‚n.', 2000, 2000, 2000, 'Siglo XXI', 'SAN JOSâ”œأ«', 41.64594900, -0.87207000, '0101000020E6100000B9533A58FFE7EBBF24F1F274AED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31818947400.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31818947400.webp', 'https://www.flickr.com/photos/zaragozaantigua/31818947400/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23222, 'Calle de Miguel Servet 2014', 'Manifestaciâ”œâ”‚n antifascista el 20 de noviembre de 2014, a su paso por la calle de Miguel Servet, con el cruce con la avenida del Compromiso de Caspe al fondo. La pancarta, de la Federaciâ”œâ”‚n de Asociaciones de Barrios de Zaragoza.', 2014, 2014, 2014, 'Siglo XXI', 'SAN JOSâ”œأ«', 41.64639300, -0.87242600, '0101000020E610000059C345EEE9EAEBBF82AE7D01BDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51140224272.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51140224272.webp', 'https://www.flickr.com/photos/zaragozaantigua/51140224272/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23249, 'C.â”¬â•‘ de Las Fuentes aâ”œâ–’os 20', 'Imagen del camino de Las Fuentes y acequia Mayor, desde Miguel Servet. A la izquierda, taller de caldererâ”œآ،a de Josâ”œآ® Claver. Las inmediatas vâ”œآ،as del tranvâ”œآ،a en el suelo apuntan hacia Miguel Servet, a la derecha. Tras la chimenea del transformador elâ”œآ®ctrico, la acequia de San Josâ”œآ® (que viene por Miguel Servet del Camino de las Torres) y la doble hilera de â”œأ­rboles, marcan el arranque del camino de las Fuentes. A la izquierda, las parcelas con los nâ”œâ•‘meros 64, 64 duplicado, y 64 triplicado. A la derecha, las traseras del nâ”œâ•‘mero 27 de Miguel Servet. Esto en la actualidad es el comienzo de Compromiso de Caspe, quedando a la derecha el bloque de viviendas nâ”¬â•‘ 1, y a la izquierda, el bloque de viviendas nâ”¬â•‘ 3. Fuente visual: foto Jesâ”œâ•‘s Cormâ”œأ­n, en "Zaragoza 1908-2008. Arquitectura y Urbanismo".', 1920, 1920, 1929, 'Anos 20', 'SAN JOSâ”œأ«', 41.64613900, -0.87195200, '0101000020E61000003DD175E107E7EBBFC7D5C8AEB4D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14921981846.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14921981846.webp', 'https://www.flickr.com/photos/zaragozaantigua/14921981846/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23254, 'Huerva 1920', 'Una captura titulada oficialmente "Panorâ”œأ­mica de un complejo industrial junto a un canal y una zona arbolada. En primer plano, un hombre se aproxima al objetivo del fotâ”œâ”‚grafo". Vista del râ”œآ،o Huerva aguas abajo del puente de san Josâ”œآ®, en una imagen capturada desde el pronunciado talud de la calle del Asalto con el telâ”œâ”‚n de fondo del cuartel de la tercera comandancia de Intendencia. En el centro de la escena, canal que deriva agua del râ”œآ،o hacia la central transformadora de ERZ, y entre los â”œأ­rboles que delimitan el Corral de abastos de Intendencia se destaca la chimenea de la fâ”œأ­brica de regaliz situada inmediatamente detrâ”œأ­s. A la derecha y sobre los â”œأ­rboles, edificios de la harinera del Pilar. Fuente visual: Gabriel Faci Abad, en AHPZ.', 1920, 1920, 1920, 'Anos 20', 'SAN JOSâ”œأ«', 41.64755000, -0.87221100, '0101000020E61000003FC4060B27E9EBBF2D431CEBE2D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20355412881.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20355412881.webp', 'https://www.flickr.com/photos/zaragozaantigua/20355412881/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23491, 'Torre de Guillâ”œآ®n c.1915', 'Imagen capturada desde la frondosa zona de huerta de la Torre del abogado Felipe Josâ”œآ® Guillâ”œآ®n y Larraz, que posa con naturalidad junto a su familia en el centro de la escena, junto al singular edificio de tres alturas con el ingreso acolumnado de su fachada principal recayente al camino de San Josâ”œآ®. Esta torre confrontaba, a la izquierda, con el pabellâ”œâ”‚n sanatorio de las Hermanitas Enfermas, integrante del gran complejo asistencial de la Congregaciâ”œâ”‚n de las Hermanitas de los Ancianos Desamparados. A mediados de siglo, esta extensa torre fue derribada y reurbanizada integralmente. Sobre su solar se levantaron varios nuevos bloques de viviendas, y por su huerta fue prolongado el antiguo callejâ”œâ”‚n del Pilar (hasta entonces con entrada y salida por Miguel Servet, frente al Matadero), para conectarlo con la avenida de San Josâ”œآ®. Este callejâ”œâ”‚n fue redenominado entonces como calle del Matadero.', 1915, 1915, 1915, 'Anos 10', 'SAN JOSâ”œأ«', 41.64431900, -0.87238300, '0101000020E610000087C3D2C08FEAEBBF8198840B79D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50625226516.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50625226516.webp', 'https://www.flickr.com/photos/zaragozaantigua/50625226516/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24041, 'Miguel Servet 1940', 'Imagen capturada en el patio del colegio de La Salle Montemolâ”œآ،n, en su ubicaciâ”œâ”‚n entre el camino de las Torres y la calle de Miguel Servet, durante la inauguraciâ”œâ”‚n oficial de una lâ”œأ­pida memorialista en recuerdo de los alumnos muertos, "Caâ”œآ،dos por Dios y por Espaâ”œâ–’a en la Gloriosa Cruzada 1936-39". De izquierda a derecha, Antonio Gil, capellâ”œأ­n del colegio; Joaquâ”œآ،n de Pitarque, secretario provincial de FET-JONS; hermano Octavio Peâ”œâ–’a, director del colegio; Pâ”œآ،o Altolaguirre, jefe provincial de FET-JONS; Josâ”œآ® Mâ”¬آ¬ Arnau, presidente de la Diputaciâ”œâ”‚n Provincial de Teruel; Josâ”œآ® Navarro Latorre, delegado provincial del SEU; y Santiago Eguâ”œآ،a Aragâ”œâ”‚n, presidente nacional de los antiguos alumnos de La Salle. Fuente: www.todocoleccion.net/', 1940, 1940, 1940, 'Anos 40', 'SAN JOSâ”œأ«', 41.64714000, -0.87386400, '0101000020E610000016DBA4A2B1F6EBBF7BF7C77BD5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30785947452.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30785947452.webp', 'https://www.flickr.com/photos/zaragozaantigua/30785947452/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24129, 'Exposiciâ”œâ”‚n aragonesa 1885', 'J. Thomas, 1885. En 1885 se inaugura el conjunto de edificios de lo que serâ”œأ­ el nuevo Matadero Municipal, con el objeto provisional de albergar la Segunda Exposiciâ”œâ”‚n Regional Aragonesa. Fue encargado al arquitecto municipal Ricardo Magdalena. Estâ”œأ­ situado en la carretera de Zaragoza a Castellâ”œâ”‚n, que corresponde al camino arbolado del primer plano del dibujo.', 1885, 1885, 1885, 'Siglo XIX', 'SAN JOSâ”œأ«', 41.64495400, -0.86960100, '0101000020E61000006534F279C5D3EBBF52B648DA8DD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14672382077.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14672382077.webp', 'https://www.flickr.com/photos/zaragozaantigua/14672382077/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24130, 'Miguel Servet 1885', 'Exposiciâ”œâ”‚n Aragonesa de 1885. Alzado y planta de la distribuciâ”œâ”‚n de los pabellones de la Exposiciâ”œâ”‚n, en lo que una vez terminada, serâ”œآ،an las instalaciones del nuevo macelo municipal. Al sur, la "Carretera al Mediterrâ”œأ­neo", o "Camino del Bajo Aragâ”œâ”‚n", mâ”œأ­s tarde "Miguel Servet". Al Noroeste, el "Camino de las Fuentes", con su correspondiente acequia al aire, en lo que mucho mâ”œأ­s tarde serâ”œآ،a "Compromiso de Caspe". Al Norte (actual "Florentino Ballesteros") y al Este (actual ""Enrique Casas Vila"), "Salida a los Parques". Fuente visual: "Zaragoza: visiones de una ciudad", Ayto. Zaragoza, 2004.', 1885, 1885, 1885, 'Siglo XIX', 'SAN JOSâ”œأ«', 41.64492700, -0.86952600, '0101000020E6100000BCB1A03028D3EBBF59A7CAF78CD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16375046162.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16375046162.webp', 'https://www.flickr.com/photos/zaragozaantigua/16375046162/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24131, 'Expo 1885', 'Marcelino de Unceta, "Inauguraciâ”œâ”‚n de la Exposiciâ”œâ”‚n Regional Aragonesa: llegada del Emmo. Sr. Cardenal Benavides al local del concurso", 1885. En su calidad de arzobispo de la ciudad, el seâ”œâ–’or Francisco de Paula de Benavides y Fernâ”œأ­ndez de Navarrete, llega al nuevo matadero sito en la carretera de Zaragoza a Castellâ”œâ”‚n, que hasta que entre en uso sirve de local del "concurso", o Expo de 1885. En la imagen, el carruaje del arzobispo junto a la reconocible y monumental puerta de entrada, representada sin las decorativas cabecicas de animales, las filigranas varias, y el escudo municipal. La inauguraciâ”œâ”‚n de esta exposiciâ”œâ”‚n se tuvo que retrasar al mes de octubre como consecuencia del brote de câ”œâ”‚lera de ese aâ”œâ–’o. Fuente visual: bdh.bne.es/ La Ilustraciâ”œâ”‚n Espaâ”œâ–’ola y Americana', 1885, 1885, 1885, 'Siglo XIX', 'SAN JOSâ”œأ«', 41.64456800, -0.87038700, '0101000020E610000038A27BD635DAEBBF2906483481D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16471129949.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16471129949.webp', 'https://www.flickr.com/photos/zaragozaantigua/16471129949/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24145, 'Exposiciâ”œâ”‚n Aragonesa 1885', '"Zaragoza. Inauguraciâ”œâ”‚n oficial del concurso: el presidente de la Sociedad Econâ”œâ”‚mica de Amigos del Paâ”œآ،s pronunciando el discurso de apertura. Composiciâ”œâ”‚n y dibujo del natural por Marcelino de Unceta". Grabado que ilustra el comienzo de la Exposiciâ”œâ”‚n Aragonesa de 1885, celebrada en las dependencias del Matadero municipal de Zaragoza, antes de que este comenzase la actividad para la que fue edificado. Fuente: La ilustracâ”œâ”‚n espaâ”œâ–’ola y americana, Madrid, 8 de noviembre de 1885.', 1885, 1885, 1885, 'Siglo XIX', 'SAN JOSâ”œأ«', 41.64492700, -0.86952600, '0101000020E6100000BCB1A03028D3EBBF59A7CAF78CD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21304859011.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21304859011.webp', 'https://www.flickr.com/photos/zaragozaantigua/21304859011/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24409, 'Colegio La Salle Montemolâ”œآ،n c.1968', 'Vista parcial del conjunto del colegio La Salle Montemolâ”œآ،n, desde su patio recayente al camino de las Torres. Fue levantado en 1916 segâ”œâ•‘n proyecto de Francisco Albiâ”œâ–’ana, junto a la ubicaciâ”œâ”‚n que ya ocupaban los hermanos de La Salle desde 1909. En 1929 se ampliâ”œâ”‚ y en 1972 se trasladâ”œâ”‚ a la calle Josâ”œآ® Galiay, siendo derribado en 1973. Al fondo a la derecha, fragmento del nâ”œâ•‘mero 15 de la calle de Miguel Servet. Fuente visual: Jaime â”œأ¼lvarez Pâ”œآ®rez de Labeaga, Josâ”œآ® Antonio Noain Roncal, "Cien aâ”œâ–’os, gracias a ti. Colegio La Salle Montemolâ”œآ،n, Zaragoza. 1909-2009".', 1968, 1968, 1968, 'Anos 60', 'SAN JOSâ”œأ«', 41.64706600, -0.87366100, '0101000020E61000000E4DD9E907F5EBBF412D060FD3D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32023866564.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32023866564.webp', 'https://www.flickr.com/photos/zaragozaantigua/32023866564/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24420, 'Calle de Miguel Servet 1969', 'Imagen de la antigua "Carnicerâ”œآ،a Casa Policeto", en la luminosa calle del Miguel Servet nâ”¬â•‘ 28, esquina con el camino de las Torres nâ”¬â•‘ 171 (a la derecha), alquilada por Policeto Lobera a los hermanos de las Escuelas Cristianas y remodelada para abrir un Colegio que denominaron de Nuestra Seâ”œâ–’ora del Pilar en 1909, al que ellos coloquialmente se referâ”œآ،an como "la casa vulgar y fea", o "la caja de cerillas" del suburbio de Montemolâ”œآ،n. Allâ”œآ، se impartâ”œآ،a educaciâ”œâ”‚n cristiana para niâ”œâ–’os pobres, y clases nocturnas diarias y catequesis los domingos para adultos. Detrâ”œأ­s de esta fachada habâ”œآ،a un patio interior utilizado como zona de recreo, y la acequia de San Josâ”œآ® bajaba al aire inmediata a la parte recayente al camino de las Torres (a la derecha) En 1916 construirâ”œأ­n un colegio de nueva planta, mucho mâ”œأ­s grande y espacioso, al otro lado del camino de las Torres, que en 1929, y tras una destacable ampliaciâ”œâ”‚n, fue redenominado La Salle Montemolâ”œآ،n, siendo derribado en 1973 tras el traslado a una nueva ubicaciâ”œâ”‚n mâ”œأ­s amplia en la calle de Josâ”œآ® Galiay, junto a la antigua Granja Agrâ”œآ،cola de Zaragoza. Esta casa fue derribada al poco de capturar la imagen, y sobre parte de ella se ampliâ”œâ”‚ en anchura el camino de las Torres para trâ”œأ­nsito rodado. A la izquierda, el bloque del actual nâ”¬â•‘ 44 de la calle de Miguel Servet. Al fondo, el bloque del actual nâ”¬â•‘ 7 del camino de las Torres. Fuente visual: Jaime â”œأ¼lvarez Pâ”œآ®rez de Labeaga, Josâ”œآ® Antonio Noain Roncal, "Cien aâ”œâ–’os, gracias a ti. Colegio La Salle Montemolâ”œآ،n, Zaragoza. 1909-2009".', 1969, 1969, 1969, 'Anos 60', 'SAN JOSâ”œأ«', 41.64682300, -0.87302500, '0101000020E61000008FE4F21FD2EFEBBF7AA69718CBD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34901838711.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34901838711.webp', 'https://www.flickr.com/photos/zaragozaantigua/34901838711/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24451, 'Matadero Municipal 1887', 'Postal. Archivo y Hemeroteca Municipales de Zaragoza, 1887. Interior del pabellâ”œâ”‚n central de matacâ”œآ،a de carneros y vacas del Matadero Municipal de la calle Miguel Servet de Zaragoza, hoy Centro Câ”œآ،vico Salvador Allende. Proyecto de "Macelo Municipal" de Ricardo Magdalena, aprobado en 1877 y construido entre 1878 y 1885, aâ”œâ–’o en que albergâ”œâ”‚ la Exposiciâ”œâ”‚n Aragonesa. Comenzâ”œâ”‚ su actividad como matadero en 1887. Fuente: "Ricardo Magdalena. Arquitecto municipal de Zaragoza". IFC, 2012.', 1887, 1887, 1887, 'Siglo XIX', 'SAN JOSâ”œأ«', 41.64492700, -0.86952600, '0101000020E6100000BCB1A03028D3EBBF59A7CAF78CD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15355507357.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15355507357.webp', 'https://www.flickr.com/photos/zaragozaantigua/15355507357/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24460, 'Avenida de San Josâ”œآ® 1978', 'Imagen del tramo inaugural de la avenida de San Josâ”œآ®. A la izquierda, el frontal hasta la calle Miraflores, con el edificio donde estuvo ubicada la Antigua fâ”œأ­brica de GIESA (Guiral Industrias Elâ”œآ®ctricas S.A.), antes de su traslado en 1946 a la calle Miguel Servet. Posteriormente, estas serâ”œآ،an las instalaciones de la fâ”œأ­brica de muebles "Abenia". Al fondo, las HH. de los Ancianos Desamparados ya habâ”œآ،an perpetrado la reforma de la fachada y el acceso desde la avenida, aunque aâ”œâ•‘n no habâ”œآ،an derribado el pabellâ”œâ”‚n de las Hermanas Enfermas. Fuente visual: "La evoluciâ”œâ”‚n urbana de Zaragoza al este del Huerva", Carmen Santos Vich, 1978.', 1978, 1978, 1978, 'Anos 70', 'SAN JOSâ”œأ«', 41.64402300, -0.87283300, '0101000020E610000080D3BB783FEEEBBF976F7D586FD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19773221214.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19773221214.webp', 'https://www.flickr.com/photos/zaragozaantigua/19773221214/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24485, 'Matadero c.1904', 'Fototipia para postal editada por "El Ciclâ”œâ”‚n", pasaje comercial, nâ”¬â•‘ 40 (Garcâ”œآ،a, Paraâ”œآ،so y Ariz-Navarreta) como parte de una serie denominada "Zaragoza". Este nuevo Matadero municipal, sito en la antigua carretera de Alcaâ”œâ–’iz, fue obra de Ricardo Magdalena, y terminado en 1884. Se estrenâ”œâ”‚ como recinto de la Exposiciâ”œâ”‚n Aragonesa de 1885. En la imagen, puerta de acceso al patio que articulaba los pabellones principales, con vista de la original fuente del Buen Pastor, obra de Dionisio Lausâ”œآ®n en 1885. Fuente visual: www.delcampe.net/', 1904, 1904, 1904, 'Anos 1900', 'SAN JOSâ”œأ«', 41.64456800, -0.87038700, '0101000020E610000038A27BD635DAEBBF2906483481D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23934521862.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23934521862.webp', 'https://www.flickr.com/photos/zaragozaantigua/23934521862/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24493, 'Calle de Miguel Servet c.1982', 'Imagen capturada desde cierta altura (posiblemente el nâ”¬â•‘ 84 de la calle de Miguel Servet) y centrada en el ingreso principal y patio central que vertebraba los pabellones del antiguo macelo municipal. En el centro del porticado espacio destaca la circular impronta donde estuviera la pâ”œآ®trea fuente del Buen Pastor, realizada por Dionisio Lasuâ”œآ®n, removida de su original ubicaciâ”œâ”‚n tras el cierre del matadero y trasladada al lustroso paseo de Marina Moreno, redenominado de la Constituciâ”œâ”‚n tras la recuperaciâ”œâ”‚n de la democracia municipal en 1979. Al fondo, edificios de la avenida del Compromiso de Caspe y de la calle de Jorge Cocci. Fuente visual: AMZ.', 1982, 1982, 1982, 'Anos 80', 'SAN JOSâ”œأ«', 41.64453300, -0.87025000, '0101000020E61000000C022B8716D9EBBFAD18AE0E80D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27113279497.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27113279497.webp', 'https://www.flickr.com/photos/zaragozaantigua/27113279497/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24500, 'Matadero 1901', 'Imagen del matadero municipal, en la carretera del Bajo Aragâ”œâ”‚n, que fuera sede de la Exposiciâ”œâ”‚n Aragonesa de 1885. El pabellâ”œâ”‚n central de la imagen, que confronta con la entrada principal, fue entonces el espacio del muestrario industrial. En el momento de realizar la captura, notable trâ”œأ­fico en el patio interior del macelo originado por vehâ”œآ،culos de reparto y distribuciâ”œâ”‚n, tras cargar las piezas procesadas. Fuente visual: Josep Maria Reitg Martâ”œآ،, Ajuntament de Girona.', 1901, 1901, 1901, 'Anos 1900', 'SAN JOSâ”œأ«', 41.64477600, -0.87006000, '0101000020E61000002BD9B11188D7EBBF739F1C0588D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31010343073.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31010343073.webp', 'https://www.flickr.com/photos/zaragozaantigua/31010343073/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24524, 'Ctra. de Castellâ”œâ”‚n c.1902', 'Imagen capturada desde el principio del camino de Cabaldâ”œâ”‚s y centrada en el Matadero municipal ubicado en la carretera de Zaragoza a Castellâ”œâ”‚n entre el huerto de Valls y la torre de Castâ”œأ­n (izquierda), el camino de las Fuentes y el riego de la Reja (al fondo), y la torre de Aladrâ”œآ®n y el campo de Higuera (derecha). Sobre el firme, vâ”œآ،as de la lâ”œآ،nea tranviaria del Bajo Aragâ”œâ”‚n. Fuente visual: www.ebay.es/', 1902, 1902, 1902, 'Anos 1900', 'SAN JOSâ”œأ«', 41.64453300, -0.87025000, '0101000020E61000000C022B8716D9EBBFAD18AE0E80D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39907125931.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39907125931.webp', 'https://www.flickr.com/photos/zaragozaantigua/39907125931/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24529, 'Ctra. de Castellâ”œâ”‚n c.1895', 'Inâ”œآ®dita imagen capturada en la calle de tierra y sin nombre que conectaba la carretera de Zaragoza a Castellâ”œâ”‚n, luego calle de Miguel Servet, con las traseras de la Torre de Ascaso, luego de Guillâ”œآ®n, el Molino del Seminario y una hijuela al aire de la acequia de Las Adulas, o de San Josâ”œآ®. A la derecha, inmueble esquinero con el arranque del camino de Cabaldâ”œâ”‚s, hacia la derecha y fuera de plano, tambiâ”œآ®n denominado camino del Frontâ”œâ”‚n por conducir al reciâ”œآ®n inaugurado Frontâ”œâ”‚n Zaragozano. Apoyada sobre su esquina, a la solana, un moderno vehâ”œآ،culo para la prâ”œأ­ctica del deporte velocipâ”œآ®dico. Al fondo, la monumental puerta de ingreso al moderno macelo municipal, donde posa una interesante galerâ”œآ،a de tancredos. Tras la verja, el patio central de los pabellones, con la estatua del Buen Pastor en su centro.', 1895, 1895, 1895, 'Siglo XIX', 'SAN JOSâ”œأ«', 41.64442400, -0.87052700, '0101000020E6100000A81E69705BDBEBBFF660527C7CD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48018802802.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48018802802.webp', 'https://www.flickr.com/photos/zaragozaantigua/48018802802/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24530, 'Avenida de San Josâ”œآ® 1937', 'Luminosa imagen capturada en la avenida de San Josâ”œآ® y centrada en el inmueble del nâ”¬â•‘ 32, esquinero con la calle de Miraflores, a la derecha, donde Joaquâ”œآ،n Guiral estableciâ”œâ”‚ la tercera de las ubicaciones en la ciudad de sus talleres de construcciones electromagnâ”œآ®ticas. Este destacable edificio, anteriormente albergâ”œâ”‚ los talleres de muebles de La Catedral del Mueble de Urbano Bernardos, y con el recrecimiento posterior de una altura perdurarâ”œآ،a con diversos usos hasta los aâ”œâ–’os 80, cuando fue derribado para dar paso a modernos bloques de viviendas. Pocos aâ”œâ–’os mâ”œأ­s tarde, y tras la constituciâ”œâ”‚n de la empresa Guiral Industrial Elâ”œآ®ctricas S.A. (Giesa), una cuarta localizaciâ”œâ”‚n darâ”œآ،a cabida a un nuevo, moderno, y mucho mâ”œأ­s grande complejo fabril en la calle de Miguel Servet. La arbolada avenida de la imagen fue podada luego con motivo del establecimiento del tendido de la tranviaria lâ”œآ،nea nâ”¬â•‘ 13. San Josâ”œآ®, inaugurada en agosto de 1945.', 1937, 1937, 1937, 'Anos 30', 'SAN JOSâ”œأ«', 41.64401500, -0.87284400, '0101000020E61000007A50508A56EEEBBF159161156FD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48382539126.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48382539126.webp', 'https://www.flickr.com/photos/zaragozaantigua/48382539126/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24539, 'Miguel Servet c.1919', 'Imagen comercializada como postal de la serie "Zaragoza", y titulada "Portada del Matadero", municipal instalaciâ”œâ”‚n diseâ”œâ–’ada por Ricardo Magdalena Tabuenca y terminada en 1884 que se estrenâ”œâ”‚ como recinto de la Exposiciâ”œâ”‚n Aragonesa de 1885. Esta monumental entrada daba acceso al patio central que articulaba los pabellones principales, donde fluâ”œآ،a la original fuente del Buen Pastor, obra de Dionisio Lausâ”œآ®n en 1885, visible al fondo. Hacia la derecha y fuera de plano, comenzaba el antiguo camino de Cabaldâ”œâ”‚s, llamado en su primer tramo camino del Frontâ”œâ”‚n por conducir al Frontâ”œâ”‚n Zaragozano allâ”œآ، ubicado.', 1919, 1919, 1919, 'Anos 10', 'SAN JOSâ”œأ«', 41.64456000, -0.87045100, '0101000020E6100000E7A7380EBCDAEBBFA6272CF180D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51327607793.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51327607793.webp', 'https://www.flickr.com/photos/zaragozaantigua/51327607793/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21323, 'Cartuja de Aula Dei c.1900', 'Dibujo de la Cartuja de Nuestra Seâ”œâ–’ora de Aula Dei con una perspectiva aâ”œآ®rea del gran conjunto, levantado entre el camino de Peâ”œâ–’aflor de Gâ”œأ­llego, hacia la izquierda, y el homâ”œâ”‚nimo râ”œآ،o, que serpentea a la derecha. En 1564 se puso la primera piedra del conjunto, con el favor polâ”œآ،tico y patrocinio del arzobispo Hernando de Aragâ”œâ”‚n, con un primer nâ”œâ•‘cleo de nueve frailes cartujos. En 1835 el inmueble fue desamortizado, y dos aâ”œâ–’os despuâ”œآ®s fue adquirido por Juan Francisco Clarac, que destinâ”œâ”‚ el recinto a fâ”œأ­brica de sedas. Durante el resto del siglo XIX cambiâ”œâ”‚ de propietario varias veces. En 1903 la Orden cartujana fue regresada a estas dependencias. El amurallado recinto aparece vertebrado en torno a tres patios. El mayor, a la izquierda, ordenaba las 36 celdas o viviendas de los moradores. A la derecha e inmediato, un camino arbolado lleva a gran entrada que conduce primero a la hospederâ”œآ،a y la procura, para dar paso luego a la iglesia y torre barroca.', 1900, 1900, 1900, 'Anos 1900', NULL, 41.73228300, -0.81255900, '0101000020E61000003E4162BB7B00EABF59350873BBDD4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48149996957.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48149996957.webp', 'https://www.flickr.com/photos/zaragozaantigua/48149996957/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24693, 'Matadero Miguel Servet 1956', 'Hay sol, pero el mercurio dice "menos 5 grados". Y sin cierzo. Tres maestros matarifes del Macelo Municipal (Mariano Martâ”œآ،nez, Mariano Dâ”œآ،ez, y Manuel Lâ”œâ”‚pez), capturados en inestable equilibrio sobre el agua helada, de habitual lâ”œآ،quida, a los pies de la estatua "El buen pastor", obra de Dionisio Lasuâ”œآ®n que desde 1885 centraba la plaza principal del nuevo Matadero de Zaragoza, sito en Miguel Servet, obra de Ricardo Magdalena. Estos matarifes formaban parte importante del proceso por el que los semovientes que ingresaban (o eran hechos ingresar) por una puerta, salieran por otra encarrilados hacia una pronta ingesta. Cuando este Matadero fue clausurado, a mediados de los aâ”œâ–’os 70 del pasado siglo, la estatua fue movilizada hasta el actual paseo de la Constituciâ”œâ”‚n, donde una infausta noche de junio de 2002 unos homâ”œآ،nidos se encaramaron por ella y la derribaron, si bien se precipitâ”œâ”‚ sin pretenderlo sobre uno de los que estaban abajo de miranda, con tal fortuna que al infortunado se le tuvo que amputar un brazo. La estatua quedâ”œâ”‚ hecha pedazos. De resultas de ello, se encargâ”œâ”‚ una fiel reproducciâ”œâ”‚n del original, realizada por Frank Norton, y que en 2006 fue colocada en el original emplazamiento de la original estatua. El original estâ”œأ­ en la nave-biblioteca del Centro Câ”œآ،vico Salvador Allende, que asâ”œآ، es como se denomina ahora este espacio.', 1956, 1956, 1956, 'Anos 50', 'SAN JOSâ”œأ«', 41.64472800, -0.86995300, '0101000020E6100000AAD381ACA7D6EBBF6268757286D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14850779554.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14850779554.webp', 'https://www.flickr.com/photos/zaragozaantigua/14850779554/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24694, 'Calle Miguel Servet 1925', 'La imagen se ha podido capturar desde el â”œâ•‘ltimo piso del nâ”¬â•‘ 41 de Miguel Servet (actual nâ”¬â•‘ 61), un edificio de 4 plantas de finales del s.XIX que ha sobrevivido y ha llegado a nuestros dâ”œآ،as como vestigio del antiguo Camino del Bajo Aragâ”œâ”‚n. En la esquina inferior derecha, el edificio de las escuelas de Montemolâ”œآ،n, o Grupo Escolar Tomâ”œأ­s Alvira (aâ”œâ•‘n en pie). Tras la calle de las Escuelas (actual Numancia), el complejo del Macelo municipal. Al otro lado de Miguel Servet, un poco mâ”œأ­s adelante de donde estâ”œأ­ el tranvâ”œآ،a, hacia la izquierda, el comienzo del Camino de Cabaldâ”œâ”‚s, que al poco llegaba al Frontâ”œâ”‚n Zaragozano. Tambiâ”œآ®n es visible la esquina del callejâ”œâ”‚n del Pilar (luego calle Matadero) que desemboca en Miguel Servet.', 1925, 1925, 1925, 'Anos 20', 'SAN JOSâ”œأ«', 41.64396500, -0.86983000, '0101000020E6100000BD8C62B9A5D5EBBF6362F3716DD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15277413984.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15277413984.webp', 'https://www.flickr.com/photos/zaragozaantigua/15277413984/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24696, 'Compromiso de Caspe 1981', 'Foto Montse Grao, septiembre de 1981. Fiestas del barrio de Las Fuentes. Desfile de majorettes por la avenida del Compromiso de Caspe, con Miguel Servet al fondo. A la izquierda, casa y solar que pronto serâ”œأ­n reemplazados por el gran edificio del nâ”œâ•‘mero 6. A la derecha, la calle Joaquâ”œآ،n Sanz Gadea. Fuente: www.facebook.com/photo.php?fbid=10152538813987961&set...', 1981, 1981, 1981, 'Anos 80', 'SAN JOSâ”œأ«', 41.64608800, -0.87090200, '0101000020E6100000F7AB00DF6DDEEBBF452BF702B3D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15480521506.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15480521506.webp', 'https://www.flickr.com/photos/zaragozaantigua/15480521506/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24698, 'Compromiso de Caspe 1978', 'Imagen de una pintura mural realizada por el "Colectivo Plâ”œأ­stico de Zaragoza", titulada "Aragâ”œâ”‚n 23 de Abril: Ganemos la Autonomâ”œآ،a". Caracterâ”œآ،stica del proceso de la "Transiciâ”œâ”‚n" y recuperaciâ”œâ”‚n de la democracia de finales de los aâ”œâ–’os 70 del pasado siglo, fue la exaltaciâ”œâ”‚n del regionalismo como otro campo de lucha contra el franquismo, que parecâ”œآ،a no haberse disuelto milagrosamente tras la muerte de Francisco Franco. En marzo de 1978 un real decreto ley del gobierno de Espaâ”œâ–’a instituyâ”œâ”‚ la Diputaciâ”œâ”‚n General de Aragâ”œâ”‚n, y el 23 de abril de ese aâ”œâ–’o, como "dâ”œآ،a de nuestro seâ”œâ–’or San Jorge", los 18 primeros diputados autonâ”œâ”‚micos (elegidos indirectamente, sin elecciones ad hoc), escenificaron en la Catedral de Huesca la elecciâ”œâ”‚n del primer Gobierno de Aragâ”œâ”‚n. Mientras, en Zaragoza tenâ”œآ،a lugar una manifestaciâ”œâ”‚n multitudinaria, por algunas de las calles mâ”œأ­s significadas de la ciudad. Unos dâ”œآ،as antes, por encargo del aâ”œâ•‘n no oficial Gobierno de Aragâ”œâ”‚n, este "Colectivo Plâ”œأ­stico de Zaragoza" realizâ”œâ”‚ cuatro murales con el institucional lema "Ganemos la Autonomâ”œآ،a", en ubicaciones de la avenida de Madrid, del paseo del General Mola (esquina con la calle Zumalacâ”œأ­rregui), de la calle San Juan de la Peâ”œâ–’a, y este que ilustra la entrada, en la manzana de casas entre Miguel Servet y Compromiso de Caspe. Este "Colectivo Plâ”œأ­stico de Zaragoza", que habâ”œآ،a nacido para reivindicar peticiones sociales, se encontrâ”œâ”‚ realizando estos murales como encargo oficial, con un lema que no significa absolutamente nada, y casualmente fueron sus â”œâ•‘ltimas producciones. El mural desapareciâ”œâ”‚, como el muro que lo soportaba. En su lugar mâ”œأ­s tarde se levantarâ”œآ،an los bloques de los nâ”œâ•‘meros 4-6-8 de Compromiso de Caspe. Fuente visual: "Historia contemporâ”œأ­nea de Aragâ”œâ”‚n. Dos siglos cruciales, del XIX al XX", HA, 1993. Fuente textual: Mâ”¬آ¬ Luisa Grau Tello, "La calle es nuestra: la pintura mural del Colectivo Plâ”œأ­stico de Zaragoza durante la Transiciâ”œâ”‚n", 2012.', 1978, 1978, 1978, 'Anos 70', 'SAN JOSâ”œأ«', 41.64608800, -0.87090200, '0101000020E6100000F7AB00DF6DDEEBBF452BF702B3D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18958406284.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18958406284.webp', 'https://www.flickr.com/photos/zaragozaantigua/18958406284/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24700, 'Matadero municipal 1901', 'El matadero municipal de Zaragoza, obra de Ricardo Magdalena, fue inaugurado en la carretera de Castellâ”œâ”‚n como sede de la Exposiciâ”œâ”‚n Aragonesa de 1885 y entrâ”œâ”‚ en funcionamiento funcional, para los propâ”œâ”‚sitos de su construcciâ”œâ”‚n, en 1887. Al fondo, el Pilar. Fuente visual: "Arquitectura y Construcciâ”œâ”‚n" (Barcelona).', 1901, 1901, 1901, 'Anos 1900', 'SAN JOSâ”œأ«', 41.64396500, -0.86983000, '0101000020E6100000BD8C62B9A5D5EBBF6362F3716DD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20925028498.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20925028498.webp', 'https://www.flickr.com/photos/zaragozaantigua/20925028498/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24714, 'Cine Roxy 1987', 'El cine Roxy, en la calle de Miguel Servet 53, fue inaugurado el 1 de febrero de 1961. Fue un cine de reestreno con 500 localidades, construido segâ”œâ•‘n proyecto de Josâ”œآ® Beltrâ”œأ­n. Cerrâ”œâ”‚ en agosto de 1985 y el edificio fue demolido en julio de 1987, como muestra la foto. Al fondo, traseras del nâ”œâ•‘mero 18 de la avenida del Compromiso de Caspe, recayentes a la calle del Monasterio de Samos.', 1987, 1987, 1987, 'Anos 80', 'SAN JOSâ”œأ«', 41.64525900, -0.87099100, '0101000020E6100000DF87838428DFEBBF8F39CFD897D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54388932253.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54388932253.webp', 'https://www.flickr.com/photos/zaragozaantigua/54388932253/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24849, 'Quinta de San Josâ”œآ® c.1900', 'Cortejo fâ”œâ•‘nebre ante la fachada de la Quinta de San Josâ”œآ®, famosa sobre todo por el gran vivero de â”œأ­rboles frutales y plantas y â”œأ­rboles ornamentales que desde los aâ”œâ–’os ochenta del siglo XIX pertenecâ”œآ،a a la familia Cambra, situado al principio del camino de San Josâ”œآ®, confrontando con el despartidero donde la calle de Miguel Servet prosigue hacia la carretera de Castellâ”œâ”‚n (a la derecha y fuera de plano). Las traseras de esta quinta llegaban hasta el camino de las Torres, y desapareciâ”œâ”‚ cuando la zona fue reurbanizada da forma radical con motivo de la apertura de la calle de la Reina Fabiola.', 1900, 1900, 1900, 'Anos 1900', 'SAN JOSâ”œأ«', 41.64619500, -0.87237200, '0101000020E61000008D463EAF78EAEBBF5BEB8B84B6D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21001811588.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21001811588.webp', 'https://www.flickr.com/photos/zaragozaantigua/21001811588/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25197, 'Puente sobre el Huerva 1847', '"Proyecto de un puente colgado que se intenta construir sobre el râ”œآ،o Huerva en el sitio denominado de San Josâ”œآ® Estramuros de la Ciudad de Zaragoza". Antonio de Ibarrarun, Graus, 1847. En el plano se refleja la iglesia del convento de San Josâ”œآ®, la ubicaciâ”œâ”‚n de la Puerta Quemada y el lugar pretendido para levantar el puente colgante (no realizado), junto a los "caminos de ronda de la poblaciâ”œâ”‚n": la actual calle del Asalto, que ha conservado el nombre popular de Ronda hasta nuestros dâ”œآ،as. Fuente: Archivo Municipal de Zaragoza.', 1847, 1847, 1847, 'Siglo XIX', 'SAN JOSâ”œأ«', 41.64818500, -0.87202200, '0101000020E6100000758F6CAE9AE7EBBFFE60E0B9F7D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30485877366.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30485877366.webp', 'https://www.flickr.com/photos/zaragozaantigua/30485877366/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25583, 'Fâ”œأ­brica de regaliz 1899', 'Vista de las traseras de la fâ”œأ­brica de regaliz de Zaragoza Carenou y Tur, levantada en 1874 como Flor, Cardenou y Tur. Sita en la calle Asalto 23, hoy El Aaiâ”œâ•‘n. Comercializaron la marca Zara. Fuente: Mâ”¬آ¬ Pilar Biel Ibâ”œأ­â”œâ–’ez, Zaragoza y la industrializaciâ”œâ”‚n: la arquitectura industrial 1875-1936, IFC, 2004.', 1899, 1899, 1899, 'Siglo XIX', 'SAN JOSâ”œأ«', 41.64852000, -0.87132000, '0101000020E610000019390B7BDAE1EBBFA5660FB402D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19613741298.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19613741298.webp', 'https://www.flickr.com/photos/zaragozaantigua/19613741298/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25589, 'Siâ”œآ؟ge de Saragosse 1809', 'Maqueta de hacia 1810, que representa la Zaragoza destruida por los Sitios en 1809. Este conjunto urbano imaginado podrâ”œآ،a rememorar el entorno del convento de los carmelitas de San Josâ”œآ®, en primer plano, derruido y utilizado como fuerte defensivo, con foso incluido. Ante â”œآ®l, una de las trincheras paralelas realizadas por los franceses en su aproximaciâ”œâ”‚n, durante el asedio de 1809. Junto a â”œآ®l, el puente de San Josâ”œآ® y el râ”œآ،o Huerva, y detrâ”œأ­s, el muro de rejola desde la puerta Quemada, hasta el molino de aceite de la ciudad. Fuente visual: www.museedesplansreliefs.culture.fr/', 1809, 1809, 1809, 'Siglo XIX', 'SAN JOSâ”œأ«', 41.64734600, -0.87205800, '0101000020E6100000A8E2C62DE6E7EBBF2499D53BDCD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30879118465.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30879118465.webp', 'https://www.flickr.com/photos/zaragozaantigua/30879118465/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25592, 'Puente de San Josâ”œآ® 1839', 'Dibujo incluido en el proyecto "para el puente llamado de San Josâ”œآ® sobre el râ”œآ،o Huerva" realizado por los arquitectos Josâ”œآ® de Yarza y Joaquâ”œآ،n Gironza para el Ayuntamiento. Este puente estaba previsto en la misma ubicaciâ”œâ”‚n "donde estaba el antiguo arruinado" durante los asedios franceses de 1808-09, y para sustituir al provisional que en 1838 se llevâ”œâ”‚ por delante una salida de madre del râ”œآ،o, que tambiâ”œآ®n destruyâ”œâ”‚ el puente de Santa Engracia. El dibujo muestra cierta fidelidad de este proyecto con el puente de piedra construido en el siglo XVI. Desde la izquierda se accede por el camino de la Puerta Quemada y la ronda que enlaza con las Tenerâ”œآ،as y la Puerta del Sol, y hacia la derecha arranca la carretera del Bajo Aragâ”œâ”‚n junto al ex-convento de San Josâ”œآ®. Este proyecto no serâ”œآ،a llevado a cabo, y finalmente un puente provisional y en madera (mâ”œأ­s barato) serâ”œآ،a ubicado unas decenas de metros aguas arriba. En los aâ”œâ–’os cincuenta y durante las obras vinculadas a la apertura de la plaza de San Miguel hacia el sur, se proyectarâ”œآ،a un nuevo puente en piedra, en una nueva ubicaciâ”œâ”‚n y definitiva aguas arriba, que abrirâ”œآ،a la nueva vâ”œآ،a de comunicaciâ”œâ”‚n hacia el sureste con una nueva puerta (del Duque de la Victoria) y su correspondiente caseta de consumos.', 1839, 1839, 1839, 'Siglo XIX', 'SAN JOSâ”œأ«', 41.64791900, -0.87250100, '0101000020E61000000246973787EBEBBF80BA8102EFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50061496367.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50061496367.webp', 'https://www.flickr.com/photos/zaragozaantigua/50061496367/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25733, 'Convento de San Josâ”œآ® 1860', 'Esta imagen aparece en el libro "Primeros tiempos de la fotografâ”œآ،a en Zaragoza", datada equivocadamente como "Convento de las Fecetas", pues se trata del antiguo Convento de San Josâ”œآ® de los Carmelitas Descalzos, fundado en 1594 junto al camino del Bajo Aragâ”œâ”‚n, en la ribera derecha del râ”œآ،o Huerva, extramuros de la ciudad. Arruinado e incendiado durante la guerra de 1808-1809, quedâ”œâ”‚ muy daâ”œâ–’ado. Fue reconstruido en 1814, y en 1835 fue desamortizado y estatalizado, ejerciendo de presidio hasta 1900, como "Penal de San Josâ”œآ®". En 1908 fue reconvertido a cuartel de Intendencia, hasta el aâ”œâ–’o 1971, en que fue incluido en la "Operaciâ”œâ”‚n Cuarteles", y vendido al Ayuntamiento, que lo derribâ”œâ”‚ unos aâ”œâ–’os despuâ”œآ®s para prolongar el camino de las Torres hasta el Ebro, y hacer zonas verdes y otros viales. En la imagen, vista del antiguo convento, cuando era Penal. A la derecha, al fondo, la torre de San Miguel de los Navarros. Por este lugar pasa, en la actualidad, el camino de las Torres un poco antes del cruce con Jorge Cocci. Fuente visual: Mariano Jâ”œâ•‘dez y Ortiz, 1859-1860. Col. Mariano Martâ”œآ،n Casalderrey.', 1860, 1860, 1860, 'Siglo XIX', 'SAN JOSâ”œأ«', 41.64755000, -0.87221100, '0101000020E61000003FC4060B27E9EBBF2D431CEBE2D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20240961111.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20240961111.webp', 'https://www.flickr.com/photos/zaragozaantigua/20240961111/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25740, 'Asilo de San Josâ”œآ® 1945', 'Imagen de la avenida de San Josâ”œآ® a la altura del Asilo de las Hermanas de los Pobres. Diseâ”œâ–’ado en 1882 en formas neomedievales, historicistas y eclâ”œآ®cticas, por Ricardo Magdalena. Una posterior reforma del edificio adosarâ”œأ­ a la planta calle, de acceso, todo un nuevo pabellon-pegote que a Magdalena no le hubiera hecho pizca gracia. El adoquinado de la avenida se habâ”œآ،a llevado por delante los â”œأ­rboles que mojoneaban el antiguo camino. Los postes de madera sostienen el cableado del tranvâ”œآ،a de la novâ”œآ،sima lâ”œآ،nea 13 "San Josâ”œآ®". La fotografâ”œآ،a se ha realizado desde una de las parcelas enfrente al Asilo, ya desaparecidas todas ellas. Fuente visual: AHPZ, Archivo Coyne', 1945, 1945, 1945, 'Anos 40', 'SAN JOSâ”œأ«', 41.64503300, -0.87278000, '0101000020E6100000CB4A9352D0EDEBBF9EEBFB7090D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20322661276.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20322661276.webp', 'https://www.flickr.com/photos/zaragozaantigua/20322661276/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25742, 'Avenida de San Josâ”œآ® 1990', 'En setiembre de 1879, Pilar Garcâ”œآ،a Fulla de Ubirâ”œآ،a, regalâ”œâ”‚ a la Congregaciâ”œâ”‚n de las Hermanitas de los Ancianos Desamparados un magnâ”œآ،fico campo con riego de la acequia de las Adulas, en el camino de San Josâ”œآ®, para construir un internado de ancianos desvalidos. Ricardo Magdalena proyectâ”œâ”‚ el inmueble, que fue inaugurado el 24 de mayo de 1882. El complejo ha padecido numerosas modificaciones y ampliaciones que lo han desvirtuado parcialmente. Una de las mutaciones mâ”œأ­s impactantes implicâ”œâ”‚ el derribo del Pabellâ”œâ”‚n-Sanatorio de las Hermanitas Enfermas, situado cerca de la esquina con la calle Miraflores. Con este derribo, se perdiâ”œâ”‚ el eclecticismo modernista de inspiraciâ”œâ”‚n neomedieval de este curioso edificio, singularmente concentrado en el poderoso torreâ”œâ”‚n. Fuente visual: Historia y poblaciâ”œâ”‚n del barrio de San Josâ”œآ® (Zaragoza), 2004.', 1990, 1990, 1990, 'Anos 90', 'SAN JOSâ”œأ«', 41.64439100, -0.87290800, '0101000020E61000002A560DC2DCEEEBBF1A6B7F677BD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20355457456.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20355457456.webp', 'https://www.flickr.com/photos/zaragozaantigua/20355457456/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25743, 'Avenida de San Josâ”œآ® 1948', 'Imagen del tranvâ”œآ،a nâ”¬â•‘ 90 (reactualizaciâ”œâ”‚n de una unidad mâ”œأ­s antigua de la serie 20) de la Lâ”œآ،nea 13 en la Avenida de Josâ”œآ® a la altura del Asilo de Pobres. Fuente: "Los tranvâ”œآ،as de Zaragoza", J. Peâ”œâ–’a - J. M. Valero, DPZ, 1985.', 1948, 1948, 1948, 'Anos 40', 'SAN JOSâ”œأ«', 41.64503300, -0.87278000, '0101000020E6100000CB4A9352D0EDEBBF9EEBFB7090D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20357745772.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20357745772.webp', 'https://www.flickr.com/photos/zaragozaantigua/20357745772/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25751, 'Elecciones 1977', 'Foto Luis Mompel, 1977. Jueves 16 de junio de 1977. En Espaâ”œâ–’a se celebran elecciones generales, prâ”œأ­ctica cuya anterior convocatoria tuvo lugar en febrero de 1936. En la imagen, un grupo de electores hacen fila en la entrada de la residencia de San Josâ”œآ® de las Hermanitas de los Ancianos Desamparados, vulgo Hermanitas de los Pobres, en la avenida de San Josâ”œآ® 22. Fuente: Archivo Heraldo de Aragâ”œâ”‚n.', 1977, 1977, 1977, 'Anos 70', 'SAN JOSâ”œأ«', 41.64503300, -0.87278000, '0101000020E6100000CB4A9352D0EDEBBF9EEBFB7090D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20571913841.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20571913841.webp', 'https://www.flickr.com/photos/zaragozaantigua/20571913841/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25768, 'Miguel Servet 1977', 'Calle de Miguel Servet en una imagen centrada en el tramo entre la del Monasterio de Samos y el punto donde, al fondo, arrancan la avenida de San Josâ”œآ®, la del Compromiso de Caspe, y la calle de la Reina Fabiola. Perdura en el firme el histâ”œâ”‚rico tendido tranviario que hasta febrero de 1976 servâ”œآ،a para conducir a las unidades de la lâ”œآ،nea 11. Parque-San Josâ”œآ® hasta las cocheras situadas mâ”œأ­s allâ”œأ­ de de la plaza de Utrillas. La fotografâ”œآ،a muestra que la supresiâ”œâ”‚n de los tranvâ”œآ،as no fue un â”œآ®xito a la hora de fluidificar el trâ”œأ­fico y mejorar la movilidad viaria. La masiva presencia de vehâ”œآ،culos a motor incluye el caracterâ”œآ،stico aparcamiento en baterâ”œآ،a, y el trâ”œأ­nsito de vehâ”œآ،culos de mâ”œأ­s de 8 Tm por esta calle, considerada por la Ordenanzas Municipales de circulaciâ”œâ”‚n como vâ”œآ،a de trâ”œأ­fico interurbano y acceso a sectores industriales desde la carretera de Castellâ”œâ”‚n.', 1977, 1977, 1977, 'Anos 70', 'SAN JOSâ”œأ«', 41.64555600, -0.87144800, '0101000020E6100000784485EAE6E2EBBF48DE3994A1D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33056621345.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33056621345.webp', 'https://www.flickr.com/photos/zaragozaantigua/33056621345/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25775, 'Av. de San Josâ”œآ® 1977', 'Imagen del primer tramo de la avenida de San Josâ”œآ® capturada desde la esquina con la calle del Fuero del Trabajo. Al fondo, el arranque desde la avenida del Compromiso de Caspe, cuyas parcelas eclipsan levemente al modernâ”œآ،simo Hâ”œأ­bitat Don 2000. A la izquierda, e inmediato, el luminoso del cine Dux, cerrado en mayo. A la derecha, muro perimetral, edificios y â”œأ­rboles de la antigua Torre Fraile, luego desaparecida. A ambos lados de la avenida perduran los gruesos postes del desmantelado tendido elâ”œآ®ctrico de la lâ”œآ،nea 11 del tranvâ”œآ،a, clausurada un aâ”œâ–’o antes. Los autobuses de la lâ”œآ،nea 40 realizan el mismo trayecto, de forma mâ”œأ­s moderna. Fuente visual: revista "Aragâ”œâ”‚n turâ”œآ،stico y monumental", SIPA.', 1977, 1977, 1977, 'Anos 70', 'SAN JOSâ”œأ«', 41.64371000, -0.87273700, '0101000020E6100000F94A202576EDEBBFD80DDB1665D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34672611971.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34672611971.webp', 'https://www.flickr.com/photos/zaragozaantigua/34672611971/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25776, 'C.â”¬â•‘ de Cabaldâ”œâ”‚s 1929', 'Imagen del interior del recinto deportivo del Frontâ”œâ”‚n Zaragozano poco antes de ser inauguradas las reformas de esta veterana instalaciâ”œâ”‚n abierta en 1895. En la soleada zona de la contracancha, inmediata a la zona de gradas descubiertas, destaca la puerta de acceso desde las taquillas ubicadas en el arranque del camino de Cabaldâ”œâ”‚s, muy cerca de la calle de Miguel Servet, donde una parada de la tranviaria lâ”œآ،nea del Bajo Aragâ”œâ”‚n le proporcionaba buena conexiâ”œâ”‚n desde el centro de la ciudad. Fuente visual: www.mecd.gob.es/.', 1929, 1929, 1929, 'Anos 20', 'SAN JOSâ”œأ«', 41.64391800, -0.87039800, '0101000020E6100000321F10E84CDAEBBF22A7AFE76BD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35068619802.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35068619802.webp', 'https://www.flickr.com/photos/zaragozaantigua/35068619802/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25792, 'Av. de San Josâ”œآ® 1977', 'Vista parcial del muro que delimitaba los restos de la antigua Torre de Fraile localizada en el tramo de la avenida entre las calles Matadero y Privilegio de la Uniâ”œâ”‚n. Aâ”œâ–’os mâ”œأ­s tarde, sobre parte de esta torre se trazarâ”œآ،a la plaza de la Reina Sofâ”œآ،a.', 1977, 1977, 1977, 'Anos 70', 'SAN JOSâ”œأ«', 41.64340700, -0.87279300, '0101000020E6100000F3AFE595EBEDEBBF3D821B295BD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54395866955.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54395866955.webp', 'https://www.flickr.com/photos/zaragozaantigua/54395866955/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26003, 'Cuartel de San Josâ”œآ® 1968', 'Vista en altura del râ”œآ،o Huerva aguas abajo del puente de San Josâ”œآ®, centrada en el Cuartel de Intendencia nâ”¬â•‘ 5 del ejâ”œآ®rcito de tierra (antiguo convento y prisiâ”œâ”‚n). En la margen izquierda del râ”œآ،o, el tambiâ”œآ®n militar "Parque", o "Corral de la Leâ”œâ–’a", y el reciente complejo de Elâ”œآ®ctricas Reunidas de Zaragoza. En la margen derecha, almacenes y solares de las traseras de Miguel Servet, calle que llega, al fondo, hasta el gran partidero hacia San Josâ”œآ®, las Fuentes, y la carretera de Castellâ”œâ”‚n. Junto al cuartel, la calle del Conde Alperche conectaba con Miguel Servet y el Camino de las Torres. El original y medieval puente de San Josâ”œآ® sobre el Huerva estuvo ubicado cerca de la esquina del convento mâ”œأ­s inmediata a nosotros. Por allâ”œآ، estaba trazado, entonces, el antiguo y principal camino de Fuentes, Mediana, y Tortosa. Cuando este puente fue destruido durante los conflictos 1808-1809, su ubicaciâ”œâ”‚n fue cambiando, hasta llegar a la actual, unos pocos cientos de metros aguas arriba, cerca de la iglesia de San Miguel. Aâ”œâ–’os mâ”œأ­s tarde, tras la primera "Operaciâ”œâ”‚n Cuarteles", esta instalaciâ”œâ”‚n cuartelaria serâ”œآ،a desmilitariazada, y derribada. El entorno comenzarâ”œآ،a a cambiar radicalmente.', 1968, 1968, 1968, 'Anos 60', 'SAN JOSâ”œأ«', 41.64755000, -0.87221100, '0101000020E61000003FC4060B27E9EBBF2D431CEBE2D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22168868028.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22168868028.webp', 'https://www.flickr.com/photos/zaragozaantigua/22168868028/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26031, 'Vista aâ”œآ®rea Miguel Servet 1963', 'Vista aâ”œآ®rea desde la calle de Miguel Servet, con el complejo del Matadero Municipal, y el resto de la ciudad, hasta el Ebro y mâ”œأ­s allâ”œأ­. Fuente: TAF Helicâ”œâ–“pters. Arxiu Nacional de Catalunya.', 1963, 1963, 1963, 'Anos 60', 'SAN JOSâ”œأ«', 41.64453300, -0.87025000, '0101000020E61000000C022B8716D9EBBFAD18AE0E80D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30539218524.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30539218524.webp', 'https://www.flickr.com/photos/zaragozaantigua/30539218524/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23367, 'Barranco del Paso del Ganado 1833', '"El Barranco del Paso del Ganado", litografâ”œآ،a de Faramundo Blanchard. El Canal Imperial de Aragâ”œâ”‚n prosigue demediado su curso hacia el Este, y a la altura de La Cartuja de la Concepciâ”œâ”‚n salva un barranco mediante la obra mostrada, que subsiste, entre las Esclusas de Valmadrid y la Almenara de La Concepciâ”œâ”‚n. Fuente visual: "Memoria histâ”œâ”‚rica del Canal imperial de Aragon: noticia sobre las utilidades que produce, y esplicacion de lo que contienen las lâ”œأ­minas que se publican", Madrid, 1833.', 1833, 1833, 1833, 'Siglo XIX', NULL, 41.58019400, -0.78656000, '0101000020E6100000B3EF8AE07F2BE9BFEFAA07CC43CA4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19308049000.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19308049000.webp', 'https://www.flickr.com/photos/zaragozaantigua/19308049000/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21214, 'Canal Imperial 1900', '1900. Gâ”œâ”‚ndola "Sta. Cecilia" en un posado en el embarcadero de la Quinta Julieta Sagols, que queda a la izquierda. Al fondo, la pronunciada curva del Canal hacia la derecha para dirigirse al puente-acueducto del Barranco de la Muerte, por donde originalmente pasaba el Canal. En la actualidad, unas biondas que quitan el miedo tratan de evitar que los coches caigan al Canal. Los peatones, mientras tanto, juegan a la pista (norte)americana para evitar ser atropellados. En 2003 se desviâ”œâ”‚ el Canal y se construyâ”œâ”‚ una nueva estructura sobre el Tercer Cinturâ”œâ”‚n mâ”œأ­s hacia la izquierda, por donde en la actualidad el Canal supera el barranco. El cisne tallado en la proa, al modo y manera de las gâ”œâ”‚ndolas venecianas, aun abatido y un tanto taciturno, acabâ”œâ”‚ por apropiarse con el nomenclâ”œأ­tor de la embarcaciâ”œâ”‚n, y la santa de la mâ”œâ•‘sica, los poetas, y los ciegos, apenas es recordada. Aquâ”œآ، lo hacemos.', 1900, 1900, 1900, 'Anos 1900', 'SAN JOSâ”œأ«', 41.62570800, -0.87143800, '0101000020E610000095BBCFF1D1E2EBBF3C6C223317D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15085398726.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15085398726.webp', 'https://www.flickr.com/photos/zaragozaantigua/15085398726/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21249, 'Quinta Julieta c.1900', 'Postal de "Quinta Julieta" circulada el aâ”œâ–’o 1907, cuando era lugar de acceso pâ”œâ•‘blico (pagando una entrada) como lugar donde pasar el domingo junto al Canal Imperial con un espectâ”œأ­culo de "macizos verdes, amarillos, arcos de rosales trepadores", de "flores, estanques y cisnes, glorietas, madreselvas, câ”œآ®sped, cenadores". Fuente visual: postal Hauser y Menet serie "Zaragoza", nâ”¬â•‘ 2005, en www.todocoleccion.net/', 1900, 1900, 1900, 'Anos 1900', 'SAN JOSâ”œأ«', 41.62527500, -0.87090200, '0101000020E6100000F7AB00DF6DDEEBBFD200DE0209D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20307535522.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20307535522.webp', 'https://www.flickr.com/photos/zaragozaantigua/20307535522/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21327, 'Quinta Julieta 1900', 'Dibujo de la tribuna de pâ”œâ•‘blico del campo de tiro habilitado en la canalina Quinta Julieta, cedida para la ocasiâ”œâ”‚n por su propietario Enrique Sagols y Ferrer durante la celebraciâ”œâ”‚n del primer certamen nacional de tiro, organizado por la Asociaciâ”œâ”‚n del Tiro Nacional en el marco de las Fiestas del Pilar de 1900, entre los dâ”œآ،as 17 y 21 de octubre.', 1900, 1900, 1900, 'Anos 1900', 'SAN JOSâ”œأ«', 41.62538700, -0.87025800, '0101000020E6100000C2A2224E27D9EBBFFA2B64AE0CD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50074123163.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50074123163.webp', 'https://www.flickr.com/photos/zaragozaantigua/50074123163/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21332, 'Quinta Julieta 1900', 'Entrega de premios en el primer certamen nacional de tiro, organizado por la Asociaciâ”œâ”‚n del Tiro Nacional en el marco de las Fiestas del Pilar de 1900, entre los dâ”œآ،as 17 y 21 de octubre. El campo de tiro fue habilitado en la Quinta Julieta, cedida para la ocasiâ”œâ”‚n por su propietario Enrique Sagols y Ferrer, cuya casa aparece en esta imagen como fondo escâ”œآ®nico para la ceremonia de entrega de premio de las tres categorâ”œآ،as habilitadas: obreros, jornaleros y trabajadores; estudiantes; y oficiales del ejâ”œآ®rcito.', 1900, 1900, 1900, 'Anos 1900', 'SAN JOSâ”œأ«', 41.62531500, -0.87065500, '0101000020E6100000062AE3DF67DCEBBF605969520AD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50923005947.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50923005947.webp', 'https://www.flickr.com/photos/zaragozaantigua/50923005947/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21411, 'Quinta Julieta c.1918', 'Curiosa imagen de la finca conocida como "Quinta Julieta", cuando tras los tiempos de las gâ”œâ”‚ndolas por el Canal y su acceso pâ”œâ•‘blico, los actos deportivos, y las renombradas fiestas y celebraciones en el marco de la exposiciâ”œâ”‚n Hispano-Francesa de 1908, ya era propiedad de los PP. Jesuitas como dependencia ultraperifâ”œآ®rica del Colegio del Salvador. Con ediciâ”œâ”‚n de â”œأ¼ngel Toldrâ”œأ­ Viazo, en Barcelona, se realizâ”œâ”‚ entonces una serie de postales alusiva a este colegio, entre las que se encontraba esta vista denominada "Las colmenas de la Quinta Julieta".', 1918, 1918, 1918, 'Anos 10', 'SAN JOSâ”œأ«', 41.62527500, -0.87090200, '0101000020E6100000F7AB00DF6DDEEBBFD200DE0209D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27595454721.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27595454721.webp', 'https://www.flickr.com/photos/zaragozaantigua/27595454721/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21546, 'La Granja 1922', 'Imagen de los jardines y huertos que flanqueaban el ingreso a los pabellones principales de la desaparecida Granja Agrâ”œآ،cola de Zaragozal. Al fondo, clarea el monumento a Manuel Rodrâ”œآ،guez Ayuso, que fuera impulsor y director de esta Granja. Detrâ”œأ­s del edificio de los establos, moreras del camino luego redenominado calle de Josâ”œآ® Galiay. Fuente visual: Archivo Requejo, AHPZ-DARA.', 1922, 1922, 1922, 'Anos 20', 'SAN JOSâ”œأ«', 41.63605300, -0.87058000, '0101000020E61000005DA79196CADBEBBFE7C2482F6AD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20182158289.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20182158289.webp', 'https://www.flickr.com/photos/zaragozaantigua/20182158289/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21554, 'Barrio de la Paciencia 1929', 'Imagen capturada en la calle de Carbâ”œâ”‚ y centrada en un muro que delimitaba una propiedad que hacâ”œآ،a de tapâ”œâ”‚n en esta calle que vertebraba el denominado barrio de la Paciencia, y que poco despuâ”œآ®s fue derribado para facilitar el trâ”œأ­nsito. Este barrio fue creado en 1928 y era otro ejemplo de barrio-calle a ambos lados de un largo y nuevo vial denominado calle Carbâ”œâ”‚ (primer tramo) y calle Grao (segundo tramo), nombres de las parcelaciones que estos propietarios emprendieron en dos terrenos que llegaban desde el camino de San Josâ”œآ® hasta el de Cabaldâ”œâ”‚s. Aâ”œâ–’os mâ”œأ­s tarde, esta calle recibirâ”œأ­ una sola denominaciâ”œâ”‚n comâ”œâ•‘n: Uniâ”œâ”‚n, y tras 1940, Privilegio de la Uniâ”œâ”‚n. La razâ”œâ”‚n que explicaba una aislada urbanizaciâ”œâ”‚n como esta, en un entorno despoblado, es que quienes vivâ”œآ،an en las 50 parcelas que componâ”œآ،an este barrio particular, unos 250 vecinos en total, trabajaban y dependâ”œآ،an de un taller de fundiciâ”œâ”‚n y una fâ”œأ­brica de mosaicos cercanos. El barrio habâ”œآ،a nacido al calor de estas factorâ”œآ،as. El desorden urbanâ”œآ،stico, la ausencia de equipamientos, la escasa calidad de los edificios (autoconstruidos con materiales de la zona), y una importante cantidad de acequias y riegos al aire, caracterizaban a esta zona, tal y como le pasaba a otros "barrios particulares" que luego conformarâ”œأ­n el barrio de San Josâ”œآ®: barrio de San Josâ”œآ® de Calasanz, Comâ”œآ،n, Monforte, Cuber, Colâ”œâ”‚n, los Chiflaos... La foto actualmente se corresponderâ”œآ،a con el tramo de los nâ”œâ•‘meros impares de la calle del Privilegio de la Uniâ”œâ”‚n entre las del Monasterio de Samos y Santa Rosa.', 1929, 1929, 1929, 'Anos 20', 'SAN JOSâ”œأ«', 41.64254700, -0.87278000, '0101000020E6100000CB4A9352D0EDEBBF4B92E7FA3ED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21179745292.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21179745292.webp', 'https://www.flickr.com/photos/zaragozaantigua/21179745292/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23368, 'Almenara de La Concepciâ”œâ”‚n 1833', '"Almenara de La Concepciâ”œâ”‚n", litografâ”œآ،a de Faramundo Blanchard. Tras pasar el Barranco de Las Casetas, en el punto en que se halla esta almenara, prâ”œâ”‚ximo a La Cartuja de la Concepciâ”œâ”‚n, el Canal Imperial abandona su curso primitivo y se transforma en una red de acequias que llega por El Burgo de Ebro (cuyos campos riega la acequia que parte de esta Almenara) hasta Fuentes de Ebro. Fuente visual: "Memoria histâ”œâ”‚rica del Canal imperial de Aragon: noticia sobre las utilidades que produce, y esplicacion de lo que contienen las lâ”œأ­minas que se publican", Madrid, 1833.', 1833, 1833, 1833, 'Siglo XIX', NULL, 41.57942800, -0.78449600, '0101000020E610000059F8FA5A971AE9BF7F315BB22ACA4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19308299060.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19308299060.webp', 'https://www.flickr.com/photos/zaragozaantigua/19308299060/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21973, 'Campo del Arenas 1944', 'El club Arenas S.D. de "football" fue fundado en 1927, y en 1941, tras pasar por La Cartuja, el velâ”œâ”‚dromo de los Campos Eliseos, la Hâ”œآ،pica y San Gregorio, contâ”œâ”‚ con terreno de juego propio en el nuevo Campo de San Josâ”œآ®, construido sobre antiguos campos de cultivo del Barrio de la Paciencia, entre el Camino de San Josâ”œآ® y el de Cabaldâ”œâ”‚s, y las calles Carbâ”œâ”‚ y Castelar, a unas pocas decenas de metros del Frontâ”œâ”‚n Zaragozano. En â”œآ®l jugaban tambiâ”œآ®n como locales equipos que no se podâ”œآ،an permitir tener campo propio, como el Club Atlâ”œآ®tico Zaragoza. Este terreno de juego fue derribado en 1967, y urbanizado inmediatamente. En la imagen, saludo fascista preceptivo antes del comienzo de la sâ”œآ®ptima jornada de la liga 1944-45 (Tercera Divisiâ”œâ”‚n, Grupo 4) entre el Club Atlâ”œآ®tico Zaragoza (camiseta blanca y pantalâ”œâ”‚n azul claro) y La Sociedad Deportiva Escoriaza (camiseta roja y pantalâ”œâ”‚n negro), en el campo de San Josâ”œآ®, el 5 de noviembre de 1944. Venciâ”œâ”‚ el Atlâ”œآ®tico por dos tantos a cero. Tras las parcelas del fondo, la larga calle Uniâ”œâ”‚n (antigua Carbâ”œâ”‚), y las pequeâ”œâ–’as calles de General Ricardos, y del Salvador. Fuente visual: Gerardo Sancho Ramo, Archivo Pâ”œâ•‘blico Municipal.', 1944, 1944, 1944, 'Anos 40', 'SAN JOSâ”œأ«', 41.64145100, -0.87096500, '0101000020E610000090BDDEFDF1DEEBBF467EFD101BD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24231521250.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24231521250.webp', 'https://www.flickr.com/photos/zaragozaantigua/24231521250/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21982, 'Arenas S.D. 1944', 'Vista parcial del terreno donde el club Arenas S.D. de "football" jugaba como local, junto al que fuera antiguo barrio "de la Paciencia", entre el Camino de San Josâ”œآ® (izquierda) y el de Cabaldâ”œâ”‚s, y las calles Carbâ”œâ”‚ y Castelar, muy cerca del Frontâ”œâ”‚n Zaragozano. En 1967, este campo cesâ”œâ”‚ en sus funciones deportivas, y fue urbanizado inmediatamente, como parte de la zona baja del barrio de San Josâ”œآ®. En la imagen, y tras las parcelas del fondo, la larga calle Uniâ”œâ”‚n (antigua Carbâ”œâ”‚), y las pequeâ”œâ–’as calles de General Ricardos, y del Salvador. Por entre los tejados de literal teja, sobresale el pinchudo remate de la torre del asilo de ancianos de las "Hermanitas de los Pobres", diseâ”œâ–’ado por Ricardo Magdalena. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1944, 1944, 1944, 'Anos 40', 'SAN JOSâ”œأ«', 41.64145100, -0.87096500, '0101000020E610000090BDDEFDF1DEEBBF467EFD101BD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28166353761.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28166353761.webp', 'https://www.flickr.com/photos/zaragozaantigua/28166353761/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22018, 'Arenas S.D. 1946', 'Vista parcial del terreno donde el club Arenas S.D. de "football" jugaba como local, junto al que fuera antiguo barrio "de la Paciencia", entre el camino de San Josâ”œآ® (izquierda) y el de Cabaldâ”œâ”‚s, y las calles Carbâ”œâ”‚ y Castelar, muy cerca del Frontâ”œâ”‚n Zaragozano. En 1967, este campo cesâ”œâ”‚ en sus funciones deportivas, y fue urbanizado inmediatamente, como parte de la zona baja del barrio de San Josâ”œآ®. En la imagen, y tras las parcelas del fondo, la larga calle de la Uniâ”œâ”‚n (antigua de Carbâ”œâ”‚), y las pequeâ”œâ–’as calles de General Ricardos, y del Salvador. Por entre los tejados de literal teja, sobresale el remate de la torre del asilo de ancianos de las "Hermanitas de los Pobres", diseâ”œâ–’ado por Ricardo Magdalena.', 1946, 1946, 1946, 'Anos 40', 'SAN JOSâ”œأ«', 41.64126500, -0.87080500, '0101000020E61000005A2F8672A2DDEBBFE388B5F814D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49421720657.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49421720657.webp', 'https://www.flickr.com/photos/zaragozaantigua/49421720657/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22106, 'Camino Puente Virrey aâ”œâ–’os 50', 'Imagen familiar tomada en el camino del Puente del Virrey del barrio de San Josâ”œآ® de Zaragoza, a la altura de la actual plaza Mayor. A la derecha se abrirâ”œأ­ la calle Raquel Meyer. Fuente: www.facebook.com/photo.php?fbid=10204194390557272&set...', 1950, 1950, 1959, 'Anos 50', 'SAN JOSâ”œأ«', 41.63790400, -0.87430400, '0101000020E61000002C62D8614CFAEBBF69FE98D6A6D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21094420910.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21094420910.webp', 'https://www.flickr.com/photos/zaragozaantigua/21094420910/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22203, 'Iglesia de San Josâ”œآ® 1953', 'Dibujo de la fachada y planta de la que fue proyectada por Regino y Josâ”œآ® Borobio como iglesia de la barriada de San Josâ”œآ®, en una estratâ”œآ®gica ubicaciâ”œâ”‚n chaflanera entre la calle de Cartagena (a la izquierda), el camino del Puente del Virrey y la avenida de San Josâ”œآ®. Vinculada al Patronato del canâ”œâ”‚nigo Agustâ”œآ،n Gericâ”œâ”‚, junto a las escuelas por â”œآ®l fundadas, aparecâ”œآ،a vertebrada en tres naves y presentaba una llamativa torre-campanario exenta de cuarenta metros de altura. No fue realizada. Fuente visual: AMZ.', 1953, 1953, 1953, 'Anos 50', 'SAN JOSâ”œأ«', 41.63991000, -0.87359500, '0101000020E6100000315F5E807DF4EBBF12312592E8D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/37894644092.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/37894644092.webp', 'https://www.flickr.com/photos/zaragozaantigua/37894644092/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22517, 'Calle de Santa Rosa c.1964', 'Luminosa y familiar estampa capturada junto al inmueble del nâ”¬â•‘ 16 de la calle de Santa Rosa, esquinero con el cruce de la reciente calle de Luis Braille, que por detrâ”œأ­s la cruza en un espacio recientemente urbanizado donde antes estuviera el campo de deportes de San Josâ”œآ® del Arenas. Hacia el fondo y a la derecha, modernos bloques de los nâ”œâ•‘meros 9 y 11 de este reciente tramo de Santa Rosa, y el angular nâ”¬â•‘ 1 de Luis Braille. En esa misma acera y a continuaciâ”œâ”‚n destaca la antigua parcela del nâ”¬â•‘ 3 de Santa Rosa, seguida por el moderno edificio de viviendas del nâ”¬â•‘ 30 de la calle del Privilegio de la Uniâ”œâ”‚n, que al fondo muestra la antigua parcela del nâ”¬â•‘ 31 de la que fuera calle de Carbâ”œâ”‚ del barrio de la Paciencia, que luego serâ”œآ،a derribada y sobre cuyo solar se construyâ”œâ”‚ a principios de los aâ”œâ–’os ochenta el actual inmueble del nâ”¬â•‘ 29 y 31 de Privilegio de la Uniâ”œâ”‚n.', 1964, 1964, 1964, 'Anos 60', 'SAN JOSâ”œأ«', 41.64089600, -0.87139600, '0101000020E6100000D9AF3BDD79E2EBBF901150E108D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52350301955.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52350301955.webp', 'https://www.flickr.com/photos/zaragozaantigua/52350301955/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22634, 'La Granja 1975', 'Los campos de cultivo de la antigua Granja Experimental de Zaragoza se extendâ”œآ،an a ambos lados de la vâ”œآ،a de los ferrocarriles a Barcelona. Para salvar la trinchera del tren, que por aquâ”œآ، seguâ”œآ،a al aire una vez cubierto el tramo Goya-Tenor Fleta-cruce con el Camino del Puente del Virrey, existâ”œآ،a tiempo ha este puentecito peatonal unos 60 m. despuâ”œآ®s del Grupo de Viviendas Puente Virrey-Rosellâ”œâ”‚n (lado derecho de las vâ”œآ،as), y a unos 40 m. de las parcelas de Emilio Mario, Alegrâ”œآ،a y Nobleza (lado izquierdo de las vâ”œآ،as). En 1943 la Granja fue abandonada, y se construyeron los edificios de viviendas del triangular bloque de la nueva calle Josâ”œآ® Galiay. Pasaron las dâ”œآ®cadas, y el entorno apenas se modificâ”œâ”‚. Las acequias seguâ”œآ،an al aire, los campos se cultivaban, las ovejas y cabras ramoneaban, y la chavalerâ”œآ،a y tercera edad hacâ”œآ،an de estos lares su lugar de juego, convivencia y sociabilidad. En la imagen, un rebaâ”œâ–’o de ovejas rasas y cabras cruza el puente peatonal (porque peatones lo somos todos los animales), en direcciâ”œâ”‚n a los abrevaderos del Camino de Cabaldâ”œâ”‚s. Al fondo, a la izquierda, se perfila la silueta del silo de cereales del Ministerio de Agricultura sito en la carretera de Castellâ”œâ”‚n, y las industriosas chimeneas de la abandonada fâ”œأ­brica de cementos Portland nos conducen al blanco edificio de viviendas de la estaciâ”œâ”‚n de Miraflores. Inmediato, sobre las vâ”œآ،as, el Camino de Cabaldâ”œâ”‚s convertido en paso para vehâ”œآ،culos a motor de explosiâ”œâ”‚n. En la actualidad, en este mismo punto termina la breve prolongaciâ”œâ”‚n de Tenor Fleta. Una metâ”œأ­lica valla da perspectiva del sarcâ”œâ”‚fago de cemento que alcanza hasta el Tercer Cinturâ”œâ”‚n, donde deberâ”œآ،a de haber llegado hace tiempo, mientras los vehâ”œآ،culos han de dar la vuelta para volver hacia donde han venido. Fuente visual: AMZ, Gerardo Sancho Ramo.', 1975, 1975, 1975, 'Anos 70', 'SAN JOSâ”œأ«', 41.63554000, -0.87270400, '0101000020E61000000BD462F030EDEBBF61A6ED5F59D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20236297745.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20236297745.webp', 'https://www.flickr.com/photos/zaragozaantigua/20236297745/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24946, 'Vista de Zaragoza 1924', 'Hay fotografâ”œآ،as que suplen la nitidez con la sugerencia, y esta del archivo Francisco Gâ”œâ”‚rriz, es una de ellas. Capturada desde las alturas del Cabezo de Buenavista, que por la derecha desciende desde el paseo del Canal hacia el cauce del râ”œآ،o Huerva. Mâ”œأ­s allâ”œأ­, huertas y campos de cultivo de la ribera de este râ”œآ،o, en el entorno del camino del Sâ”œأ­bado, el viejo camino de Cuarte, y el paseo de los Ruiseâ”œâ–’ores. A la derecha, algunos de los edificios del paseo de los Ruiseâ”œâ–’ores, como el reciente colegio Pompiliano de las MM. Escolapias, tan destacado por la notable diferencia de cota de altura de unas terrazas naturales, y otras. El ciudadano que acaba de salir del camino viejo de Cuarte nos seâ”œâ–’ala el curso, a la inversa, de la acequia de las Adulas o de San Josâ”œآ®, que por ahâ”œآ، continâ”œâ•‘a su largo recorrido al aire hasta el camino de las Torres y mucho mâ”œأ­s allâ”œأ­. En descenso desde el Canal Imperial, el cauce de la derivaciâ”œâ”‚n de agua que abastecâ”œآ،a a la fâ”œأ­brica de harinas de Monares y que unos metros mâ”œأ­s abajo desembocaba en la acequia de las Adulas. Al fondo, como un escâ”œآ®nico telâ”œâ”‚n, la ciudad y sus emergentes torres y câ”œâ•‘pulas, cuando seguâ”œآ،an siendo los referentes edilicios visualmente mâ”œأ­s destacados.', 1924, 1924, 1924, 'Anos 20', 'UNIVERSIDAD', 41.63421300, -0.89280800, '0101000020E6100000EC6D3315E291ECBF5AD93EE42DD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28009925163.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28009925163.webp', 'https://www.flickr.com/photos/zaragozaantigua/28009925163/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22635, 'La Granja 1975', 'Captura parcial de algunos de los edificios que formaban parte del enorme complejo de la antigua Granja Agrâ”œآ،cola Experimental, creada en 1881 y abandonada desde 1943. Hasta su derribo para construir el nuevo Colegio Pâ”œâ•‘blico Calixto Ariâ”œâ–’o-Hilario Val, fue una de las emblemâ”œأ­ticas "solanas" del barrio donde las yayas y yayos, venidos con las ornadas de expulsados de los pueblos, se iban a echar la maâ”œâ–’ana y la tarde. El alto edificio de la izquierda habâ”œآ،a sido el pabellâ”œâ”‚n docente de la instituciâ”œâ”‚n, diseâ”œâ–’ado por el arquitecto municipal Fâ”œآ®lix Navarro. Los bancos adosados fueron aâ”œâ–’adido posterior, en las esquinas mâ”œأ­s guarnecidas. Lo mismo sucedâ”œآ،a con el edificio del centro, que fue antiguo cocherâ”œâ”‚n para la maquinaria agrâ”œآ،cola utilizada en las clases prâ”œأ­cticas. El edificio de la derecha se construyâ”œâ”‚ sobre la original bâ”œأ­scula para carros tirados por mulos. Los campos de los alrededores siguieron siendo cultivados de herbâ”œأ­ceos y maâ”œآ،z unos aâ”œâ–’os mâ”œأ­s, hasta 1978-79. Al fondo de la imagen, uno de los arcos de la antigua fâ”œأ­brica de briquetas asociada a la Estaciâ”œâ”‚n de ferrocarril de Zaragoza a Utrillas, en la actual calle Ducado de Atenas, donde hoy se levanta el pabellâ”œâ”‚n municipal de deportes P. Felipe. Mâ”œأ­s al fondo, algunos de los industriosos edificios de Miguel Servet. Fuente visual: AVV San Josâ”œآ®', 1975, 1975, 1975, 'Anos 70', 'SAN JOSâ”œأ«', 41.63564100, -0.87072800, '0101000020E610000082C476F700DDEBBF957F2DAF5CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20242766662.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20242766662.webp', 'https://www.flickr.com/photos/zaragozaantigua/20242766662/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22638, 'La Granja 1975', 'Imagen del edificio a doble vertiente del antiguo "cocherâ”œâ”‚n de maquinaria agrâ”œآ،cola" de la Granja Agrâ”œآ،cola Experimental de Zaragoza, ya convertido hacâ”œآ،a tiempo en comunitario y oficioso espacio al aire libre de reuniâ”œâ”‚n social del barrio, como solanera en invierno, y fresquera en verano. Tras â”œآ®l, campos de cultivo de maâ”œآ،z en lo que fueran antiguos jardines del acceso principal a los pabellones de la Granja. A la izquierda, el antiguo y gran edificio con funciones de residencia de estudiantes "granjeros", mostrando inequâ”œآ،vocas seâ”œâ–’ales del mal paso de los aâ”œâ–’os, tras el abandono de estas instalaciones, varias dâ”œآ®cadas antes. Al fondo, entre los dos edificios de la Granja, despunta la rotunda torre de la fâ”œأ­brica GIESA-Schindler, al otro lado de la calle Miguel Servet. A la izquierda, bloques cercanos al camino del Junco. Pocos aâ”œâ–’os despuâ”œآ®s, esta zona representada serâ”œآ،a profundamente modificada. Fuente visual: AVV. San Josâ”œآ®', 1975, 1975, 1975, 'Anos 70', 'SAN JOSâ”œأ«', 41.63564100, -0.87072800, '0101000020E610000082C476F700DDEBBF957F2DAF5CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20353031476.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20353031476.webp', 'https://www.flickr.com/photos/zaragozaantigua/20353031476/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22640, 'Tren Miraflores 1975', 'Imagen de un convoy transitando bajo el puente peatonal sobre las vâ”œآ،as del ferrocarril Madrid-Barcelona. A la izquierda, al fondo, chimeneas de la fâ”œأ­brica de Cementos de Miraflores. A la derecha, el aterrazado descenso desde el Camino de Miraflores, con parcial vista de las "Casas de los Americanos". Fuente visual: AMZ, Gerardo Sancho Ramo.', 1975, 1975, 1975, 'Anos 70', 'SAN JOSâ”œأ«', 41.63554000, -0.87270400, '0101000020E61000000BD462F030EDEBBF61A6ED5F59D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20412743472.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20412743472.webp', 'https://www.flickr.com/photos/zaragozaantigua/20412743472/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22896, 'Parque La Granja 1989', 'Vista aâ”œآ®rea sobre el barrio de San Josâ”œآ® centrada en la construcciâ”œâ”‚n del Parque de La Granja, que muestra el trazado de sus viales internos y los espacios donde luego se instalarâ”œأ­n diversos complementos. Este nuevo parque suponâ”œآ،a la ampliaciâ”œâ”‚n de la arbolada zona que, a su izquierda, se habâ”œآ،a trazado unos aâ”œâ–’os antes entre la calle de Josâ”œآ® Galiay y el camino de Cabaldâ”œâ”‚s, y que junto al Colegio Pâ”œâ•‘blico Calixto Ariâ”œâ–’o-Hilario Val, el Colegio Pâ”œâ•‘blico de Educaciâ”œâ”‚n Especial â”œأ¼ngel Riviâ”œآ؟re, y el nuevo parque, ocupaban el espacio donde estuviera la antigua Granja Agrâ”œآ،cola de Zaragoza. Vertebrann la escena las vâ”œآ،as del ferrocarril, ya soterradas hasta el puentecillo peatonal de la calle de Luis Aula. Tras el parque, el Centro Deportivo Municipal La Granja, y a la derecha la estaciâ”œâ”‚n de Miraflores. Al fondo, obras del nuevo pabellâ”œâ”‚n municipal de deportes, y la Facultad de Veterinaria.', 1989, 1989, 1989, 'Anos 80', 'SAN JOSâ”œأ«', 41.63518400, -0.87141900, '0101000020E6100000E59D4319AAE2EBBFA37895B54DD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20552947004.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20552947004.webp', 'https://www.flickr.com/photos/zaragozaantigua/20552947004/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22283, 'Calle de Rodrigo Rebolledo 1962', 'Archivo Municipal Zaragoza. Gerardo Sancho Ramo. Noviembre 1962. "Calles de Zaragoza." Imagen de la calle Rodrigo Rebolledo (este tramo, desde 1974, serâ”œأ­ denominado Monasterio Nâ”¬آ¬ Sâ”¬آ¬ de El Pueyo), con visual, al fondo, de Compromiso de Caspe. A la izquierda, las vâ”œآ،as de la lâ”œآ،nea 17 del tranvâ”œآ،a ("Las Fuentes"), inaugurada en 1957 para unir la Plaza de Espaâ”œâ–’a con Salvador Minguijâ”œâ”‚n, aunque ya en 1961 el trayecto serâ”œأ­ recortado a Rodrigo Rebolledo. Al fondo, el Grupo de Viviendas "Casta â”œأ¼lvarez", y la esquina del Matadero en que nacen Florentino Ballesteros y Monasterio de Samos.', 1962, 1962, 1962, 'Anos 60', 'LAS FUENTES', 41.64613100, -0.86768300, '0101000020E6100000047289230FC4EBBF44F7AC6BB4D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15049357997.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15049357997.webp', 'https://www.flickr.com/photos/zaragozaantigua/15049357997/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23040, 'Calle de Cartagena 1994', 'Imagen capturada durante la urbanizaciâ”œâ”‚n de la calle de Cartagena al objeto de prepararla para conectar la avenida de Cesâ”œأ­reo Alierta, al fondo, con la prolongaciâ”œâ”‚n de la misma que ya estaba construida desde esta calle y hasta el Pabellâ”œâ”‚n Municipal de Deportes Prâ”œآ،ncipe Felipe. La intervenciâ”œâ”‚n incluâ”œآ،a la renovaciâ”œâ”‚n de las redes de abastecimiento de agua, alcantarillado, alumbrado pâ”œâ•‘blico, semaforizaciâ”œâ”‚n, etcâ”œآ®tera, ademâ”œأ­s de la pavimentaciâ”œâ”‚n de las aceras, calzada y medianas, de forma similar que el tramo ya realizado. Con esta urbanizaciâ”œâ”‚n, a la prolongaciâ”œâ”‚n de la avenida de Cesâ”œأ­reo Alierta ya sâ”œâ”‚lo le quedaba pendiente de realizaciâ”œâ”‚n el tramo comprendido entre el pabellâ”œâ”‚n municipal y el enlace con la carretera de Castellâ”œâ”‚n, cumpliendo asâ”œآ، el proyecto ideado varias dâ”œآ®cadas antes, como forma de conectar de forma directa la circulaciâ”œâ”‚n rodada del centro de la ciudad con la carretera de Castellâ”œâ”‚n, sin tener que pasar por la congestionada calle de Miguel Servet. Con esta obra, la veterana calle de Cartagena desaparecerâ”œآ،a del nomenclâ”œأ­tor urbano.', 1994, 1994, 1994, 'Anos 90', 'SAN JOSâ”œأ«', 41.63921200, -0.87131000, '0101000020E610000036B05582C5E1EBBFFA9AE5B2D1D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50380070208.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50380070208.webp', 'https://www.flickr.com/photos/zaragozaantigua/50380070208/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23203, 'Calle San Luis de Francia 2010', 'Aspecto de la calle de San Luis de Francia, con la del Privilegio de la Uniâ”œâ”‚n al fondo, en enero de 2010. El solar de la izquierda, perteneciente al nâ”œâ•‘mero 21, fue acondicionado como espacio de ocio en 2015. Este entorno se da en denominar Isla de San Josâ”œآ®, y es uno de los mâ”œأ­s envejecidos de la ciudad. Fuente: Heraldo de Aragâ”œâ”‚n.', 2010, 2010, 2010, 'Siglo XXI', 'SAN JOSâ”œأ«', 41.64172600, -0.87082900, '0101000020E61000007B116DC7D4DDEBBF177FDB1324D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32548808403.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32548808403.webp', 'https://www.flickr.com/photos/zaragozaantigua/32548808403/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23210, 'Calle Santa Rosa 2010', 'Foto: Oliver Duch. Vista de la calle de Santa Rosa, tramo comprendido entre las de Antonio Maura y Emilio Castelar (al fondo). El solar de la derecha serâ”œأ­ objeto de acondicionamiento en 2011 dentro del programa municipal "Esto no es un solar". Fuente: Heraldo de Aragâ”œâ”‚n.', 2010, 2010, 2010, 'Siglo XXI', 'SAN JOSâ”œأ«', 41.64078800, -0.87231000, '0101000020E61000000B293FA9F6E9EBBFAAD5575705D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33383878816.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33383878816.webp', 'https://www.flickr.com/photos/zaragozaantigua/33383878816/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23228, 'C.â”¬â•‘ del Puente del Virrey 2014', 'Imagen del portâ”œâ”‚n de ingreso a la antigua Quinta de San Josâ”œآ®, que destaca por el remate en forja a modo de dintel o tâ”œآ،mpano donde pueden leerse las letras en chapa soldada con la leyenda "Quinta/San Josâ”œآ®". Junto a â”œآ®l y hacia la derecha, restos de la antigua Torre de la viuda de Mariano Lâ”œâ”‚pez, esquinera con la calle de Pablo Remacha y la plaza Mayor de San Josâ”œآ®. Este portâ”œâ”‚n permitâ”œآ،a el ingreso desde el camino del Puente del Virrey a un camino que varias decenas de metros hacia el fondo, conducâ”œآ،a hasta la referida Quinta. Unos meses despuâ”œآ®s de capturada la presente imagen, estos restos edilicios de finales del siglo XIX-principios del siglo XX fueron derribados durante el proceso de ampliaciâ”œâ”‚n del colegio concertado (privado sostenido con fondos pâ”œâ•‘blicos) Agustâ”œآ،n Gericâ”œâ”‚, perdurando sâ”œâ”‚lo la referida reja del portâ”œâ”‚n que aâ”œâ–’os despuâ”œآ®s fue restaurada y reinstalada en una râ”œآ®plica en hormigâ”œâ”‚n del portâ”œâ”‚n diseâ”œâ–’ada por el arquitecto Ricardo Usâ”œâ”‚n Garcâ”œآ،a, que fue ubicada en 2022 como puerta monumental en un cercano parterre ajardinado del andador central de la avenida de Cesâ”œأ­reo Alierta (a la izquierda de la fotografâ”œآ،a, fuera de plano).', 2014, 2014, 2014, 'Siglo XXI', 'SAN JOSâ”œأ«', 41.63927800, -0.87377000, '0101000020E6100000BD3AC780ECF5EBBFB1868BDCD3D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54396033740.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54396033740.webp', 'https://www.flickr.com/photos/zaragozaantigua/54396033740/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24381, 'Quinta Julieta c.1958', '"Casa de Ejercicios espirituales "Quinta Julieta", en el Paseo del Canal. Fachada principal. Aparcado, un Seat 600". La denominada "casa de ejercicios de la Compaâ”œâ–’â”œآ،a de Jesâ”œâ•‘s en la Quinta Julieta", propiedad de los PP. Jesuitas, fue construida segâ”œâ•‘n proyecto del arquitecto Santiago Lagunas en el aâ”œâ–’o 1958, en terrenos de la antigua "Quinta de Julieta Sagols", junto al Canal Imperial, al sur del Cabezo Cortado. De ella conservâ”œâ”‚ el nombre, y algunos restos de las maravillas que formaron parte de este espacio con acceso pâ”œâ•‘blico, antes de su conversiâ”œâ”‚n en un lugar exclusivo y confesional. El frontal curvo de la imagen es el nexo de uniâ”œâ”‚n entre los dos pabellones laterales, y el resto de dependencias traseras. El ingreso desde el paseo del Canal se realiza por la izquierda, en pronunciado desnivel. Al fondo, tras el edificio, la estaciâ”œâ”‚n del ferrocarril de Utrillas. A la derecha, tras otro importante descenso, el antiguo camino de Miraflores y la acequia del Ontonar. Fuente visual: Archivo Coyne (DARA-AHPZ).', 1958, 1958, 1958, 'Anos 50', 'SAN JOSâ”œأ«', 41.62540500, -0.86995700, '0101000020E610000005A4FD0FB0D6EBBFA0E062450DD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22252128833.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22252128833.webp', 'https://www.flickr.com/photos/zaragozaantigua/22252128833/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24395, 'Luis Aula 1972', 'Imagen capturada durante las obras de construcciâ”œâ”‚n del nuevo colegio de La Salle "Montemolâ”œآ،n" en la periferia pura y dura del barrio de San Josâ”œآ®, entre las calles Luis Aula (desde donde se ha tomado la imagen), Gascâ”œâ”‚n y Guimbao (derecha), y Josâ”œآ® Galiay (al fondo, a la derecha), donde tenâ”œآ،a radicada su direcciâ”œâ”‚n postal y entrada "magna" (VIP, poco operativa, y escalonada). El curso 1972-1973 fue el que inaugurâ”œâ”‚ estas novâ”œآ،simas instalaciones, frente a la antigua Granja Agrâ”œآ،cola, que todavâ”œآ،a definâ”œآ،a el entorno de la zona con su magna presencia residual, calles de tierra, riegos al aire, moreras, campos de maâ”œآ،z y herbâ”œأ­ceas, y noches oscuras como la boca de un lobo. Este colegio fue construido, precisamente, en uno de esos campos de herbâ”œأ­ceas. En la imagen, los dos grandes pabellones del aulario, rodeados de patios. A la izquierda, sobresale la residencia de los Hermanos de las Escuelas Cristianas. Detrâ”œأ­s, donde despunta la "pluma" de obra, la capilla, las dependencias administrativas, y en otro pabellâ”œâ”‚n aparte, el salâ”œâ”‚n recreativo y el cine. Fuente visual: "Memoria Escolar 1971-1972", amable aportaciâ”œâ”‚n de Juan Carlos Crespo.', 1972, 1972, 1972, 'Anos 70', 'SAN JOSâ”œأ«', 41.63712100, -0.87126600, '0101000020E61000004DBC033C69E1EBBF234C512E8DD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26122422956.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26122422956.webp', 'https://www.flickr.com/photos/zaragozaantigua/26122422956/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24511, 'La Granja 1908', 'Imagen del inglâ”œآ®s tren de trilla "Ruston", laborando en la Escuela de Agricultura de Zaragoza, en la Granja Agrâ”œآ،cola, como imagen promocional de la casa Alberto Alhes y Câ”¬آ¬., importadora de maquinaria agrâ”œآ،cola. Fuente visual: fotografâ”œآ،a Granja Agrâ”œآ،cola, en "Zaragoza artâ”œآ،stica â”œآ® industrial. Album de la Exposiciâ”œâ”‚n. 1908."', 1908, 1908, 1908, 'Anos 1900', 'SAN JOSâ”œأ«', 41.63564100, -0.87072800, '0101000020E610000082C476F700DDEBBF957F2DAF5CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33757697474.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33757697474.webp', 'https://www.flickr.com/photos/zaragozaantigua/33757697474/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24540, 'Calle de Juana de Ibarbourou 1973', 'Inâ”œآ®dita imagen capturada con motivo de la inauguraciâ”œâ”‚n del Supermercado Sabeco radicado en los grandes bajos comerciales del modernâ”œآ،simo edificio del nâ”¬â•‘ 5 de la calle de Juana de Ibarbourou, esquinero con la calle del Monasterio de Poblet. Este era el octavo "super" que esta cadena abrâ”œآ،a en Zaragoza, desde que en 1960 inauguraran el pionero Sabeco-Supermax en la calle de las Delicias. Con este reciâ”œآ®n inaugurado se trataba de dar servicio a la entonces denominada "zona de Miguel Servet" y cubrir el â”œأ­rea entre los establecimientos ya abiertos en Las Fuentes (calle de Salvador Minguijâ”œâ”‚n) y en San Josâ”œآ® (avenida de San Josâ”œآ®). A mediados de los aâ”œâ–’os 70 Sabeco era una de las principales empresas del sector servicios en Zaragoza, con algo mâ”œأ­s de 200 empleados, y una importante implantaciâ”œâ”‚n, incluyendo los barrios mâ”œأ­s populosos de la periferia. En la imagen, nutrida fila de expectantes clientas (hacer la compra era cosa de mujeres) de este nuevo "super" esperan su turno para entrar, bajo una festiva decoraciâ”œâ”‚n de globos. Fue tal la aglomeraciâ”œâ”‚n, que tuvieron que abrir las puertas media hora antes de lo previsto. Todo un â”œآ®xito, con notable impacto en el pequeâ”œâ–’o comercio de proximidad.', 1973, 1973, 1973, 'Anos 70', 'SAN JOSâ”œأ«', 41.64245100, -0.86952900, '0101000020E6100000008E3D7B2ED3EBBF292499D53BD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51591320388.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51591320388.webp', 'https://www.flickr.com/photos/zaragozaantigua/51591320388/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24947, 'Cabezo Buenavista 1924', 'Imagen del cabezo de Buenavista, sito en el parque del mismo nombre, decorado con el monumento a Alfonso I, obra del escultor Josâ”œآ® Bueno. Aunque el motivo de su erecciâ”œâ”‚n fue el aniversario de la conquista de la ciudad, su instalaciâ”œâ”‚n se consumâ”œâ”‚ unos aâ”œâ–’os despuâ”œآ®s, y sigue pendiente de inaugurarse, parece ser. El felino africano que le caracteriza, a sus pies, llegarâ”œآ،a unos aâ”œâ–’os mâ”œأ­s tarde. Como la imagen ilustra, ya entonces era utilizado como fondo escâ”œآ®nico a fotografâ”œآ،as y recuerdos grâ”œأ­ficos varios. Fuente visual: Francisco Gâ”œâ”‚rriz, Archivo Municipal de Zaragoza', 1924, 1924, 1924, 'Anos 20', 'UNIVERSIDAD', 41.63366800, -0.89333800, '0101000020E610000000C5C8923996ECBFC84274081CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29812049400.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29812049400.webp', 'https://www.flickr.com/photos/zaragozaantigua/29812049400/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24567, 'La Granja 1915', 'Imagen de la oficial inauguraciâ”œâ”‚n, en la Granja agrâ”œآ،cola experimental, de un busto en homenaje a Manuel Rodrâ”œآ،guez Ayuso, prâ”œâ”‚cer local que fuera director de esta instituciâ”œâ”‚n desde 1891 a 1908. Este busto fue una de las primeras obras del escultor Josâ”œآ® Julio Bueno, luego mâ”œأ­s reconocido por el monumento de la Fosa Comâ”œâ•‘n de Torrero (1919), el Batallador del Cabezo de Buenavista (1921), la "Mujer dormida" de la plaza de Basilio Paraâ”œآ،so (1921), et caetera. En la imagen, el busto se localiza en el acceso principal, desde el camino del Bajo Aragâ”œâ”‚n, muy al fondo, a las instalaciones centrales de la Granja. A la izquierda, el campo de experimentaciâ”œâ”‚n de cereales. A la derecha, la pequeâ”œâ–’a garita meteorolâ”œâ”‚gica. Al fondo, los dos edificios que flanqueaban la entrada junto al camino de Cabaldâ”œâ”‚s. Cuando la Granja fue clausurada en 1943, la estatua estuvo desaparecida casi cuarenta aâ”œâ–’os (signo de los tiempos), hasta que el CITA (Centro de Investigaciâ”œâ”‚n y Tecnologâ”œآ،a Agroalimentaria de Aragâ”œâ”‚n) la hizo aparecer para reinstalarla (demediada) en la entrada de sus modernas instalaciones del campus de Montaâ”œâ–’ana. En la actualidad, el espacio de la foto forma parte de los amplios patios de juego y recreo del colegio pâ”œâ•‘blico bilingâ”œâ•‌e "Calixto Ariâ”œâ–’o-Hilario Val". Fuente visual: Foto Serrano Sancho ("Mundo Grâ”œأ­fico").', 1915, 1915, 1915, 'Anos 10', 'SAN JOSâ”œأ«', 41.63605300, -0.87058000, '0101000020E61000005DA79196CADBEBBFE7C2482F6AD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20040957118.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20040957118.webp', 'https://www.flickr.com/photos/zaragozaantigua/20040957118/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24572, 'La Granja 1930', 'Captura de los edificios principales de la Granja Agrâ”œآ،cola Experimental de Zaragoza. El edificio central era el de la Direcciâ”œâ”‚n de la Granja. En 1930 el ingeniero agrâ”œâ”‚nomo Josâ”œآ® Cruz Lapazarâ”œأ­n ejercâ”œآ،a esas funciones. En los ornamentales jardines del acceso al edificio estaba el Monumento al fundador de La Granja, Manuel Rodrâ”œآ،guez Ayuso, y muy cerca, la garita meteorolâ”œâ”‚gica. A sus flancos, los pabellones residencial y de vivienda del alumnado, y el de laboratorios y pruebas prâ”œأ­cticas. En los sâ”œâ”‚tanos habâ”œآ،a espacio para pruebas con hongos y setas, asâ”œآ، como para una interesante bodega de caldos. A la derecha, los establos, caseta de peones, y apriscos. A la izquierda, fuera de plano, el lavadero de coches, la bâ”œأ­scula para carros, el cocherâ”œâ”‚n de maquinaria agrâ”œآ،cola, el semillero, el gallinero, y las cochiqueras. Los campos de experimentaciâ”œâ”‚n de esta zona "noble" eran un compendio de todos los "palos" que La Granja tocaba: cereales, vides, hortofrutâ”œآ،colas, herbâ”œأ­ceos, maâ”œآ،z, remolacha, plantas medicinales... El acceso a La Granja se hacâ”œآ،a desde Miguel Servet, por un camino que cruzaba los enormes campos de experimentaciâ”œâ”‚n, la lâ”œآ،nea minera Zaragoza-Utrillas, y el Camino de Cabaldâ”œâ”‚s. Al fondo, y tras los edificios de los pabellones, transitaba la lâ”œآ،nea de ferrocarril de los directos a Barcelona. En la actualidad, aquâ”œآ، se encuentran el Parque de La Granja, el CEIP bilingâ”œâ•‌e (alemâ”œأ­n-espaâ”œâ–’ol) Calixto Ariâ”œâ–’o-Hilario Val, y el CPEE â”œأ¼ngel Riviâ”œآ؟re. Fuente visual: "Granja Agrâ”œآ،cola de Zaragoza. Su cincuentenario. Homenaje y gratitud."', 1930, 1930, 1930, 'Anos 30', 'SAN JOSâ”œأ«', 41.63605300, -0.87058000, '0101000020E61000005DA79196CADBEBBFE7C2482F6AD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20259226271.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20259226271.webp', 'https://www.flickr.com/photos/zaragozaantigua/20259226271/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24573, 'La Granja 1883', '"Establecimientos de enseâ”œâ–’anza agrâ”œآ،cola. Zaragoza. Proyecto de una Granja-Escuela, actualmente en construcciâ”œâ”‚n, segâ”œâ•‘n planos del arquitecto D. Fâ”œآ®lix Navarro". Fuente visual: "La Ilustraciâ”œâ”‚n espaâ”œâ–’ola y americana", 1883.', 1883, 1883, 1883, 'Siglo XIX', 'SAN JOSâ”œأ«', 41.63564100, -0.87072800, '0101000020E610000082C476F700DDEBBF957F2DAF5CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20337026809.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20337026809.webp', 'https://www.flickr.com/photos/zaragozaantigua/20337026809/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24576, 'La Granja 1930', 'Posado de un grupo de chavales becados por el ministerio de Trabajo, que con edades comprendidas entre los 14 y los 18 aâ”œâ–’os, realizaban un cursillo de capacitaciâ”œâ”‚n de tres meses de duraciâ”œâ”‚n en las instalaciones de la Granja Agrâ”œآ،cola de Zaragoza. Junto a ellos, el director de la Granja, Josâ”œآ® Cruz Lapazarâ”œأ­n, y los profesores Mariano Gros, Antonio Vela, Francisco Guerra, y Lucio Serrano. Detrâ”œأ­s del grupo, el monumento a Manuel Rodrâ”œآ،guez Ayuso, y vista parcial de algunos pabellones granjeros. Fuente visual: Miguel Marâ”œآ،n Chivite, periâ”œâ”‚dico "Heraldo de Aragâ”œâ”‚n".', 1930, 1930, 1930, 'Anos 30', 'SAN JOSâ”œأ«', 41.63605300, -0.87058000, '0101000020E61000005DA79196CADBEBBFE7C2482F6AD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32447165261.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32447165261.webp', 'https://www.flickr.com/photos/zaragozaantigua/32447165261/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24579, 'La Granja 1930', 'Operarios de la Granja Agrâ”œآ،cola en tareas de recolecciâ”œâ”‚n de alfalfa y experimentaciâ”œâ”‚n con abonos "catalâ”œآ،ticos" para buscar la fijaciâ”œâ”‚n del nitrâ”œâ”‚geno atmosfâ”œآ®rico, acelerando asâ”œآ، la mineralizaciâ”œâ”‚n y activaciâ”œâ”‚n de la vida microbiana en suelos carentes o pobres de nutrientes. La imagen estâ”œأ­ capturada en el campo de experimentaciâ”œâ”‚n inmediato al pabellâ”œâ”‚n docente de la escuela de Peritos (al fondo, a la derecha). Junto a este pabellâ”œâ”‚n estaba la bâ”œأ­scula para carros y el lavadero de coches. Los â”œأ­rboles jalonan el camino que conducâ”œآ،a a un puentecillo peatonal de paso sobre las vâ”œآ،as del ferrocarril a Barcelona, a la calle de la Granja Modelo, y al camino del Puente del Virrey. Fuente visual: "Homenaje y testimonio de gratitud que dedican a la Granja Agrâ”œآ،cola de Zaragoza en el Cincuentenario de su fundaciâ”œâ”‚n, los representantes de la Agricultura e Industrias, agradecidas a su benâ”œآ®fico influjo en el resurgimiento de la economâ”œآ،a general aragonesa".', 1930, 1930, 1930, 'Anos 30', 'SAN JOSâ”œأ«', 41.63518900, -0.86990300, '0101000020E61000003927F6D03ED6EBBFB4E386DF4DD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33872908073.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33872908073.webp', 'https://www.flickr.com/photos/zaragozaantigua/33872908073/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24580, 'La Granja 1930', 'Imagen de un rebaâ”œâ–’o ovino lanar practicando el ramoneo tras la recolecciâ”œâ”‚n del maâ”œآ،z en un campo de la Granja Agrâ”œآ،cola de Zaragoza, posiblemente integrado por ejemplares del cruce entre la inglesa raza Shropshire Down con la autâ”œâ”‚ctona Rasa. Luego serâ”œآ،an regresadas al cercano aprisco de la Granja. A la izquierda, el puente de paso peatonal que, sobre las vâ”œآ،as del ferrocarril de Zaragoza a Barcelona, conducâ”œآ،a a la calle de la Granja Modelo. Al fondo, parcelas en el entorno del camino del Puente del Virrey y la calle del Once de Febrero, de la Nobleza, de la Alegrâ”œآ،a, de Don Ignacio de Buera, y de Don Joaquâ”œآ،n de Herrera. Fuente visual: exposiciâ”œâ”‚n أ”أ‡آ£La investigaciâ”œâ”‚n agroalimentaria en Aragâ”œâ”‚n. Sus inicios con Rodrâ”œآ،guez Ayusoأ”أ‡أک, Centro de Investigaciâ”œâ”‚n y Tecnologâ”œآ،a Agroalimentaria de Aragâ”œâ”‚n (CITA).', 1930, 1930, 1930, 'Anos 30', 'SAN JOSâ”œأ«', 41.63518400, -0.87141900, '0101000020E6100000E59D4319AAE2EBBFA37895B54DD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33925662033.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33925662033.webp', 'https://www.flickr.com/photos/zaragozaantigua/33925662033/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23369, 'Esclusas de Valdegurriana 1833', '"Esclusas de Valdegurrian", litografâ”œآ،a de Faramundo Blanchard. Vista de las esclusas de Valdegurriana y la almenara de San Bernardo del Canal Imperial de Aragâ”œâ”‚n. Se trata de cuatro esclusas para facilitar la navegaciâ”œâ”‚n. Fuente visual: "Memoria histâ”œâ”‚rica del Canal imperial de Aragon: noticia sobre las utilidades que produce, y esplicacion de lo que contienen las lâ”œأ­minas que se publican", Madrid, 1833.', 1833, 1833, 1833, 'Siglo XIX', NULL, 41.61116500, -0.85628000, '0101000020E610000011018750A566EBBFDCBA9BA73ACE4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19468297386.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19468297386.webp', 'https://www.flickr.com/photos/zaragozaantigua/19468297386/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24583, 'La Granja 1930', 'Imagen de la "estatua elevada en terrenos de la Granja por agricultores, ganaderos e industriales en recuerdo del insigne Director que fuâ”œآ® de este Centro Don Manuel Rodrâ”œآ،guez Ayuso". Fue inaugurada en 1915, dos aâ”œâ–’os despuâ”œآ®s del fallecimiento de Ayuso, y permaneciâ”œâ”‚ en esta ubicaciâ”œâ”‚n hasta que, tras unos aâ”œâ–’os desaparecida, fue recolocada (algo demediada) en las actuales instalaciones del Centro de Investigaciâ”œâ”‚n y Tecnologâ”œآ،a Agroalimentaria de Aragâ”œâ”‚n (CITA). Tras la isleta de la estatua, el edificio de la Direcciâ”œâ”‚n de la Granja Agrâ”œآ،cola, y uno de los pabellones principales. Fuente visual: "Granja Agrâ”œآ،cola de Zaragoza. Su cincuentenario. Homenaje y gratitud."', 1930, 1930, 1930, 'Anos 30', 'SAN JOSâ”œأ«', 41.63605300, -0.87058000, '0101000020E61000005DA79196CADBEBBFE7C2482F6AD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34614442795.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34614442795.webp', 'https://www.flickr.com/photos/zaragozaantigua/34614442795/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24584, 'La Granja 1930', 'Imagen capturada en la Granja Agrâ”œآ،cola de Zaragoza, en la recoleta zona de ensayo de cultivos de hongos comestibles blancos, corrientemente designados con el nombre de "champignon", al objeto de evaluar su posible generalizaciâ”œâ”‚n tanto para la conserverâ”œآ،a como el consumo en fresco, a precio asequible. El â”œآ®xito en la experimentaciâ”œâ”‚n se tradujo en la extensiâ”œâ”‚n de este cultivo como complementario a otros cultivos principales, y sobre todo orientado al sector conservero. Fuente visual: www.mapama.gob.es/', 1930, 1930, 1930, 'Anos 30', 'SAN JOSâ”œأ«', 41.63564100, -0.87072800, '0101000020E610000082C476F700DDEBBF957F2DAF5CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35075122142.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35075122142.webp', 'https://www.flickr.com/photos/zaragozaantigua/35075122142/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24585, 'Granja Agrâ”œآ،cola 1928', 'Imagen capturada con motivo de la exposiciâ”œâ”‚n de trabajos desarrollados por el Servicio Agronâ”œâ”‚mico de la Confederaciâ”œâ”‚n Sindical Hidrogrâ”œأ­fica del Ebro celebrada en la Granja Agrâ”œآ،cola de Zaragoza. En el posado figuran la direcciâ”œâ”‚n (destacando el fundador y primer Director Tâ”œآ®cnico de la instituciâ”œâ”‚n, Manuel Lorenzo Pardo Fuentes, de pie, en el centro de la imagen), Sâ”œآ،ndicos y los Vocales del Comitâ”œآ® de Aplicaciones de la Confederaciâ”œâ”‚n Sindical Hidrogrâ”œأ­fica del Ebro, ademâ”œأ­s del ingeniero-director de la Granja Agrâ”œآ،cola, Josâ”œآ® Cruz Lapazarâ”œأ­n Beristaâ”œآ،n (a la derecha, de pie, en primer tâ”œآ®rmino). De fondo escâ”œآ®nico, fachada del cuadrangular edificio de Oficinas y Direcciâ”œâ”‚n de la Granja Agrâ”œآ،cola, en el que ademâ”œأ­s se encontraban el laboratorio, biblioteca y Observatorio, domiciliado en el nâ”¬â•‘ 158 del barrio de Montemolâ”œآ،n. A espaldas del fotâ”œâ”‚grafo, fuera de plano, el Monumento inaugurado en 1913 a D. Manuel Rodrâ”œآ،guez Ayuso, "Director que fue de esta Granja Agrâ”œآ،cola, verdadero apâ”œâ”‚stol de la enseâ”œâ–’anza agraria". Fuente visual: foto Martâ”œآ،nez, en Revista Confederaciâ”œâ”‚n Sindical Hidrogrâ”œأ­fica del Ebro.', 1928, 1928, 1928, 'Anos 20', 'SAN JOSâ”œأ«', 41.63605300, -0.87058000, '0101000020E61000005DA79196CADBEBBFE7C2482F6AD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/45290946791.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/45290946791.webp', 'https://www.flickr.com/photos/zaragozaantigua/45290946791/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25720, 'La Granja 1977', 'Fotografâ”œآ،a de la AVV. del Barrio de San Josâ”œآ®. 1977. Una de las "esquinas calientes" de la abandonada "Granja Agrâ”œآ،cola Experimental", "La Granja", como era denominada por los vecinos del barrio de S. Josâ”œآ®. Clausurada de sus originales funciones en 1943, sus solanas y resguardos a la cierzera pronto fueron detectados por los mayores que se venâ”œآ،an del pueblo con sus hijos durante el â”œآ®xodo rural de la segunda mitad de siglo. Hasta su derribo a finales de los aâ”œâ–’os 70, para construir un colegio pâ”œâ•‘blico, un parque y un centro deportivo municipal, fue un autâ”œآ®ntico centro social "al aire", cuando eso de los "centros de mayores" eran cosa inexistente. En la imagen, animada tertulia granjina con un telâ”œâ”‚n de fondo espectacular: las instalaciones abandonadas de la fâ”œأ­brica de cemento Portland, y el edificio residencial de la antigua Estaciâ”œâ”‚n de Miraflores.', 1977, 1977, 1977, 'Anos 70', 'SAN JOSâ”œأ«', 41.63564100, -0.87072800, '0101000020E610000082C476F700DDEBBF957F2DAF5CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15445665399.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15445665399.webp', 'https://www.flickr.com/photos/zaragozaantigua/15445665399/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25730, 'Grupo &quot;Agustâ”œآ،n Gericâ”œâ”‚&quot; 1947', 'Imagen desde la Granja Agrâ”œآ،cola del Grupo "Agustâ”œآ،n Gericâ”œâ”‚", compuesto por 95 viviendas baratas impulsadas por el arcipreste Agustâ”œآ،n Gericâ”œâ”‚, y diseâ”œâ–’adas por Alejandro Allanegui y Josâ”œآ® de Yarza en una caracterâ”œآ،stica manzana triangular adaptada a la parcelaciâ”œâ”‚n de la zona. Ante ellas, el camino rural de moreras y acequia luego denominado Josâ”œآ® Galiay. A la derecha, los campos de cultivo de herbâ”œأ­ceas a los que se trasladarâ”œأ­ la Salle Montemolâ”œآ،n unas dâ”œآ®cadas despuâ”œآ®s. Fuente visual: AHPZ, Archivo Coyne', 1947, 1947, 1947, 'Anos 40', 'SAN JOSâ”œأ«', 41.63655800, -0.87127800, '0101000020E61000005E2D776682E1EBBFEB0088BB7AD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20162543899.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20162543899.webp', 'https://www.flickr.com/photos/zaragozaantigua/20162543899/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25745, 'Cesâ”œأ­reo Alierta 1977', 'Imagen de la Avenida de Cesâ”œأ­reo Alierta como sorprendente espacio peatonal. Al fondo, la calle Cartagena y la parroquia de San Agustâ”œآ،n, el viejo edificio del "Despartidero" antes de su reforma (edificio entre la avenida de San Josâ”œآ® y el Camino del Puente del Virrey), y los restos de las antiguas parcelas de este sector de Miraflores. Fuente visual: AVV. San Josâ”œآ®', 1977, 1977, 1977, 'Anos 70', 'SAN JOSâ”œأ«', 41.64036700, -0.87388500, '0101000020E6100000F4E0EEACDDF6EBBF0438BD8BF7D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20379517845.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20379517845.webp', 'https://www.flickr.com/photos/zaragozaantigua/20379517845/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25752, 'La Granja 1945', 'El Râ”œآ®gimen Franquista aliado del Eje Roma-Berlâ”œآ،n-Tokio seguâ”œآ،a siendo deficitario de productos como el algodâ”œâ”‚n. En 1940 estableciâ”œâ”‚, mediante la Ley de Racionalizaciâ”œâ”‚n y Fomento del Cultivo de Plantas Textiles, el "Instituto de Fomento del Cultivo del Algodonero", como encargado de encontrar soluciones en esta materia. Asâ”œآ،, estableciâ”œâ”‚ cuatro "zonas algodoneras", que fueron ampliadas aâ”œâ–’os despuâ”œآ®s hasta llegar al nâ”œâ•‘mero de 12. En 1941, la Granja Agrâ”œآ،cola de Zaragoza iniciâ”œâ”‚ los ensayos productivos del algodâ”œâ”‚n en tierras de regadâ”œآ،o, de forma exitosa. Asâ”œآ،, a finales de 1945 la provincia de Zaragoza fue incluida, junto con Huesca y Teruel, como nueva zona de producciâ”œâ”‚n nâ”¬â•‘ 8. Ese aâ”œâ–’o moldeâ”œâ”‚ sus primeras "balas" de algodâ”œâ”‚n "de tipo americano y fibra corta", de unos cuarenta kilos de peso cada una. A comienzos de 1946, la entidad "Algodonera del Ebro, S.A.", del importantâ”œآ،simo Grupo Sans, recibiâ”œâ”‚ la adjudicaciâ”œâ”‚n, por dos aâ”œâ–’os, de la "Zona octava algodonera". Los satisfactorios resultados alcanzados permitirâ”œأ­n a esta entidad recibir la concesiâ”œâ”‚n durante otras diez campaâ”œâ–’as, ampliando la zona a algunas comarcas de Navarra y Logroâ”œâ–’o. Casi veinte aâ”œâ–’os despuâ”œآ®s, en 1967 tedndrâ”œأ­ lugar la â”œâ•‘ltima campaâ”œâ–’a algodonera en la provincia de Zaragoza. La imagen recoge esa primera producciâ”œâ”‚n experimental, que auguraba un futuro exitoso y prometedor. Pero mientras el algodâ”œâ”‚n se convertâ”œآ،a en el privado "mejor negocio de la posguerra", la pâ”œâ•‘blica Granja Agrâ”œآ،cola de Zaragoza era clausurada y abandonada. Fuente visual: Revista "Aragâ”œâ”‚n", nâ”¬â•‘ 211.', 1945, 1945, 1945, 'Anos 40', 'SAN JOSâ”œأ«', 41.63564100, -0.87072800, '0101000020E610000082C476F700DDEBBF957F2DAF5CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20583781071.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20583781071.webp', 'https://www.flickr.com/photos/zaragozaantigua/20583781071/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25761, 'P.â”¬â•‘ Marina Moreno 1976', 'Captura desde las alturas del edificio que ejercâ”œآ،a de "despartidero" entre la Avenida de San Josâ”œآ® y el arranque del Camino del Puente del Virrey, con imagen del estado de las obras de urbanizaciâ”œâ”‚n motivadas por la apertura al trâ”œأ­fico rodado de la prolongaciâ”œâ”‚n del paseo de Marina Moreno, en el tramo entre el Camino de las Torres (al fondo, a la izquierda) y la Avenida de San Josâ”œآ®. A la derecha, la gran manzana entre las calles de Castelar y Cartagena, en la que destaca el complejo de la antigua parroquia de San Agustâ”œآ،n. En su proyecto original, de finales de los aâ”œâ–’os sesenta, la prolongaciâ”œâ”‚n de Marina Moreno deberâ”œآ،a llegar hasta la carretera de Castellâ”œâ”‚n, por eso fue ideado como si de una multi-autopista se tratara, pasmo de la Zaragoza que irrumpâ”œآ،a con fuerza en la ultramodernidad formal. Por estos pagos, hasta no ha demasiado tiempo, perduraban campos de cultivo y huertas de los tiempos en que formaban parte del tâ”œآ®rmino de "Miralflores". Esta demediada prolongaciâ”œâ”‚n dio el pistoletazo de salida en esta zona a nuevos e interesantes polâ”œآ،gonos edilicios, y se quedâ”œâ”‚ estancada en este punto unos veinte aâ”œâ–’os, hasta que fue finalizada. Composiciâ”œâ”‚n inâ”œآ®dita, democrâ”œأ­tica, cientâ”œآ،fica y popular, generada en los laboratorios del', 1976, 1976, 1976, 'Anos 70', 'SAN JOSâ”œأ«', 41.64028800, -0.87365800, '0101000020E6100000CA703C9F01F5EBBFB8020AF5F4D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30147917751.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30147917751.webp', 'https://www.flickr.com/photos/zaragozaantigua/30147917751/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25764, 'Av. San Josâ”œآ® 1990', 'Imagen a la salida de la parroquia de San Agustâ”œآ،n, esquinera entre la avenida de San Josâ”œآ®, y el arranque de la calle de Cartagena, capturada durante los aâ”œâ–’os de complicada negociaciâ”œâ”‚n administrativa de expropiaciones aparejadas a la prolongaciâ”œâ”‚n de la avenida de Cesâ”œأ­reo Alierta. Dos aâ”œâ–’os despuâ”œآ®s comenzarâ”œأ­n los derribos, como el de la parroquia, que se trasladarâ”œآ،a a los bajos de un nuevo edificio del tramo prolongado, hacia la derecha. Fuente visual: www.zaragozarebelde.org/', 1990, 1990, 1990, 'Anos 90', 'SAN JOSâ”œأ«', 41.63991000, -0.87359500, '0101000020E6100000315F5E807DF4EBBF12312592E8D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32168008606.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32168008606.webp', 'https://www.flickr.com/photos/zaragozaantigua/32168008606/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25785, 'C.â”¬â•‘ del Puente del Virrey 1991', 'Imagen capturada en el gran solar conformado por el antiguo erial delimitado entre el camino del Puente del Virrey y las calles de Raquel Meller (a la izquierda y fuera de plano) y de Pablo Remacha (a la derecha y fuera de plano). Utilizado habitualmente como aparcamiento en superficie para vehâ”œآ،culos de todo tipo, y ocasionalmente para emplazar atracciones de feria, su situaciâ”œâ”‚n de abandono incluâ”œآ،a tambiâ”œآ®n episodios de chabolismo. Al fondo, la calle de â”œأ¼ngel Ganivet que conecta con la avenida de San Josâ”œآ®. Sobre este erial, y gracias a la reivindicaciâ”œâ”‚n vecinal, aâ”œâ–’os despuâ”œآ®s se trazarâ”œآ،a la actual plaza Mayor de San Josâ”œآ®.', 1991, 1991, 1991, 'Anos 90', 'SAN JOSâ”œأ«', 41.63803300, -0.87399200, '0101000020E610000075E61E12BEF7EBBF6762BA10ABD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50450918082.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50450918082.webp', 'https://www.flickr.com/photos/zaragozaantigua/50450918082/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25787, 'Miraflores c.1987', 'Los componentes del Vocoder, pionero grupo local de "tecno pop", posan en esta simpâ”œأ­tica imagen encaramados a una seâ”œâ–’alâ”œآ®tica del ferrocarril que comunica con Barcelona. Al fondo y a la izquierda, vista parcial de las viviendas ferroviarias junto a la estaciâ”œâ”‚n de Miraflores, que queda detrâ”œأ­s. En torno al gran y enorme Antonio Tenas, la vocalista Pilar Pellicer, Antonio Laval e Ildefonso Olarte.', 1987, 1987, 1987, 'Anos 80', 'SAN JOSâ”œأ«', 41.63391200, -0.86996900, '0101000020E61000001615713AC9D6EBBF5F45460724D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51768710027.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51768710027.webp', 'https://www.flickr.com/photos/zaragozaantigua/51768710027/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25789, 'Parroquia de San Agustâ”œآ،n 1967', 'Inâ”œآ®dita imagen capturada en el recoleto interior de la moderna parroquia de San Agustâ”œآ،n, establecida como tal desde el 8 de diciembre de 1966 de resultas de la divisiâ”œâ”‚n de la parroquia de San Vicente Mâ”œأ­rtir por el arzobispo Pedro Cantero Cuadrado para atender mejor a las 6.000 almas del barrio de San Josâ”œآ® aquâ”œآ، aparroquiadas. El pequeâ”œâ–’o tamaâ”œâ–’o del edificio tendrâ”œآ،a que ver posiblemente con que se trataba de la capilla de las "Obras Escolares, Catequâ”œآ،sticas y Religiosas de San Josâ”œآ®", con la que compartâ”œآ،a direcciâ”œâ”‚n postal en el nâ”¬â•‘ 10 de la calle de Cartagena. Ello explicarâ”œآ،a que la imagen que la preside sea un "San Josâ”œآ® con el niâ”œâ–’o" posiblemente de la Escuela de Olot, y no la preceptiva de San Agustâ”œآ،n. La ceremonia tiene lugar para oficiar el enlace de Carmen Lâ”œأ­zaro Sierra (hija de los guardeses de la Torre de Sarto) y Jesâ”œâ•‘s Hernâ”œأ­ndez Urbano.', 1967, 1967, 1967, 'Anos 60', 'SAN JOSâ”œأ«', 41.63927600, -0.87217900, '0101000020E6100000684128EFE3E8EBBF118FC4CBD3D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52536045841.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52536045841.webp', 'https://www.flickr.com/photos/zaragozaantigua/52536045841/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22087, 'Facultad de Veterinaria 1951', 'La Facultad de Veterinaria de la Universidad de Zaragoza fue inaugurada en 1951. En la imagen se recoge el estado prâ”œâ”‚ximo al final de las obras de su edificio principal, comenzadas en abril de 1945, segâ”œâ•‘n proyecto de Santiago Lagunas, Manuel Martâ”œآ،nez de Ubago y Casimiro Lanaja de 1943. Estâ”œأ­ situada en la calle de Miguel Servet 177, donde â”œآ®sta terminaba y daba paso a la carretera de Castellâ”œâ”‚n. Sustituâ”œآ،a a la anterior sede, en la calle del General Sanjurjo, Fuente: Crâ”œâ”‚nica de 150 aâ”œâ–’os de estudios veterinarios en Aragâ”œâ”‚n. IFC, 2000.', 1951, 1951, 1951, 'Anos 50', 'SAN JOSâ”œأ«', 41.63465600, -0.86111800, '0101000020E6100000D6E6FF55478EEBBFE71A66683CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18683881173.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18683881173.webp', 'https://www.flickr.com/photos/zaragozaantigua/18683881173/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22090, 'Joaquâ”œآ،n Ruiz-Gimâ”œآ®nez 1951', 'El Ministro de Educaciâ”œâ”‚n Nacional, Joaquâ”œآ،n Ruiz-Gimâ”œآ®nez, toma la palabra en el acto oficial de inauguraciâ”œâ”‚n de la nueva Facultad de Veterinaria de Zaragoza, el 20 de octubre de 1951. Este polâ”œآ،tico catâ”œâ”‚lico continuâ”œâ”‚ ejerciendo tras la muerte de Franco, llegando a ser el primer Defensor del Pueblo, entre 1982 y 1987. Fuente: Crâ”œâ”‚nica de 150 aâ”œâ–’os de estudios veterinarios en Aragâ”œâ”‚n. IFC, 2000.', 1951, 1951, 1951, 'Anos 50', 'SAN JOSâ”œأ«', 41.63465600, -0.86111800, '0101000020E6100000D6E6FF55478EEBBFE71A66683CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19117940378.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19117940378.webp', 'https://www.flickr.com/photos/zaragozaantigua/19117940378/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22454, 'Ctra. de Castellâ”œâ”‚n 1967', 'Imagen del silo denominado Zaragoza-Sur, o Zaragoza-Castellâ”œâ”‚n, del Servicio Nacional del Trigo, inaugurado en 1963 junto a la carretera de Castellâ”œâ”‚n, en una frontera ubicaciâ”œâ”‚n entre los parajes de La Cartuja Baja, el Rabalete, y Cabaldâ”œâ”‚s. Se trataba de un silo de tipo "D", de almacenamiento vertical con capacidad para 2300 toneladas mâ”œآ®tricas de cereales. La imagen se ha tomado desde la entrada de la que fuera casa de Gil Gonzâ”œأ­lez Marcilla. Aâ”œâ–’os despuâ”œآ®s, en tiempos del Servicio Nacional de Cereales, esta traza original se verâ”œآ،a modificada cuando se le anexara de forma descentrada un edificio administrativo en la fachada principal a la carretera. Fue derribado en 2019. Fuente visual: Cuadernos de Aragâ”œâ”‚n, 2, IFC', 1967, 1967, 1967, 'Anos 60', 'SAN JOSâ”œأ«', 41.63264700, -0.86024700, '0101000020E6100000766D6FB72487EBBFCD74AF93FAD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31616177237.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31616177237.webp', 'https://www.flickr.com/photos/zaragozaantigua/31616177237/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22530, 'Miguel Servet 1972', 'La lâ”œآ،nea 1 del Tranvâ”œآ،a ("Bajo Aragâ”œâ”‚n") llevaba rodando desde 1885, si bien entonces la tracciâ”œâ”‚n era "de sangre", y llegaba hasta la Estaciâ”œâ”‚n de Cappa. Electrificada en 1902, fue prolongada en 1953 hasta la nueva Facultad de Veterinaria. Fusionada en 1967 con la Lâ”œآ،nea 15 hasta Casablanca, en 1969 recuperâ”œâ”‚ su trayecto original: Pza. S. Miguel-Bajo Aragâ”œâ”‚n. En las fiestas matronales de 1975, fue suprimida. En la imagen, el tranvâ”œآ،a nâ”¬â•‘ 203 de la serie 200 a la altura de la Facultad de Veterinaria, en el bajo Miguel Servet. Fuente visual: www.flickr.com/photos/jhm0284/5812533003/in/photostream/', 1972, 1972, 1972, 'Anos 70', 'SAN JOSâ”œأ«', 41.63497800, -0.86207200, '0101000020E61000009483D9041896EBBFF9D687F546D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14708661627.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14708661627.webp', 'https://www.flickr.com/photos/zaragozaantigua/14708661627/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
