INSERT INTO public.photos VALUES (22641, 'Cementera Miraflores 1979', 'Imagen de las instalaciones de la fâ”œأ­brica de Cementos de Miraflores capturada desde la metâ”œأ­lica pasarela peatonal que salvaba las vâ”œآ،as del ferrocarril de Madrid a Barcelona. Abandonada desde hacâ”œآ،a aâ”œâ–’os, pronto serâ”œأ­ derribada.', 1979, 1979, 1979, 'Anos 70', 'SAN JOSâ”œأ«', 41.63145000, -0.86343500, '0101000020E6100000A818E76F42A1EBBF9487855AD3D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20413473722.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20413473722.webp', 'https://www.flickr.com/photos/zaragozaantigua/20413473722/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22774, 'Miguel Servet 1972', 'Despejada imagen centrada en la unidad 222 de la serie de los "gaditanos" en servicio en la tranviaria lâ”œآ،nea 1 "Bajo Aragâ”œâ”‚n", localizada en la terminal inmediata a la nueva Facultad de Veterinaria y preparada para encaminarse a la plaza de San Miguel. Esta Facultad fue inaugurada en 1951 en el tramo bajo de la calle de Miguel Servet. A la derecha de la fachada principal de Veterinaria, el solar donde aâ”œâ–’os mâ”œأ­s tarde (1977) serâ”œآ،a inaugurado el reivindicado pabellâ”œâ”‚n de Zootecnia y Tecnologâ”œآ،a de los Alimentos. Tras la clausura de la lâ”œآ،nea en 1975, este tranvâ”œآ،a fue desguazado. Fuente visual: colecciâ”œâ”‚n Josep Miquel Solâ”œآ®.', 1972, 1972, 1972, 'Anos 70', 'SAN JOSâ”œأ«', 41.63466800, -0.86165300, '0101000020E61000005C02F04FA992EBBFABE80FCD3CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34161763193.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34161763193.webp', 'https://www.flickr.com/photos/zaragozaantigua/34161763193/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24478, 'Fielato carretera Castellâ”œâ”‚n 1962', 'En 1962 existâ”œآ،an en Zaragoza siete oficinas auxiliares de arbitrios o fielatos, que cobraban impuestos sobre algunas mercancâ”œآ،as que entraban a la ciudad, a cargo de la Policâ”œآ،a Sanitaria de Abastos. La de la imagen, en la carretera de Castellâ”œâ”‚n, junto a la antigua vivienda de Gil Gonzâ”œأ­lez Marcilla, era denominada La Cartuja. Las otras cinco fueron La Venta, en la carretera de Huesca; la de la carretera de Barcelona, junto al puente de Santa Isabel; Casablanca, en la carretera de Valencia; Carabinas, en la de Madrid; y Caminreal, al final del paseo de Pamplona, junto a la carretera de Logroâ”œâ–’o. En 1961 se habâ”œآ،a inaugurado tambiâ”œآ®n una caseta en la calle Asalto, junto al Corral de la Leâ”œâ–’a.', 1962, 1962, 1962, 'Anos 60', 'SAN JOSâ”œأ«', 41.63295700, -0.85981900, '0101000020E61000007157AF22A383EBBF1B6327BC04D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21636790192.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21636790192.webp', 'https://www.flickr.com/photos/zaragozaantigua/21636790192/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24517, 'Miraflores 1929', 'Imagen de la nueva fâ”œأ­brica de cementos Portland de Zaragoza "Alfonso XIII", ubicada en Miraflores, entre las lâ”œآ،neas del ferrocarril MZA y de Utrillas, capturada antes de su inauguraciâ”œâ”‚n y puesta en funcionamiento. La imagen se habrâ”œآ،a capturado desde el "camino a la Fâ”œأ­brica de Cementos" que la conectaba con la carretera de Castellâ”œâ”‚n. En primer tâ”œآ®rmino, posiblemente una casilla de vialidad y obras de la lâ”œآ،nea de Utrillas, y a la derecha, el notable edificio de la Direcciâ”œâ”‚n de la fâ”œأ­brica. Al fondo, las modernas instalaciones de la fâ”œأ­brica para el tratamiento de â”œأ­ridos (arcilla, caliza y margas) y su conversiâ”œâ”‚n en cemento. Fuente visual: www.mecd.gob.es/.', 1929, 1929, 1929, 'Anos 20', 'SAN JOSâ”œأ«', 41.63314400, -0.86333700, '0101000020E6100000F4A78DEA74A0EBBF4ED4D2DC0AD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35337417925.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35337417925.webp', 'https://www.flickr.com/photos/zaragozaantigua/35337417925/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24861, 'Calle de Miguel Servet c.1987', 'Inâ”œآ®dita imagen capturada durante la construcciâ”œâ”‚n de las nuevas cocheras para la empresa Transportes Urbanos de Zaragoza S.A., con diseâ”œâ–’o del arquitecto Josâ”œآ® Marâ”œآ،a Valero Suâ”œأ­rez, en su nueva ubicaciâ”œâ”‚n de la calle de Miguel Servet nâ”¬â•‘ 199. En primer tâ”œآ®rmino, los nuevos accesos desde esta calle-carretera, que confrontan con el principio del camino de Enmedio, y con el antiguo silo "Zaragoza-Castellâ”œâ”‚n", del Servicio Nacional de Cereales.', 1987, 1987, 1987, 'Anos 80', 'SAN JOSâ”œأ«', 41.63253200, -0.85782400, '0101000020E6100000392A37514B73EBBF34D6FECEF6D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32652380807.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32652380807.webp', 'https://www.flickr.com/photos/zaragozaantigua/32652380807/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
